function getIsSuperAdmin() {
  return state.user?.role === "super_admin";
}

function getIsAdmin() {
  return state.user?.role === "admin";
}

function getCanManageMasterData() {
  return ["super_admin", "admin"].includes(state.user?.role);
}

function isDashboardControlPanelItem(itemName = state.activeSidebarItem) {
  return itemName === "control-panel";
}

function isDashboardOverviewItem(itemName = state.activeSidebarItem) {
  return itemName === "dashboard";
}

function isSystemPrivilegedRole(role = "") {
  return ["super_admin", "admin"].includes(String(role || "").trim().toLowerCase());
}

function normalizeUserProfileRoleValue(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (USER_PROFILE_ROLE_LABELS.has(normalized)) {
    return normalized;
  }
  return normalized === "user" ? "new_user" : "new_user";
}

function getUserProfileRoleLabel(value = "") {
  return USER_PROFILE_ROLE_LABELS.get(normalizeUserProfileRoleValue(value)) || "New User";
}

function getUserSystemRoleLabel(role = "") {
  if (role === "super_admin") {
    return "Super Admin";
  }
  if (role === "admin") {
    return "Admin";
  }
  return "User";
}

function getUserOrganizationNames(user = {}) {
  const directOrganizationName = String(user?.organizationName || "").trim();
  const scopedNames = Array.isArray(user?.organizations)
    ? user.organizations.map((organization) => String(organization?.name || "").trim()).filter(Boolean)
    : [];
  return Array.from(new Set([directOrganizationName, ...scopedNames].filter(Boolean)));
}

function getUserOrganizationSummary(user = {}) {
  const organizationNames = getUserOrganizationNames(user);

  if (organizationNames.length === 0) {
    return "Bez organizacije";
  }

  if (organizationNames.length === 1) {
    return organizationNames[0];
  }

  return `${organizationNames[0]} +${organizationNames.length - 1}`;
}

function getUserRoleSummary(user = {}) {
  const profileRoleLabel = getUserProfileRoleLabel(user.profileRole);
  const systemRoleLabel = getUserSystemRoleLabel(user.role);
  const shouldShowSystemRole = user.role === "super_admin"
    || (user.role === "admin" && profileRoleLabel !== systemRoleLabel);

  return {
    title: profileRoleLabel,
    subtitle: shouldShowSystemRole ? `Sustav: ${systemRoleLabel}` : "",
  };
}

function getUserAuthorizationSummary(user = {}) {
  const panicQualification = getUserElectricalQualification(user, "elektro");
  const switchQualification = getUserElectricalQualification(user, "tipkalo");
  const activeAreas = [
    { label: "Panik rasvjeta", qualification: panicQualification },
    { label: "Tipkalo", qualification: switchQualification },
  ].filter(({ qualification }) => hasQualificationCapability(qualification));

  if (activeAreas.length === 0) {
    return {
      title: "Bez aktivnih ovlaštenja",
      subtitle: "Nisu upisana aktivna područja",
      meta: [],
    };
  }

  return {
    title: activeAreas.map((entry) => entry.label).join(" · "),
    subtitle: activeAreas.map((entry) => getQualificationValidityLabel(entry.qualification)).join(" · "),
    meta: [createMetaPill(`${activeAreas.length} aktivna`, "is-success")],
  };
}

function isUserAuthorizationCurrentlyActive(qualification = {}) {
  if (!hasQualificationCapability(qualification)) {
    return false;
  }

  if (qualification?.validForever) {
    return true;
  }

  const validUntil = String(qualification?.validUntil || "").trim();
  if (!validUntil) {
    return true;
  }

  return validUntil >= new Date().toISOString().slice(0, 10);
}

function getUserActiveAuthorizationCount(user = {}) {
  const areas = [
    getUserElectricalQualification(user, "elektro"),
    getUserElectricalQualification(user, "tipkalo"),
  ];

  return areas.filter((qualification) => isUserAuthorizationCurrentlyActive(qualification)).length;
}

function getUserDocumentDisplayName(user = null) {
  const displayName = String(user?.displayName || "").trim();
  if (displayName) {
    return displayName;
  }

  return String(user?.fullName || user?.email || "Korisnik").trim();
}

function hasQualificationCapability(qualification = {}) {
  return Boolean(qualification?.canInspect || qualification?.canAuthorize);
}

function getQualificationValidityLabel(qualification = {}) {
  if (!hasQualificationCapability(qualification)) {
    return "";
  }
  if (qualification?.validForever) {
    return "Trajno";
  }
  if (qualification?.validUntil) {
    return `Do ${formatDate(qualification.validUntil)}`;
  }
  return "Bez roka";
}

function syncQualificationValidityInput(dateInput, foreverInput) {
  if (!(dateInput instanceof HTMLInputElement) || !(foreverInput instanceof HTMLInputElement)) {
    return;
  }

  dateInput.disabled = foreverInput.checked;
}

function normalizeNotificationDayValue(value, fallback = 1, { min = 1, max = 365 } = {}) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) {
    return fallback;
  }

  return Math.max(min, Math.min(max, Math.round(numeric)));
}

function normalizeMeasurementEquipmentNotificationSettings(value = {}) {
  const source = value && typeof value === "object"
    ? value
    : {};
  const fallback = DEFAULT_MEASUREMENT_EQUIPMENT_NOTIFICATION_SETTINGS;
  return {
    leadDaysBeforeExpiry: normalizeNotificationDayValue(
      source.leadDaysBeforeExpiry ?? source.leadDays,
      fallback.leadDaysBeforeExpiry,
      { min: 1, max: 365 },
    ),
    repeatEveryDays: normalizeNotificationDayValue(
      source.repeatEveryDays ?? source.repeatIntervalDays ?? source.repeatDays,
      fallback.repeatEveryDays,
      { min: 1, max: 90 },
    ),
  };
}

