function escapeHtml(value = "") {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function sanitizeDocumentTemplateFileName(value = "", fallback = "zapisnik-template") {
  const slug = slugifyValue(value).replace(/-+/g, "-").replace(/^-+|-+$/g, "");
  return slug || fallback;
}

function triggerBlobDownload(blob, fileName) {
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = fileName;
  document.body.append(link);
  link.click();
  link.remove();
  window.setTimeout(() => {
    URL.revokeObjectURL(url);
  }, 1_000);
}

function triggerBlobPrint(blob, fileName = "zapisnici.pdf") {
  const url = URL.createObjectURL(blob);
  const iframe = document.createElement("iframe");
  iframe.style.position = "fixed";
  iframe.style.width = "0";
  iframe.style.height = "0";
  iframe.style.opacity = "0";
  iframe.style.pointerEvents = "none";
  iframe.setAttribute("aria-hidden", "true");
  iframe.src = url;

  let settled = false;
  const cleanup = () => {
    if (settled) {
      return;
    }
    settled = true;
    window.setTimeout(() => {
      iframe.remove();
      URL.revokeObjectURL(url);
    }, 1_500);
  };

  iframe.addEventListener("load", () => {
    window.setTimeout(() => {
      try {
        iframe.contentWindow?.focus();
        iframe.contentWindow?.print();
      } catch (error) {
        console.error("Ne mogu otvoriti print dijalog za PDF batch.", error);
        triggerBlobDownload(blob, fileName);
      } finally {
        cleanup();
      }
    }, 250);
  }, { once: true });

  iframe.addEventListener("error", () => {
    triggerBlobDownload(blob, fileName);
    cleanup();
  }, { once: true });

  document.body.append(iframe);
}

function triggerDataUrlDownload(dataUrl, fileName) {
  const link = document.createElement("a");
  link.href = dataUrl;
  link.download = fileName;
  document.body.append(link);
  link.click();
  link.remove();
}

function createWordHtmlBlob(title, bodyHtml) {
  const html = `<!DOCTYPE html>
<html lang="hr">
<head>
  <meta charset="utf-8" />
  <title>${escapeHtml(title)}</title>
  <style>
    body { font-family: Arial, sans-serif; color: #24362e; line-height: 1.5; margin: 28px; }
    h1, h2, h3 { color: #1f4e42; margin-bottom: 12px; }
    h1 { font-size: 26px; }
    h2 { font-size: 20px; margin-top: 30px; }
    h3 { font-size: 16px; margin-top: 20px; }
    p { margin: 10px 0; }
    table { width: 100%; border-collapse: collapse; margin: 12px 0 18px; }
    th, td { border: 1px solid #cad8d1; padding: 8px 10px; text-align: left; vertical-align: top; }
    th { background: #eef5f2; }
    .cover { border: 1px solid #cad8d1; border-radius: 18px; padding: 24px; background: #f7faf8; }
    .signature-grid { display: table; width: 100%; table-layout: fixed; margin-top: 18px; }
    .signature-cell { display: table-cell; width: 50%; padding-right: 18px; }
    .signature-line { margin-top: 46px; border-top: 1px solid #95aea3; padding-top: 8px; }
    .placeholder-table td:first-child { width: 32%; font-family: Consolas, monospace; }
    .placeholder-page p { margin: 0 0 12px; font-family: Consolas, "Courier New", monospace; color: #24362e; }
  </style>
</head>
<body>${bodyHtml}</body>
</html>`;

  return new Blob(["\ufeff", html], {
    type: "application/msword;charset=utf-8",
  });
}

function parseTemplateLooseNumber(value, fallback = 0) {
  const raw = String(value ?? "").trim().replace(/\s+/g, "").replace(",", ".");
  const parsed = Number.parseFloat(raw);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function normalizeDocumentTemplateSystemDescriptionLineCount(value = 1) {
  return Math.max(1, Math.min(8, Math.round(parseTemplateLooseNumber(value, 1))));
}

function createEmptyDocumentTemplateSystemDescriptionRowDraft(initial = {}, index = 0) {
  return {
    id: initial.id || crypto.randomUUID(),
    subtitle: String(initial.subtitle ?? initial.label ?? "").trim(),
    description: String(initial.description ?? initial.value ?? "").replace(/\r\n/g, "\n").trim(),
    lineCount: normalizeDocumentTemplateSystemDescriptionLineCount(initial.lineCount ?? initial.rows),
    placeholder: String(initial.placeholder ?? "").trim(),
  };
}

function createDefaultDocumentTemplateSystemDescriptionRows() {
  return [
    { id: "system-description-default-1", subtitle: "Proizvođač", description: "", lineCount: 1, placeholder: "npr. COOPER" },
    { id: "system-description-default-2", subtitle: "Tip", description: "", lineCount: 1, placeholder: "npr. FULL CXM/CO/GP/R/BB" },
    { id: "system-description-default-3", subtitle: "Teh. podaci", description: "", lineCount: 1, placeholder: "npr. 1 kom" },
    { id: "system-description-default-4", subtitle: "", description: "", lineCount: 2, placeholder: "Kratki opis sustava, položaja i bitnih napomena..." },
  ].map((row, index) => createEmptyDocumentTemplateSystemDescriptionRowDraft(row, index));
}

function normalizeDocumentTemplateSystemDescriptionRows(rows = [], { ensureOne = true, fallbackRows = [] } = {}) {
  const sourceRows = Array.isArray(rows) && rows.length > 0
    ? rows
    : (Array.isArray(fallbackRows) && fallbackRows.length > 0 ? fallbackRows : []);
  const normalizedRows = sourceRows
    .slice(0, 16)
    .map((row, index) => createEmptyDocumentTemplateSystemDescriptionRowDraft(row, index));

  if (normalizedRows.length > 0) {
    return normalizedRows;
  }

  return ensureOne
    ? [createEmptyDocumentTemplateSystemDescriptionRowDraft({}, 0)]
    : [];
}

function createDocumentTemplateSystemDescriptionBlockDraft(initial = {}, field = {}, index = 0) {
  const defaultTitle = String(field?.label || field?.wordLabel || "Opis sustava").trim() || "Opis sustava";
  const fallbackRows = normalizeDocumentTemplateSystemDescriptionRows(
    field?.systemRows,
    {
      ensureOne: true,
      fallbackRows: createDefaultDocumentTemplateSystemDescriptionRows(),
    },
  );

  return {
    id: initial.id || crypto.randomUUID(),
    title: String(initial.title ?? initial.label ?? defaultTitle).trim() || defaultTitle,
    sectionSubtitle: String(initial.sectionSubtitle ?? initial.subtitle ?? field?.sectionSubtitle ?? "").trim(),
    rows: normalizeDocumentTemplateSystemDescriptionRows(
      initial.rows,
      {
        ensureOne: true,
        fallbackRows,
      },
    ),
  };
}

function normalizeDocumentTemplateSystemDescriptionBlocks(value = null, field = {}, { ensureOne = true } = {}) {
  const legacyRows = Array.isArray(value?.rows) ? value.rows : [];
  const sourceBlocks = Array.isArray(value?.blocks)
    ? value.blocks
    : (legacyRows.length > 0 || value?.title || value?.sectionSubtitle
      ? [{
        id: value?.id,
        title: value?.title,
        sectionSubtitle: value?.sectionSubtitle,
        rows: legacyRows,
      }]
      : []);

  const normalizedBlocks = sourceBlocks
    .slice(0, 24)
    .map((block, index) => createDocumentTemplateSystemDescriptionBlockDraft(block, field, index));

  if (normalizedBlocks.length > 0) {
    return normalizedBlocks;
  }

  return ensureOne
    ? [createDocumentTemplateSystemDescriptionBlockDraft({}, field, 0)]
    : [];
}

function isDocumentTemplateSystemDescriptionValue(value = null) {
  return Boolean(
    value
    && typeof value === "object"
    && !Array.isArray(value)
    && (Array.isArray(value.rows) || Array.isArray(value.blocks)),
  );
}

function normalizeDocumentTemplateSystemDescriptionRuntimeValue(field = {}, value = null) {
  const source = isDocumentTemplateSystemDescriptionValue(value) ? value : {};
  return {
    blocks: normalizeDocumentTemplateSystemDescriptionBlocks(source, field, { ensureOne: true }),
  };
}

function createDocumentTemplateSystemDescriptionBlankValue(field = {}) {
  const value = normalizeDocumentTemplateSystemDescriptionRuntimeValue(field);
  return {
    ...value,
    blocks: value.blocks.map((block, blockIndex) => ({
      ...block,
      id: block.id || `system-description-block-${blockIndex + 1}`,
      rows: (Array.isArray(block.rows) ? block.rows : []).map((row) => ({
        ...row,
        description: "",
      })),
    })),
  };
}

function buildDocumentTemplateSystemDescriptionSummaryLines(value = null) {
  const model = isDocumentTemplateSystemDescriptionValue(value)
    ? normalizeDocumentTemplateSystemDescriptionRuntimeValue({}, value)
    : null;

  if (!model) {
    return [];
  }

  const lines = [];
  model.blocks.forEach((block) => {
    const title = String(block.title || "").trim();
    const subtitle = String(block.sectionSubtitle || "").trim();
    if (title) {
      lines.push(title);
    }
    if (subtitle) {
      lines.push(subtitle);
    }
    (Array.isArray(block.rows) ? block.rows : []).forEach((row) => {
      const rowSubtitle = String(row.subtitle || "").trim();
      const description = String(row.description || "").trim();
      if (!rowSubtitle && !description) {
        return;
      }
      lines.push(rowSubtitle ? `${rowSubtitle}: ${description}`.trim() : description);
    });
  });

  return lines.filter(Boolean);
}

function buildDocumentTemplateSystemDescriptionSummaryText(value = null) {
  return buildDocumentTemplateSystemDescriptionSummaryLines(value).join("\n");
}

function hasDocumentTemplateSystemDescriptionContent(value = null) {
  if (!isDocumentTemplateSystemDescriptionValue(value)) {
    return false;
  }

  const model = normalizeDocumentTemplateSystemDescriptionRuntimeValue({}, value);
  return model.blocks.some((block) => (
    String(block.sectionSubtitle || "").trim()
    || (Array.isArray(block.rows) ? block.rows : []).some((row) => (
      String(row?.description || "").trim()
    ))
  ));
}

