async function exportDocumentTemplateWord({ placeholderMode = false } = {}) {
  const template = buildDocumentTemplateDraft();
  if (!placeholderMode) {
    const templateId = getDocumentTemplateRuntimeTemplateId(template);
    const workOrder = getDocumentTemplateRuntimeActiveWorkOrder();
    const hasReferenceTemplate = doesDocumentTemplateHaveReferenceWordTemplate(template);

    if (!templateId || !workOrder) {
      setDocumentTemplateMessage("Odaberi aktivni zapisnik i RN prije Word exporta.");
      return;
    }

    if (!hasReferenceTemplate) {
      setDocumentTemplateMessage("Za Word i PDF export prvo učitaj gotovi .docx/.dotx Word predložak u Template Development.");
      return;
    }

    try {
      await persistActiveDocumentTemplateRuntimeRecord();
    } catch (error) {
      console.error("Ne mogu spremiti runtime zapisnik prije Word exporta.", error);
      setDocumentTemplateMessage(error?.message || "Ne mogu spremiti vrijednosti zapisnika prije Word exporta.");
      return;
    }

    try {
      const exportEntry = await buildDocumentTemplateRuntimeExportEntryAsync(template, workOrder);
      const payload = {
        fileName: exportEntry?.wordFileName || `${buildDocumentTemplateRuntimeExportFileBaseName(template, workOrder)}.docx`,
        placeholders: exportEntry?.placeholders || buildDocumentTemplateRuntimePlaceholderPayload(
          template,
          buildDocumentTemplatePreviewContext(template, { workOrder }),
        ),
      };
      const response = await apiBinaryRequest(`/document-templates/${encodeURIComponent(templateId)}/export-word`, {
        method: "POST",
        body: payload,
      });
      triggerBlobDownload(response.blob, response.fileName || payload.fileName || "zapisnik.docx");
      setDocumentTemplateMessage("Word zapisnik je generiran iz spremljenog predloška.", { type: "success" });
      return;
    } catch (error) {
      console.error("Ne mogu generirati DOCX iz Word predloška.", error);
      setDocumentTemplateMessage(
        error?.message || "Ne mogu generirati Word iz spremljenog predloška.",
      );
      return;
    }
  }

  const fileName = placeholderMode
    ? `${sanitizeDocumentTemplateFileName(template.title || "template-dokument")}-placeholder.doc`
    : `${sanitizeDocumentTemplateFileName(template.title || "zapisnik")}.doc`;
  const html = placeholderMode
    ? buildDocumentTemplatePlaceholderWordMarkup(template)
    : buildDocumentTemplatePreviewMarkup(template, {
      placeholderMode: false,
      sheetTabs: false,
    });
  triggerBlobDownload(createWordHtmlBlob(template.title || "Template", html), fileName);
}

function buildDocumentTemplateRuntimeBatchSequenceEntries() {
  const sequenceEntries = getDocumentTemplateRuntimeSequenceEntries();
  if (sequenceEntries.length > 0) {
    return sequenceEntries;
  }

  const activeTemplate = buildDocumentTemplateDraft();
  const activeTemplateId = getDocumentTemplateRuntimeTemplateId(activeTemplate);
  const activeWorkOrder = getDocumentTemplateRuntimeActiveWorkOrder();
  if (!activeTemplateId || !activeWorkOrder) {
    return [];
  }

  return [{
    templateId: activeTemplateId,
    workOrderId: String(activeWorkOrder.id || "").trim(),
    templateTitle: String(activeTemplate.title || activeTemplate.documentType || "Zapisnik").trim(),
    workOrderNumber: String(activeWorkOrder.workOrderNumber || "").trim(),
  }];
}

async function exportDocumentTemplateBatchPdf({ print = true } = {}) {
  const sequenceEntries = buildDocumentTemplateRuntimeBatchSequenceEntries();
  if (sequenceEntries.length === 0) {
    setDocumentTemplateMessage("Nema zapisnika za batch ispis.");
    return;
  }

  const exportEntries = [];

  try {
    for (const sequenceEntry of sequenceEntries) {
      const template = getDocumentTemplateById(sequenceEntry.templateId);
      const workOrder = getDocumentTemplateRuntimeWorkOrderById(sequenceEntry.workOrderId);

      if (!template || !workOrder) {
        continue;
      }

      if (!doesDocumentTemplateHaveReferenceWordTemplate(template)) {
        setDocumentTemplateMessage(`Template "${template.title || template.documentType || "Zapisnik"}" nema učitan .docx/.dotx Word predložak. Batch PDF mora koristiti isti Word predložak kao i Word export.`);
        return;
      }

      await persistDocumentTemplateRuntimeRecordFor(template, workOrder);
      const exportEntry = await buildDocumentTemplateRuntimeExportEntryAsync(template, workOrder);
      if (exportEntry) {
        exportEntries.push(exportEntry);
      }
    }
  } catch (error) {
    console.error("Ne mogu pripremiti batch zapisnike za ispis.", error);
    setDocumentTemplateMessage(error?.message || "Ne mogu pripremiti batch zapisnike za ispis.");
    return;
  }

  if (exportEntries.length === 0) {
    setDocumentTemplateMessage("Nema nijednog pripremljenog zapisnika za batch ispis.");
    return;
  }

  try {
    const response = await apiBinaryRequest("/document-templates/export-pdf-batch", {
      method: "POST",
      body: {
        fileName: `zapisnici-${new Date().toISOString().slice(0, 10)}.pdf`,
        entries: exportEntries.map((entry) => ({
          templateId: entry.templateId,
          fileName: entry.wordFileName,
          placeholders: entry.placeholders,
          renderModel: entry.renderModel,
        })),
      },
    });

    if (print) {
      triggerBlobPrint(response.blob, response.fileName || "zapisnici.pdf");
    } else {
      triggerBlobDownload(response.blob, response.fileName || "zapisnici.pdf");
    }

    setDocumentTemplateMessage("Batch PDF zapisnici su pripremljeni.", { type: "success" });
  } catch (error) {
    console.error("Ne mogu generirati batch PDF zapisnike.", error);
    setDocumentTemplateMessage(error?.message || "Ne mogu generirati batch PDF zapisnike.");
  }
}

async function queueDocumentTemplateForDigitalSignature() {
  const template = buildDocumentTemplateDraft();
  const workOrder = getDocumentTemplateRuntimeActiveWorkOrder();
  if (!isDocumentTemplateRuntimeFillMode() || !workOrder) {
    setDocumentTemplateMessage("Prvo otvori aktivni zapisnik za digitalni potpis.");
    return;
  }

  try {
    await persistActiveDocumentTemplateRuntimeRecord();
  } catch (error) {
    console.error("Ne mogu spremiti zapisnik prije digitalnog potpisa.", error);
    setDocumentTemplateMessage(error?.message || "Ne mogu pripremiti zapisnik za digitalni potpis.");
    return;
  }

  const signers = getDocumentTemplateRuntimeSignatureEntriesFor(template, workOrder);
  if (signers.length === 0) {
    setDocumentTemplateMessage("Nema odabranih potpisnika za digitalni potpis.");
    return;
  }

  const signerLabel = signers
    .map((entry) => [String(entry.name || "").trim(), String(entry.role || "").trim()].filter(Boolean).join(" · "))
    .filter(Boolean)
    .join(", ");

  setDocumentTemplateMessage(
    `Zapisnik je pripremljen za digitalni potpis. Potpisnici: ${signerLabel}. Ovaj korak sada koristi rezervirane slotove i spreman je za buduću Java/Fina/eOI integraciju.`,
    { type: "success" },
  );
}

function getCheckedValues(container, inputName) {
  return Array.from(container?.querySelectorAll(`input[name="${inputName}"]:checked`) ?? [])
    .map((input) => String(input.value || "").trim())
    .filter(Boolean);
}

function getTemplateTitlesByIds(ids = []) {
  return (ids ?? [])
    .map((templateId) => state.documentTemplates.find((item) => String(item.id) === String(templateId))?.title ?? "")
    .filter(Boolean);
}

function getLegalFrameworkLinkedTemplateIds(item = {}) {
  if (Array.isArray(item?.linkedTemplateIds) && item.linkedTemplateIds.length > 0) {
    return item.linkedTemplateIds.map((value) => String(value ?? "").trim()).filter(Boolean);
  }

  if (!item?.id) {
    return [];
  }

  return sortDocumentTemplates(state.documentTemplates ?? [])
    .filter((template) => (template.selectedLegalFrameworkIds ?? []).some((entryId) => String(entryId) === String(item.id)))
    .map((template) => String(template.id))
    .filter(Boolean);
}

function getLegalFrameworkLinkedTemplateTitles(item = {}) {
  if (Array.isArray(item?.linkedTemplateTitles) && item.linkedTemplateTitles.length > 0) {
    return item.linkedTemplateTitles.map((value) => String(value ?? "").trim()).filter(Boolean);
  }

  return getTemplateTitlesByIds(getLegalFrameworkLinkedTemplateIds(item));
}

function isLegalFrameworkDocumentFileAllowed(file) {
  const fileName = String(file?.name || "").trim().toLowerCase();
  const fileType = String(file?.type || "").trim().toLowerCase();
  return fileName.endsWith(".pdf") || fileType.includes("pdf");
}

function formatLegalFrameworkDocumentCountLabel(count = 0) {
  const safeCount = Math.max(0, Number(count) || 0);

  if (safeCount === 1) {
    return "1 PDF dokument";
  }

  if (safeCount >= 2 && safeCount <= 4) {
    return `${safeCount} PDF dokumenta`;
  }

  return `${safeCount} PDF dokumenata`;
}

function formatLegalFrameworkTemplateCountLabel(count = 0) {
  const safeCount = Math.max(0, Number(count) || 0);

  if (safeCount === 0) {
    return "Bez povezanih zapisnika";
  }

  if (safeCount === 1) {
    return "1 povezani zapisnik";
  }

  if (safeCount >= 2 && safeCount <= 4) {
    return `${safeCount} povezana zapisnika`;
  }

  return `${safeCount} povezanih zapisnika`;
}

function setLegalFrameworkDocumentDrafts(items = []) {
  legalFrameworkDocumentDrafts = (Array.isArray(items) ? items : [])
    .map((item) => createModuleAttachmentDraft({
      ...item,
      documentCategory: item?.documentCategory || "pdf",
    }))
    .filter((item) => item.fileName && (item.dataUrl || item.storageUrl));
}

function createLegalFrameworkCardDocumentActions(item = {}) {
  const documents = (Array.isArray(item.documents) ? item.documents : [])
    .map((entry) => createModuleAttachmentDraft(entry))
    .filter((entry) => entry.fileName && (entry.dataUrl || entry.storageUrl));

  if (documents.length === 0) {
    return null;
  }

  const actions = document.createElement("div");
  actions.className = "legal-framework-card-actions";

  documents.slice(0, 3).forEach((entry) => {
    const downloadButton = createIconActionButton(
      `Preuzmi ${entry.fileName || "PDF dokument"}`,
      "download",
      "",
      (event) => {
        event.preventDefault();
        event.stopPropagation();
        triggerModuleAttachmentDownload(entry);
      },
    );
    downloadButton.classList.add("legal-framework-card-download-button");
    actions.append(downloadButton);
  });

  if (documents.length > 3) {
    actions.append(createBadge(`+${documents.length - 3}`, "legal-framework-meta-badge"));
  }

  return actions;
}

function renderLegalFrameworkDocuments() {
  if (!legalFrameworkDocumentsList) {
    return;
  }

  if (legalFrameworkDocumentDrafts.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy module-copy";
    empty.textContent = "Još nema dodanih PDF dokumenata za ovaj propis.";
    legalFrameworkDocumentsList.replaceChildren(empty);
    return;
  }

  legalFrameworkDocumentsList.replaceChildren(...legalFrameworkDocumentDrafts.map((entry) => {
    const row = document.createElement("article");
    row.className = "module-attachment-row legal-framework-document-row";

    const copy = document.createElement("div");
    copy.className = "module-attachment-copy";

    const title = document.createElement("strong");
    title.textContent = entry.fileName || "PDF dokument";

    const meta = document.createElement("span");
    meta.textContent = [
      "PDF",
      formatFileSize(entry.fileSize),
      entry.updatedAt ? formatCompactDateTime(entry.updatedAt) : "",
    ].filter(Boolean).join(" | ");

    copy.append(title, meta);

    if (entry.description) {
      const description = document.createElement("p");
      description.className = "module-attachment-description";
      description.textContent = entry.description;
      copy.append(description);
    }

    const actions = document.createElement("div");
    actions.className = "module-attachment-actions";
    actions.append(
      createIconActionButton("Preuzmi PDF", "download", "", () => {
        triggerModuleAttachmentDownload(entry);
      }),
      createIconActionButton("Makni PDF", "trash", "card-danger", () => {
        legalFrameworkDocumentDrafts = legalFrameworkDocumentDrafts.filter((item) => String(item.id) !== String(entry.id));
        renderLegalFrameworkDocuments();
      }),
    );

    row.append(copy, actions);
    return row;
  }));
}

async function queueLegalFrameworkDocuments(files) {
  const uploadFiles = Array.from(files ?? []).filter((file) => file instanceof File);

  if (!uploadFiles.length) {
    return;
  }

  for (const file of uploadFiles) {
    if (!isLegalFrameworkDocumentFileAllowed(file)) {
      throw new Error(`Format ${file.name} nije podrzan. Dozvoljen je samo PDF.`);
    }

    if (file.size > WORK_ORDER_DOCUMENT_MAX_SIZE_BYTES) {
      throw new Error(`Datoteka ${file.name} mora biti manja od 12 MB.`);
    }
  }

  const nextDocuments = await Promise.all(uploadFiles.map(async (file) => createModuleAttachmentDraft({
    fileName: file.name,
    fileType: file.type || "application/pdf",
    fileSize: file.size || 0,
    documentCategory: "pdf",
    dataUrl: await readFileAsDataUrl(file, `Ne mogu učitati datoteku ${file.name}.`),
    updatedAt: new Date().toISOString(),
  })));

  legalFrameworkDocumentDrafts = [
    ...legalFrameworkDocumentDrafts,
    ...nextDocuments,
  ];
  renderLegalFrameworkDocuments();
}

function renderTemplateSelectionChecklist(
  container,
  {
    selectedIds = [],
    inputName = "linked-template-id",
    emptyText = "Prvo dodaj templatee u Template Development.",
  } = {},
) {
  if (!container) {
    return;
  }

  const selectedSet = new Set((selectedIds ?? []).map((value) => String(value)));
  const templates = sortDocumentTemplates(state.documentTemplates ?? []);

  if (templates.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy module-copy";
    empty.textContent = emptyText;
    container.replaceChildren(empty);
    return;
  }

  container.replaceChildren(...templates.map((template) => {
    const label = document.createElement("label");
    label.className = "service-catalog-template-option";

    const checkbox = document.createElement("input");
    checkbox.type = "checkbox";
    checkbox.name = inputName;
    checkbox.value = String(template.id);
    checkbox.checked = selectedSet.has(String(template.id));

    const copy = document.createElement("div");
    copy.className = "service-catalog-template-option-copy";

    const title = document.createElement("strong");
    title.textContent = template.title || "Template";

    const meta = document.createElement("span");
    meta.textContent = [
      getDocumentTemplateTypeLabel(template.documentType),
      getDocumentTemplateStatusLabel(template.status),
      template.referenceDocument?.fileName ? "Word ref" : "",
    ].filter(Boolean).join(" | ");

    copy.append(title, meta);
    label.append(checkbox, copy);
    return label;
  }));
}

function createModuleAttachmentDraft(document = {}) {
  const documentCategory = String(document.documentCategory || document.category || "").trim();
  return {
    id: String(document.id || crypto.randomUUID()),
    fileName: String(document.fileName || "").trim(),
    fileType: String(document.fileType || "").trim(),
    fileSize: Number(document.fileSize || 0) || 0,
    documentCategory,
    documentCategoryLocked: Boolean(document.documentCategoryLocked) || (Boolean(document.isPersisted || document.persisted) && Boolean(documentCategory)),
    description: String(document.description || "").trim(),
    dataUrl: String(document.dataUrl || document.storageUrl || "").trim(),
    storageProvider: String(document.storageProvider || "").trim(),
    storageBucket: String(document.storageBucket || "").trim(),
    storageKey: String(document.storageKey || "").trim(),
    storageUrl: String(document.storageUrl || document.dataUrl || "").trim(),
    createdAt: String(document.createdAt || new Date().toISOString()),
    updatedAt: String(document.updatedAt || document.createdAt || new Date().toISOString()),
  };
}

function normalizeDocumentTemplateMediaFieldValue(value = null) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    return null;
  }

  const draft = createModuleAttachmentDraft(value);
  return draft.fileName && (draft.dataUrl || draft.storageUrl) ? draft : null;
}

function getDocumentTemplateMediaFieldSummary(value = null, field = {}) {
  const mediaValue = normalizeDocumentTemplateMediaFieldValue(value);
  if (!mediaValue) {
    return `Nema dodane datoteke za ${getDocumentTemplateMediaFieldKindLabel(field?.type)}.`;
  }

  return [
    mediaValue.fileName,
    mediaValue.fileType || "",
    formatFileSize(mediaValue.fileSize),
  ].filter(Boolean).join(" · ");
}

function getDocumentTemplateMediaFieldPreviewUrl(value = null) {
  const mediaValue = normalizeDocumentTemplateMediaFieldValue(value);
  if (!mediaValue) {
    return "";
  }

  return String(mediaValue.storageUrl || mediaValue.dataUrl || "").trim();
}

async function createDocumentTemplateMediaDraftFromFile(file, field = {}) {
  if (!isDocumentTemplateMediaFileAllowed(field?.type, file)) {
    throw new Error(`${getDocumentTemplateMediaFieldKindLabel(field?.type)} prihvaća samo podržane slike${String(field?.type || "").trim().toLowerCase() === "sketch_upload" ? " ili PDF skicu" : ""}.`);
  }

  const dataUrl = await readFileAsDataUrl(file, "Ne mogu učitati datoteku.");
  return createModuleAttachmentDraft({
    fileName: file.name,
    fileType: file.type || "application/octet-stream",
    fileSize: file.size || 0,
    documentCategory: getDocumentTemplateMediaFieldKindLabel(field?.type),
    dataUrl,
    updatedAt: new Date().toISOString(),
  });
}

function getUserElectricalQualification(user = {}, signatureArea = "elektro") {
  const normalizedArea = normalizeQualificationAreaKey(signatureArea);
  const rootQualification = user?.electricalQualification ?? {};
  const qualification = normalizedArea === "elektro"
    ? rootQualification
    : rootQualification?.additionalAreas?.[normalizedArea] ?? {};
  const inheritedSignatureDataUrl = String(
    rootQualification.signatureDataUrl
    || rootQualification.signatureStorageUrl
    || rootQualification.storageUrl
    || "",
  ).trim();
  return {
    discipline: String(qualification.discipline || normalizedArea || "elektro").trim().toLowerCase() || "elektro",
    canInspect: Boolean(qualification.canInspect),
    canAuthorize: Boolean(qualification.canAuthorize),
    classCode: String(qualification.classCode || "").trim(),
    urbroj: String(qualification.urbroj || "").trim(),
    eBroj: String(qualification.eBroj || "").trim(),
    signatureDataUrl: String(
      qualification.signatureDataUrl
      || qualification.signatureStorageUrl
      || inheritedSignatureDataUrl
      || qualification.storageUrl
      || "",
    ).trim(),
    signatureStorageProvider: String(qualification.signatureStorageProvider || "").trim(),
    signatureStorageBucket: String(qualification.signatureStorageBucket || "").trim(),
    signatureStorageKey: String(qualification.signatureStorageKey || "").trim(),
    signatureStorageUrl: String(qualification.signatureStorageUrl || "").trim(),
    documents: Array.isArray(qualification.documents) ? qualification.documents : [],
  };
}

function getQualifiedUsersForSignatureArea(capability = "inspect", signatureArea = "elektro") {
  const normalizedCapability = capability === "authorize" ? "authorize" : "inspect";
  const normalizedArea = normalizeQualificationAreaKey(signatureArea);
  return (state.users ?? [])
    .filter((user) => Boolean(user?.isActive))
    .filter((user) => {
      const qualification = getUserElectricalQualification(user, normalizedArea);
      if (qualification.discipline !== normalizedArea) {
        return false;
      }

      return normalizedCapability === "authorize"
        ? qualification.canAuthorize
        : qualification.canInspect;
    })
    .sort((left, right) => String(left.fullName || left.email || "").localeCompare(
      String(right.fullName || right.email || ""),
      "hr",
    ));
}

function getQualifiedUserSelectLabel(user = {}, capability = "inspect", signatureArea = "elektro") {
  const qualification = getUserElectricalQualification(user, signatureArea);
  const summaryParts = [
    qualification.classCode ? `Klasa ${qualification.classCode}` : "",
    qualification.urbroj ? `UrBROJ ${qualification.urbroj}` : "",
    qualification.eBroj ? `E ${qualification.eBroj}` : "",
  ].filter(Boolean);
  const roleLabel = capability === "authorize" ? "nositelj" : "ispitivač";
  const areaLabel = getSignatureAreaLabel(signatureArea);
  const fallback = `${roleLabel} · ${areaLabel}`;
  return [
    String(user.fullName || user.email || fallback).trim(),
    summaryParts.join(" · "),
  ].filter(Boolean).join(" | ");
}

function getQualifiedUserSelectOptions(capability = "inspect", signatureArea = "elektro") {
  const emptyLabel = capability === "authorize"
    ? "Odaberi nositelja"
    : "Odaberi ispitivača";
  return [
    { value: "", label: emptyLabel },
    ...getQualifiedUsersForSignatureArea(capability, signatureArea).map((user) => ({
      value: String(user.id),
      label: getQualifiedUserSelectLabel(user, capability, signatureArea),
    })),
  ];
}

function getQualifiedUserOptionsForSignatureAreas(
  capability = "inspect",
  signatureAreas = [],
  { includeEmpty = false, emptyLabel = "" } = {},
) {
  const normalizedAreas = Array.from(new Set(
    (Array.isArray(signatureAreas) ? signatureAreas : [signatureAreas])
      .map((area) => normalizeQualificationAreaKey(area))
      .filter(Boolean),
  ));
  const areas = normalizedAreas.length > 0 ? normalizedAreas : ["elektro"];
  const merged = new Map();

  areas.forEach((area) => {
    getQualifiedUsersForSignatureArea(capability, area).forEach((user) => {
      const key = String(user.id);
      const existing = merged.get(key) ?? {
        user,
        areas: new Set(),
      };
      existing.areas.add(area);
      merged.set(key, existing);
    });
  });

  const options = [...merged.values()]
    .sort((left, right) => String(left.user.fullName || left.user.email || "").localeCompare(
      String(right.user.fullName || right.user.email || ""),
      "hr",
    ))
    .map(({ user, areas: userAreas }) => {
      const labels = [...userAreas].map((area) => getSignatureAreaLabel(area));
      return {
        value: String(user.id),
        label: [
          String(user.fullName || user.email || "").trim(),
          labels.join(", "),
        ].filter(Boolean).join(" | "),
      };
    });

  if (!includeEmpty) {
    return options;
  }

  return [
    { value: "", label: emptyLabel || (capability === "authorize" ? "Odaberi nositelja" : "Odaberi ispitivača") },
    ...options,
  ];
}

function findQualifiedUserById(userId = "", capability = "inspect", signatureArea = "elektro") {
  const normalizedId = String(userId || "").trim();
  if (!normalizedId) {
    return null;
  }

  return getQualifiedUsersForSignatureArea(capability, signatureArea)
    .find((user) => String(user.id) === normalizedId) || null;
}

function getQualifiedUserSummaryValue(user = null, capability = "inspect", signatureArea = "elektro") {
  if (!user) {
    const roleLabel = capability === "authorize" ? "Nositelj ovlaštenja" : "Ispitivač";
    return `${roleLabel} (${getSignatureAreaLabel(signatureArea)})`;
  }

  const qualification = getUserElectricalQualification(user, signatureArea);
  return [
    getUserDocumentDisplayName(user),
    qualification.classCode ? `Klasa ${qualification.classCode}` : "",
    qualification.urbroj ? `UrBROJ ${qualification.urbroj}` : "",
    qualification.eBroj ? `E broj ${qualification.eBroj}` : "",
  ].filter(Boolean).join(" | ");
}

function getQualifiedUserDocumentMetaLines(user = null, capability = "inspect", signatureArea = "elektro") {
  if (!user) {
    return [];
  }

  const qualification = getUserElectricalQualification(user, signatureArea);
  return [
    user.title ? String(user.title).trim() : "",
    user.oib ? `OIB ${String(user.oib).trim()}` : "",
    qualification.classCode ? `Klasa ${qualification.classCode}` : "",
    qualification.urbroj ? `UrBROJ ${qualification.urbroj}` : "",
    qualification.eBroj ? `E broj ${qualification.eBroj}` : "",
  ].filter(Boolean);
}

function normalizeQualifiedUserIdList(values = []) {
  const source = Array.isArray(values)
    ? values
    : String(values || "")
      .split(",")
      .map((value) => value.trim())
      .filter(Boolean);

  return Array.from(new Set(source.map((value) => String(value || "").trim()).filter(Boolean)));
}

function getQualifiedUsersByIds(userIds = [], capability = "inspect", signatureArea = "elektro") {
  const normalizedIds = normalizeQualifiedUserIdList(userIds);
  if (normalizedIds.length === 0) {
    return [];
  }

  const eligibleUsers = new Map(
    getQualifiedUsersForSignatureArea(capability, signatureArea)
      .map((user) => [String(user.id), user]),
  );

  return normalizedIds
    .map((id) => eligibleUsers.get(String(id)) || null)
    .filter(Boolean);
}

function resolveQualifiedWorkOrderUsers(workOrder = {}, capability = "inspect", signatureArea = "elektro") {
  const normalizedArea = normalizeQualificationAreaKey(signatureArea);
  const executorNames = getWorkOrderExecutors(workOrder).map((entry) => normalizePersonLookupValue(entry)).filter(Boolean);
  const eligibleUsers = getQualifiedUsersForSignatureArea(capability, normalizedArea);

  return eligibleUsers.filter((user) => (
    executorNames.includes(normalizePersonLookupValue(user.fullName || user.email || ""))
  ));
}

function getWorkOrderDocumentQualifiedUsers(workOrder = {}, capability = "inspect", signatureArea = "elektro") {
  const areaSpecificListFieldName = getWorkOrderDocumentSignaturePersonListFieldName(capability, signatureArea);
  const areaSpecificUsers = getQualifiedUsersByIds(
    workOrder?.id && areaSpecificListFieldName
      ? getDocumentTemplateRuntimeArrayValue(workOrder.id, areaSpecificListFieldName)
      : [],
    capability,
    signatureArea,
  );

  if (areaSpecificUsers.length > 0) {
    return areaSpecificUsers;
  }

  const listFieldName = capability === "authorize" ? "authorizationHolderUserIds" : "inspectorUserIds";
  const explicitUsers = getQualifiedUsersByIds(
    workOrder?.id ? getDocumentTemplateRuntimeArrayValue(workOrder.id, listFieldName) : [],
    capability,
    signatureArea,
  );

  if (explicitUsers.length > 0) {
    return explicitUsers;
  }

  const areaSpecificFieldName = getWorkOrderDocumentSignaturePersonFieldName(capability, signatureArea);
  const areaSpecificUserId = workOrder?.id ? getDocumentTemplateRuntimeValue(workOrder.id, areaSpecificFieldName) : "";
  const areaSpecificUser = findQualifiedUserById(areaSpecificUserId, capability, signatureArea);
  if (areaSpecificUser) {
    return [areaSpecificUser];
  }

  const singleFieldName = capability === "authorize" ? "authorizationHolderUserId" : "inspectorUserId";
  const explicitSingleUserId = workOrder?.id ? getDocumentTemplateRuntimeValue(workOrder.id, singleFieldName) : "";
  const explicitSingleUser = findQualifiedUserById(explicitSingleUserId, capability, signatureArea);
  if (explicitSingleUser) {
    return [explicitSingleUser];
  }

  return resolveQualifiedWorkOrderUsers(workOrder, capability, signatureArea);
}

function getWorkOrderDocumentQualifiedUser(workOrder = {}, capability = "inspect", signatureArea = "elektro") {
  return getWorkOrderDocumentQualifiedUsers(workOrder, capability, signatureArea)[0]
    || resolveQualifiedWorkOrderUser(workOrder, capability, signatureArea);
}

function getDocumentTemplateRuntimeResolvedServiceItems(workOrder = {}) {
  const normalizedId = String(workOrder?.id || "").trim();
  const record = normalizedId ? getDocumentTemplateRuntimeOverrideRecord(normalizedId) : null;
  if (record && Object.prototype.hasOwnProperty.call(record, "serviceItems")) {
    return getWorkOrderServiceItems({ serviceItems: record.serviceItems });
  }
  return getWorkOrderServiceItems(workOrder);
}

function getDocumentTemplateRuntimeMatchedServiceItems(workOrder = {}, template = buildDocumentTemplateDraft()) {
  const runtimeTemplateId = getDocumentTemplateRuntimeTemplateId(template);
  const normalizedTemplateTitle = String(template?.title || "").trim().toLowerCase();

  return getDocumentTemplateRuntimeResolvedServiceItems(workOrder).filter((service) => {
    const templateIds = getWorkOrderServiceTemplateIds(service).map((value) => String(value || "").trim());
    if (runtimeTemplateId && templateIds.includes(runtimeTemplateId)) {
      return true;
    }

    if (!normalizedTemplateTitle) {
      return false;
    }

    return getResolvedWorkOrderServiceTemplateTitles(service)
      .map((value) => String(value || "").trim().toLowerCase())
      .includes(normalizedTemplateTitle);
  });
}

function getDocumentTemplateRuntimePrimaryServiceItem(workOrder = {}, template = buildDocumentTemplateDraft()) {
  return getDocumentTemplateRuntimeMatchedServiceItems(workOrder, template)[0] ?? null;
}

function getDocumentTemplateRuntimeDocumentNumber(workOrder = {}, template = buildDocumentTemplateDraft()) {
  const workOrderNumber = String(workOrder?.workOrderNumber || "").trim();
  const primaryService = getDocumentTemplateRuntimePrimaryServiceItem(workOrder, template);
  const serviceCode = String(
    primaryService?.serviceCode
    || primaryService?.name
    || template?.title
    || ""
  ).trim();

  return [workOrderNumber, serviceCode].filter(Boolean).join("-");
}

function formatQualifiedInspectorNameWithTitle(user = {}) {
  const name = String(user?.fullName || user?.email || "").trim();
  const title = String(user?.title || "").trim();
  return [name, title].filter(Boolean).join(", ");
}

function getWorkOrderDocumentQualifiedInspectorsWithTitles(workOrder = {}) {
  const orderedInspectors = [];
  const seenUserIds = new Set();

  WORK_ORDER_DOCUMENT_SIGNATURE_PERSON_FIELDS
    .filter((definition) => definition.capability === "inspect")
    .forEach((definition) => {
      getWorkOrderDocumentQualifiedUsers(workOrder, "inspect", definition.signatureArea).forEach((user) => {
        const key = String(user?.id || user?.email || user?.fullName || "").trim();
        if (!key || seenUserIds.has(key)) {
          return;
        }
        seenUserIds.add(key);
        orderedInspectors.push(user);
      });
    });

  return orderedInspectors
    .map((user) => formatQualifiedInspectorNameWithTitle(user))
    .filter(Boolean)
    .join(", ");
}

function getQualifiedUserSourcePreviewValue(source, context = {}) {
  const workOrder = context.sampleWorkOrder;
  const normalizedSource = String(source || "").trim().toUpperCase();
  if (!workOrder) {
    return "";
  }

  if (normalizedSource === "QUALIFIED_INSPECTOR_LIST_WITH_TITLES") {
    return getWorkOrderDocumentQualifiedInspectorsWithTitles(workOrder);
  }

  const sourceMap = {
    QUALIFIED_INSPECTOR_NAME: { capability: "inspect", field: "name" },
    QUALIFIED_INSPECTOR_CLASS_CODE: { capability: "inspect", field: "classCode" },
    QUALIFIED_INSPECTOR_URBROJ: { capability: "inspect", field: "urbroj" },
    QUALIFIED_INSPECTOR_E_BROJ: { capability: "inspect", field: "eBroj" },
    QUALIFIED_INSPECTOR_SUMMARY: { capability: "inspect", field: "summary" },
    QUALIFIED_AUTHORIZATION_HOLDER_NAME: { capability: "authorize", field: "name" },
    QUALIFIED_AUTHORIZATION_HOLDER_CLASS_CODE: { capability: "authorize", field: "classCode" },
    QUALIFIED_AUTHORIZATION_HOLDER_URBROJ: { capability: "authorize", field: "urbroj" },
    QUALIFIED_AUTHORIZATION_HOLDER_E_BROJ: { capability: "authorize", field: "eBroj" },
    QUALIFIED_AUTHORIZATION_HOLDER_SUMMARY: { capability: "authorize", field: "summary" },
  };
  const mapping = sourceMap[normalizedSource];
  if (!mapping) {
    return "";
  }

  const user = getWorkOrderDocumentQualifiedUser(workOrder, mapping.capability, "elektro");
  if (!user) {
    return "";
  }

  const qualification = getUserElectricalQualification(user);
  if (mapping.field === "summary") {
    return getQualifiedUserSummaryValue(user, mapping.capability, "elektro");
  }
  if (mapping.field === "name") {
    return getUserDocumentDisplayName(user);
  }

  return String(qualification[mapping.field] || "").trim();
}

function getUserDocuments(user = {}) {
  return Array.isArray(user?.documents) ? user.documents : [];
}

function getUserSignatureScanDataUrl(user = {}) {
  const rootQualification = user?.electricalQualification ?? {};
  return String(
    user?.signatureDataUrl
    || user?.signatureStorageUrl
    || rootQualification.signatureDataUrl
    || rootQualification.signatureStorageUrl
    || rootQualification.storageUrl
    || "",
  ).trim();
}

function clearUserElectricalSignaturePad({ preserveValue = false } = {}) {
  if (!preserveValue && userElectricalSignatureDataUrlInput) {
    userElectricalSignatureDataUrlInput.value = "";
  }

  if (userElectricalSignatureFileInput) {
    userElectricalSignatureFileInput.value = "";
  }

  if (userElectricalSignaturePreview) {
    userElectricalSignaturePreview.replaceChildren();
    userElectricalSignaturePreview.classList.add("is-empty");
  }
}

function renderUserElectricalSignaturePad(signatureValue = "") {
  const safeValue = String(signatureValue || "").trim();

  if (userElectricalSignatureDataUrlInput) {
    userElectricalSignatureDataUrlInput.value = safeValue;
  }

  if (userElectricalSignatureFileInput) {
    userElectricalSignatureFileInput.value = "";
  }

  if (!userElectricalSignaturePreview) {
    return;
  }

  userElectricalSignaturePreview.replaceChildren();
  userElectricalSignaturePreview.classList.toggle("is-empty", !safeValue);

  if (!safeValue) {
    return;
  }

  const previewImage = document.createElement("img");
  previewImage.src = safeValue;
  previewImage.alt = "Scan potpisa korisnika";
  previewImage.loading = "lazy";

  userElectricalSignaturePreview.append(previewImage);
}

async function queueUserElectricalSignatureFile(file) {
  if (!file) {
    return;
  }

  const dataUrl = await readFileAsDataUrl(file, `Ne mogu učitati datoteku ${file.name}.`);
  renderUserElectricalSignaturePad(dataUrl);
}

function setUserDocumentDrafts(items = []) {
  userDocumentDrafts = (Array.isArray(items) ? items : [])
    .map((item) => createModuleAttachmentDraft(item))
    .filter((item) => item.fileName && item.dataUrl);
}

function updateUserDocumentDraft(documentId, patch = {}) {
  userDocumentDrafts = userDocumentDrafts.map((item) => (
    item.id === documentId
      ? {
        ...item,
        ...patch,
      }
      : item
  ));
}

function focusUserDocumentCategory(documentId = "") {
  if (!documentId || !userDocumentsList) {
    return;
  }

  requestAnimationFrame(() => {
    const target = Array.from(
      userDocumentsList.querySelectorAll(".module-attachment-category-select"),
    ).find((input) => input.dataset.documentId === String(documentId));

    target?.focus({ preventScroll: false });
  });
}

function focusUserDocumentCustomCategory(documentId = "") {
  if (!documentId || !userDocumentsList) {
    return;
  }

  requestAnimationFrame(() => {
    const target = Array.from(
      userDocumentsList.querySelectorAll(".module-attachment-custom-category-input"),
    ).find((input) => input.dataset.documentId === String(documentId));

    target?.focus({ preventScroll: false });
  });
}

function finalizeUserDocumentCustomCategory(documentId = "", rawValue = "") {
  const nextValue = String(rawValue || "").trim();
  if (!documentId || !nextValue) {
    return false;
  }

  updateUserDocumentDraft(documentId, {
    documentCategory: nextValue,
    documentCategoryMode: "",
  });
  renderUserDocuments();
  focusUserDocumentCategory(documentId);
  return true;
}

function renderUserDocuments() {
  if (!userDocumentsList) {
    return;
  }

  if (userDocumentDrafts.length === 0) {
    const empty = document.createElement("div");
    empty.className = "module-attachment-empty";
    empty.setAttribute("aria-label", "Nema dokumenata za korisnika");
    userDocumentsList.replaceChildren(empty);
    return;
  }

  userDocumentsList.replaceChildren(...userDocumentDrafts.map((entry) => {
    const row = document.createElement("article");
    row.className = "module-attachment-row";
    row.classList.toggle("is-unclassified", !entry.documentCategory);

    const copy = document.createElement("div");
    copy.className = "module-attachment-copy";

    const meta = document.createElement("span");
    meta.className = "module-attachment-meta";
    meta.textContent = [
      entry.fileType || "",
      formatFileSize(entry.fileSize),
      entry.updatedAt ? formatCompactDate(entry.updatedAt) : "",
    ].filter(Boolean).join(" | ");

    const fieldWrap = document.createElement("div");
    fieldWrap.className = "module-attachment-fields";

    const nameField = document.createElement("label");
    nameField.className = "module-attachment-field";

    const nameLabel = document.createElement("span");
    nameLabel.className = "module-attachment-field-label";
    nameLabel.textContent = "Naziv";

    const nameInput = document.createElement("input");
    nameInput.type = "text";
    nameInput.value = entry.fileName;
    nameInput.maxLength = 220;
    nameInput.placeholder = "Naziv dokumenta";
    nameInput.addEventListener("input", () => {
      updateUserDocumentDraft(entry.id, { fileName: nameInput.value });
    });

    nameField.append(nameLabel, nameInput);

    const categoryField = document.createElement("label");
    categoryField.className = "module-attachment-field";

    const categoryLabel = document.createElement("span");
    categoryLabel.className = "module-attachment-field-label";
    categoryLabel.textContent = "Vrsta";

    const categorySelect = document.createElement("select");
    categorySelect.className = "module-attachment-category-select";
    categorySelect.dataset.documentId = entry.id;
    const categoryOptions = buildDraftCategoryOptions(
      USER_DOCUMENT_CATEGORY_OPTIONS,
      userDocumentDrafts,
      entry.documentCategory || "",
    );
    const usesCustomCategory = entry.documentCategoryMode === "custom";
    replaceSelectOptions(
      categorySelect,
      categoryOptions,
      entry.documentCategory || "",
    );
    categorySelect.addEventListener("change", () => {
      const nextValue = categorySelect.value || "";
      if (nextValue === "__custom__") {
        updateUserDocumentDraft(entry.id, {
          documentCategory: "",
          documentCategoryMode: "custom",
        });
        renderUserDocuments();
        focusUserDocumentCustomCategory(entry.id);
        return;
      }
      updateUserDocumentDraft(entry.id, {
        documentCategory: nextValue,
        documentCategoryMode: "",
      });
      row.classList.toggle("is-unclassified", !nextValue);
      if (usesCustomCategory) {
        renderUserDocuments();
      }
    });

    categoryField.append(categoryLabel, categorySelect);
    fieldWrap.append(nameField, categoryField);
    if (usesCustomCategory) {
      const customCategoryField = document.createElement("label");
      customCategoryField.className = "module-attachment-field is-custom-category";

      const customCategoryLabel = document.createElement("span");
      customCategoryLabel.className = "module-attachment-field-label";
      customCategoryLabel.textContent = "Nova vrsta";

      const customCategoryInput = document.createElement("input");
      customCategoryInput.type = "text";
      customCategoryInput.value = entry.documentCategory || "";
      customCategoryInput.maxLength = 64;
      customCategoryInput.placeholder = "Upiši vrstu dokumenta";
      customCategoryInput.className = "module-attachment-custom-category-input";
      customCategoryInput.dataset.documentId = entry.id;
      customCategoryInput.addEventListener("input", () => {
        const customValue = customCategoryInput.value;
        updateUserDocumentDraft(entry.id, {
          documentCategory: customValue,
          documentCategoryMode: "custom",
        });
        row.classList.toggle("is-unclassified", !String(customValue || "").trim());
      });
      customCategoryInput.addEventListener("blur", () => {
        finalizeUserDocumentCustomCategory(entry.id, customCategoryInput.value);
      });
      customCategoryInput.addEventListener("keydown", (event) => {
        if (event.key === "Enter") {
          event.preventDefault();
          finalizeUserDocumentCustomCategory(entry.id, customCategoryInput.value);
          return;
        }

        if (event.key === "Escape") {
          event.preventDefault();
          updateUserDocumentDraft(entry.id, {
            documentCategory: "",
            documentCategoryMode: "",
          });
          renderUserDocuments();
          focusUserDocumentCategory(entry.id);
        }
      });

      customCategoryField.append(customCategoryLabel, customCategoryInput);
      fieldWrap.append(customCategoryField);
    }

    copy.append(meta, fieldWrap);

    const actions = document.createElement("div");
    actions.className = "module-attachment-actions";

    const openButton = createActionButton("Preuzmi", "card-button", () => {
      triggerModuleAttachmentDownload({
        ...entry,
        fileName: nameInput.value || entry.fileName,
      });
    });
    const removeButton = createActionButton("Makni", "card-button card-danger", () => {
      userDocumentDrafts = userDocumentDrafts.filter((item) => item.id !== entry.id);
      renderUserDocuments();
    });

    actions.append(openButton, removeButton);
    row.append(copy, actions);
    return row;
  }));
}

async function queueUserDocuments(files) {
  const uploads = await buildWorkOrderDocumentUploadPayload(files);
  const nextDocuments = uploads.map((file) => createModuleAttachmentDraft(file));
  userDocumentDrafts = [
    ...userDocumentDrafts,
    ...nextDocuments,
  ];
  renderUserDocuments();
  focusUserDocumentCategory(nextDocuments[0]?.id || "");
}

function setUserElectricalDocumentDrafts(items = []) {
  userElectricalDocumentDrafts = (Array.isArray(items) ? items : [])
    .map((item) => createModuleAttachmentDraft(item))
    .filter((item) => item.fileName && item.dataUrl);
}

function updateUserElectricalDocumentDraft(documentId, patch = {}) {
  userElectricalDocumentDrafts = userElectricalDocumentDrafts.map((item) => (
    item.id === documentId
      ? {
        ...item,
        ...patch,
      }
      : item
  ));
}

function focusUserElectricalDocumentCategory(documentId = "") {
  if (!documentId || !userElectricalDocumentsList) {
    return;
  }

  requestAnimationFrame(() => {
    const target = Array.from(
      userElectricalDocumentsList.querySelectorAll(".module-attachment-category-select"),
    ).find((input) => input.dataset.documentId === String(documentId));

    target?.focus({ preventScroll: false });
  });
}

function renderUserElectricalDocuments() {
  if (!userElectricalDocumentsList) {
    return;
  }

  if (userElectricalDocumentDrafts.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy module-copy";
    empty.textContent = "Nema dodanih dokumenata panik rasvjete za ovog korisnika.";
    userElectricalDocumentsList.replaceChildren(empty);
    return;
  }

  userElectricalDocumentsList.replaceChildren(...userElectricalDocumentDrafts.map((entry) => {
    const row = document.createElement("article");
    row.className = "module-attachment-row";
    row.classList.toggle("is-unclassified", !entry.documentCategory);

    const copy = document.createElement("div");
    copy.className = "module-attachment-copy";

    const title = document.createElement("strong");
    title.textContent = entry.fileName;

    const meta = document.createElement("span");
    meta.textContent = [
      entry.fileType || "",
      formatFileSize(entry.fileSize),
      entry.updatedAt ? formatCompactDate(entry.updatedAt) : "",
    ].filter(Boolean).join(" | ");

    copy.append(title, meta);

    const fieldWrap = document.createElement("div");
    fieldWrap.className = "module-attachment-fields";

    const categoryField = document.createElement("label");
    categoryField.className = "module-attachment-field";

    const categoryLabel = document.createElement("span");
    categoryLabel.className = "module-attachment-field-label";
    categoryLabel.textContent = "Što je ovo?";

    const categorySelect = document.createElement("select");
    categorySelect.className = "module-attachment-category-select";
    categorySelect.dataset.documentId = entry.id;
    replaceSelectOptions(
      categorySelect,
      USER_ELECTRICAL_DOCUMENT_CATEGORY_OPTIONS,
      entry.documentCategory || "",
    );
    categorySelect.addEventListener("change", () => {
      const nextValue = categorySelect.value || "";
      updateUserElectricalDocumentDraft(entry.id, { documentCategory: nextValue });
      row.classList.toggle("is-unclassified", !nextValue);
    });
    categoryField.append(categoryLabel, categorySelect);
    fieldWrap.append(categoryField);
    copy.append(fieldWrap);

    const actions = document.createElement("div");
    actions.className = "module-attachment-actions";

    const openButton = createActionButton("Preuzmi", "card-button", () => {
      triggerModuleAttachmentDownload(entry);
    });
    const removeButton = createActionButton("Makni", "card-button card-danger", () => {
      userElectricalDocumentDrafts = userElectricalDocumentDrafts.filter((item) => item.id !== entry.id);
      renderUserElectricalDocuments();
    });

    actions.append(openButton, removeButton);
    row.append(copy, actions);
    return row;
  }));
}

async function queueUserElectricalDocuments(files) {
  const uploads = await buildWorkOrderDocumentUploadPayload(files);
  const nextDocuments = uploads.map((file) => createModuleAttachmentDraft(file));
  userElectricalDocumentDrafts = [
    ...userElectricalDocumentDrafts,
    ...nextDocuments,
  ];
  renderUserElectricalDocuments();
  focusUserElectricalDocumentCategory(nextDocuments[0]?.id || "");
}

function setMeasurementEquipmentDocumentDrafts(items = []) {
  measurementEquipmentDocumentDrafts = (Array.isArray(items) ? items : [])
    .map((item) => createModuleAttachmentDraft({
      ...item,
      isPersisted: true,
    }))
    .filter((item) => (
      item.fileName
      && item.dataUrl
      && normalizeMeasurementEquipmentDocumentCategoryValue(item.documentCategory) !== MEASUREMENT_EQUIPMENT_CARD_TEMPLATE_CATEGORY
    ));
}

function updateMeasurementEquipmentDocumentDraft(documentId, patch = {}) {
  measurementEquipmentDocumentDrafts = measurementEquipmentDocumentDrafts.map((item) => (
    item.id === documentId
      ? {
        ...item,
        ...(
          item.documentCategoryLocked
            ? Object.fromEntries(
              Object.entries(patch).filter(([key]) => !["documentCategory", "documentCategoryMode", "documentCategoryLocked"].includes(key)),
            )
            : patch
        ),
      }
      : item
  ));
}

function focusMeasurementEquipmentDocumentCategory(documentId = "") {
  if (!documentId || !measurementEquipmentDocumentsList) {
    return;
  }

  requestAnimationFrame(() => {
    const target = Array.from(
      measurementEquipmentDocumentsList.querySelectorAll(".module-attachment-category-select"),
    ).find((input) => input.dataset.documentId === String(documentId));

    target?.focus({ preventScroll: false });
  });
}

function triggerModuleAttachmentDownload(fileDocument) {
  const href = String(fileDocument?.storageUrl || fileDocument?.dataUrl || "").trim();

  if (!href) {
    return;
  }

  const link = document.createElement("a");
  link.href = href;
  link.download = String(fileDocument?.fileName || "dokument").trim() || "dokument";
  link.target = "_blank";
  link.rel = "noopener";
  document.body.append(link);
  link.click();
  link.remove();
}

function normalizeMeasurementEquipmentDocumentCategoryValue(value = "") {
  return String(value || "").trim().toLowerCase();
}

function getMeasurementEquipmentDocumentCategoryLabel(value = "") {
  const normalized = normalizeMeasurementEquipmentDocumentCategoryValue(value);
  if (!normalized) {
    return "";
  }
  return getOptionLabel(MEASUREMENT_EQUIPMENT_DOCUMENT_CATEGORY_OPTIONS, normalized)
    || normalized.replace(/_/g, " ");
}

function isMeasurementEquipmentWordTemplateDocument(entry = {}) {
  const fileName = String(entry?.fileName || "").trim().toLowerCase();
  const fileType = String(entry?.fileType || "").trim().toLowerCase();
  return fileName.endsWith(".docx")
    || fileName.endsWith(".dotx")
    || /officedocument\.wordprocessingml\.(document|template)/i.test(fileType);
}

function getMeasurementEquipmentCardTemplateDocument() {
  const templateDocument = state.measurementEquipmentCardTemplate;
  if (!templateDocument || typeof templateDocument !== "object") {
    return null;
  }
  return {
    ...templateDocument,
    documentCategory: MEASUREMENT_EQUIPMENT_CARD_TEMPLATE_CATEGORY,
  };
}

function buildMeasurementEquipmentExportActivityLines(type = "", { limit = 0 } = {}) {
  const normalizedType = normalizeMeasurementEquipmentActivityTypeValue(type);
  const safeLimit = Number.isFinite(Number(limit)) && Number(limit) > 0
    ? Math.max(1, Math.min(24, Math.round(Number(limit))))
    : 0;

  let entries = buildMeasurementEquipmentActivityPayload()
    .filter((entry) => (normalizedType ? normalizeMeasurementEquipmentActivityTypeValue(entry.activityType) === normalizedType : true));
  if (safeLimit > 0) {
    entries = entries.slice(0, safeLimit);
  }

  return entries
    .map((entry) => {
      const safeType = normalizeMeasurementEquipmentActivityTypeValue(entry.activityType);
      const base = [
        getMeasurementEquipmentActivityTypeLabel(safeType),
        entry.performedOn ? formatCompactDate(entry.performedOn) : "bez datuma",
      ];
      if (entry.performedBy) {
        base.push(entry.performedBy);
      }
      if (safeType === "umjeravanje") {
        if (entry.validUntil) {
          base.push(`vrijedi do ${formatCompactDate(entry.validUntil)}`);
        }
        if (entry.satisfies) {
          base.push(`zadovoljava: ${String(entry.satisfies || "").toUpperCase()}`);
        }
      } else if (entry.note) {
        base.push(entry.note);
      }
      return base.filter(Boolean).join(" - ");
    })
    .filter(Boolean);
}

function buildMeasurementEquipmentExportActivityLinesFromEntries(
  entriesInput = [],
  type = "",
  { limit = 0 } = {},
) {
  const normalizedType = normalizeMeasurementEquipmentActivityTypeValue(type);
  const safeLimit = Number.isFinite(Number(limit)) && Number(limit) > 0
    ? Math.max(1, Math.min(24, Math.round(Number(limit))))
    : 0;

  let entries = (Array.isArray(entriesInput) ? entriesInput : [])
    .map((entry) => createMeasurementEquipmentActivityDraft(entry, { defaultCompleted: true }))
    .filter((entry) => entry.activityType || entry.performedOn || entry.performedBy || entry.validUntil || entry.calibrationPeriod || entry.satisfies || entry.note)
    .sort(compareMeasurementEquipmentActivityDraftRecency)
    .filter((entry) => (normalizedType ? normalizeMeasurementEquipmentActivityTypeValue(entry.activityType) === normalizedType : true));

  if (safeLimit > 0) {
    entries = entries.slice(0, safeLimit);
  }

  return entries
    .map((entry) => {
      const safeType = normalizeMeasurementEquipmentActivityTypeValue(entry.activityType);
      const base = [
        getMeasurementEquipmentActivityTypeLabel(safeType),
        entry.performedOn ? formatCompactDate(entry.performedOn) : "bez datuma",
      ];
      if (entry.performedBy) {
        base.push(entry.performedBy);
      }
      if (safeType === "umjeravanje") {
        if (entry.validUntil) {
          base.push(`vrijedi do ${formatCompactDate(entry.validUntil)}`);
        }
        if (entry.satisfies) {
          base.push(`zadovoljava: ${String(entry.satisfies || "").toUpperCase()}`);
        }
      } else if (entry.note) {
        base.push(entry.note);
      }
      return base.filter(Boolean).join(" - ");
    })
    .filter(Boolean);
}

function normalizeMeasurementEquipmentSpecDraftEntry(entry = {}) {
  return {
    id: String(entry.id || crypto.randomUUID()),
    quantity: String(entry.quantity || entry.measurementQuantity || entry.mjernaVelicina || "").trim().slice(0, 140),
    range: String(entry.range || entry.raspon || "").trim().slice(0, 140),
    remark: String(entry.remark || entry.opaska || "").trim().slice(0, 220),
  };
}

function setMeasurementEquipmentSpecDrafts(items = []) {
  measurementEquipmentSpecDrafts = (Array.isArray(items) ? items : [])
    .map((entry) => normalizeMeasurementEquipmentSpecDraftEntry(entry))
    .filter((entry) => entry.quantity || entry.range || entry.remark)
    .slice(0, 6);

  if (measurementEquipmentSpecDrafts.length === 0) {
    measurementEquipmentSpecDrafts = [normalizeMeasurementEquipmentSpecDraftEntry({})];
    return;
  }

  if (
    measurementEquipmentSpecDrafts.length < 6
    && measurementEquipmentSpecDrafts.every((entry) => entry.quantity || entry.range || entry.remark)
  ) {
    measurementEquipmentSpecDrafts.push(normalizeMeasurementEquipmentSpecDraftEntry({}));
  }
}

function updateMeasurementEquipmentSpecDraft(specId = "", patch = {}) {
  const targetId = String(specId || "").trim();
  if (!targetId) {
    return { didAppendRow: false };
  }

  const index = measurementEquipmentSpecDrafts.findIndex((entry) => String(entry.id) === targetId);
  if (index < 0) {
    return { didAppendRow: false };
  }

  const currentEntry = measurementEquipmentSpecDrafts[index];
  const nextEntry = normalizeMeasurementEquipmentSpecDraftEntry({
    ...currentEntry,
    ...patch,
  });

  if (
    currentEntry.quantity === nextEntry.quantity
    && currentEntry.range === nextEntry.range
    && currentEntry.remark === nextEntry.remark
  ) {
    return { didAppendRow: false };
  }

  measurementEquipmentSpecDrafts[index] = nextEntry;

  const hasBlank = measurementEquipmentSpecDrafts.some((entry) => !(entry.quantity || entry.range || entry.remark));
  let didAppendRow = false;
  if (!hasBlank && measurementEquipmentSpecDrafts.length < 6) {
    measurementEquipmentSpecDrafts.push(normalizeMeasurementEquipmentSpecDraftEntry({}));
    didAppendRow = true;
  }

  return { didAppendRow };
}

function buildMeasurementEquipmentSpecPayload() {
  return measurementEquipmentSpecDrafts
    .map((entry) => normalizeMeasurementEquipmentSpecDraftEntry(entry))
    .filter((entry) => entry.quantity || entry.range || entry.remark)
    .slice(0, 6);
}

function buildMeasurementEquipmentExportSpecLines() {
  return buildMeasurementEquipmentSpecPayload()
    .map((entry, index) => {
      const values = [entry.quantity, entry.range, entry.remark].filter(Boolean);
      return values.length > 0
        ? `${index + 1}. ${values.join(" | ")}`
        : "";
    })
    .filter(Boolean);
}

function buildMeasurementEquipmentExportDocumentLines() {
  return measurementEquipmentDocumentDrafts
    .filter((entry) => normalizeMeasurementEquipmentDocumentCategoryValue(entry.documentCategory) !== MEASUREMENT_EQUIPMENT_CARD_TEMPLATE_CATEGORY)
    .map((entry) => [
      getMeasurementEquipmentDocumentCategoryLabel(entry.documentCategory) || "Dokument",
      entry.fileName || "",
    ].filter(Boolean).join(": "))
    .filter(Boolean);
}

function buildMeasurementEquipmentExportDocumentLinesFromEntries(entriesInput = []) {
  return (Array.isArray(entriesInput) ? entriesInput : [])
    .filter((entry) => normalizeMeasurementEquipmentDocumentCategoryValue(entry.documentCategory) !== MEASUREMENT_EQUIPMENT_CARD_TEMPLATE_CATEGORY)
    .map((entry) => [
      getMeasurementEquipmentDocumentCategoryLabel(entry.documentCategory) || "Dokument",
      entry.fileName || "",
    ].filter(Boolean).join(": "))
    .filter(Boolean);
}

function getMeasurementEquipmentCardPlaceholderDefinitions() {
  const definitions = [...MEASUREMENT_EQUIPMENT_CARD_PLACEHOLDER_BASE_DEFINITIONS];
  for (let index = 1; index <= 6; index += 1) {
    definitions.push(
      { key: `MJERNA_VELICINA_${index}`, label: `Mjerna veličina ${index}` },
      { key: `RASPON_${index}`, label: `Raspon ${index}` },
      { key: `OPASKA_${index}`, label: `Opaska ${index}` },
    );
  }
  return definitions;
}

function buildMeasurementEquipmentPlaceholderWordMarkup() {
  const rows = getMeasurementEquipmentCardPlaceholderDefinitions()
    .map((entry) => `
      <tr>
        <td>{{${escapeHtml(entry.key)}}}</td>
        <td>${escapeHtml(entry.label)}</td>
      </tr>
    `)
    .join("");

  return `
    <div class="cover">
      <h1>Karton opreme · Placeholderi</h1>
      <p>Kopiraj točan token (s vitičastim zagradama) u svoj .docx/.dotx predložak.</p>
      <table class="placeholder-table">
        <thead>
          <tr>
            <th>Placeholder</th>
            <th>Značenje</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>
    </div>
  `;
}

function buildMeasurementEquipmentExportPlaceholders() {
  const requiresCalibration = measurementEquipmentRequiresCalibrationInput?.value === "true";
  const linkedTemplateTitles = getTemplateTitlesByIds(getMeasurementEquipmentTemplateSelectionIds());
  const activityAll = buildMeasurementEquipmentExportActivityLines();
  const activityCalibration = buildMeasurementEquipmentExportActivityLines("umjeravanje", { limit: 6 });
  const activityReview = buildMeasurementEquipmentExportActivityLines("pregled", { limit: 6 });
  const activityService = buildMeasurementEquipmentExportActivityLines("servis", { limit: 6 });
  const documentLines = buildMeasurementEquipmentExportDocumentLines();
  const specItems = buildMeasurementEquipmentSpecPayload();
  const specLines = buildMeasurementEquipmentExportSpecLines();
  const todayIso = new Date().toISOString().slice(0, 10);

  const placeholders = {
    NAZIV_UREDJAJA: measurementEquipmentNameInput?.value || "",
    PROIZVODAC: measurementEquipmentManufacturerInput?.value || "",
    TIP_MODEL: measurementEquipmentTypeInput?.value || "",
    OZNAKA_UREDAJA: measurementEquipmentDeviceCodeInput?.value || "",
    SERIJSKI_BROJ: measurementEquipmentSerialNumberInput?.value || "",
    INV_BROJ: measurementEquipmentInventoryNumberInput?.value || "",
    MJERNU_OPREMU_UNIO: measurementEquipmentEnteredByInput?.value || "",
    ODOBRIO: measurementEquipmentApprovedByInput?.value || "",
    DATUM_UNOSA: measurementEquipmentEntryDateInput?.value ? formatCompactDate(measurementEquipmentEntryDateInput.value) : "",
    UMJERAVA_SE: requiresCalibration ? "DA" : "NE",
    DATUM_UMJERAVANJA: measurementEquipmentCalibrationDateInput?.value ? formatCompactDate(measurementEquipmentCalibrationDateInput.value) : "",
    PERIODIKA_UMJERAVANJA: measurementEquipmentCalibrationPeriodInput?.value || "",
    VRIJEDI_DO: measurementEquipmentValidUntilInput?.value ? formatCompactDate(measurementEquipmentValidUntilInput.value) : "",
    ZAPISNICI: linkedTemplateTitles.join(", "),
    AKTIVNOSTI: activityAll.join("\n"),
    AKTIVNOSTI_UMJERAVANJE: activityCalibration.join("\n"),
    AKTIVNOSTI_PREGLED: activityReview.join("\n"),
    AKTIVNOSTI_SERVIS: activityService.join("\n"),
    DOKUMENTI: documentLines.join("\n"),
    MJERNE_STAVKE: specLines.join("\n"),
    NAPOMENA: measurementEquipmentNoteInput?.value || "",
    DATUM_GENERIRANJA: formatCompactDate(todayIso),
    DANAS: formatCompactDate(todayIso),
  };

  for (let index = 0; index < 6; index += 1) {
    const entry = specItems[index] ?? {};
    placeholders[`MJERNA_VELICINA_${index + 1}`] = entry.quantity || "";
    placeholders[`RASPON_${index + 1}`] = entry.range || "";
    placeholders[`OPASKA_${index + 1}`] = entry.remark || "";
  }

  return placeholders;
}

function buildMeasurementEquipmentExportPlaceholdersForItem(item = {}) {
  const requiresCalibration = item?.requiresCalibration === true
    || String(item?.requiresCalibration || "").toLowerCase() === "true"
    || String(item?.requiresCalibration || "") === "1";
  const linkedTemplateTitles = (Array.isArray(item?.linkedTemplateTitles) && item.linkedTemplateTitles.length > 0)
    ? item.linkedTemplateTitles
    : getTemplateTitlesByIds(Array.isArray(item?.linkedTemplateIds) ? item.linkedTemplateIds : []);
  const activityEntries = Array.isArray(item?.activityItems) ? item.activityItems : [];
  const activityAll = buildMeasurementEquipmentExportActivityLinesFromEntries(activityEntries);
  const activityCalibration = buildMeasurementEquipmentExportActivityLinesFromEntries(activityEntries, "umjeravanje", { limit: 6 });
  const activityReview = buildMeasurementEquipmentExportActivityLinesFromEntries(activityEntries, "pregled", { limit: 6 });
  const activityService = buildMeasurementEquipmentExportActivityLinesFromEntries(activityEntries, "servis", { limit: 6 });
  const documentLines = buildMeasurementEquipmentExportDocumentLinesFromEntries(item?.documents ?? []);
  const specItems = (Array.isArray(item?.measurementSpecs) ? item.measurementSpecs : [])
    .map((entry) => normalizeMeasurementEquipmentSpecDraftEntry(entry))
    .filter((entry) => entry.quantity || entry.range || entry.remark)
    .slice(0, 6);
  const specLines = specItems
    .map((entry, index) => {
      const values = [entry.quantity, entry.range, entry.remark].filter(Boolean);
      return values.length > 0 ? `${index + 1}. ${values.join(" | ")}` : "";
    })
    .filter(Boolean);
  const todayIso = new Date().toISOString().slice(0, 10);

  const placeholders = {
    NAZIV_UREDJAJA: item?.name || "",
    PROIZVODAC: item?.manufacturer || "",
    TIP_MODEL: item?.deviceType || "",
    OZNAKA_UREDAJA: item?.deviceCode || "",
    SERIJSKI_BROJ: item?.serialNumber || "",
    INV_BROJ: item?.inventoryNumber || "",
    MJERNU_OPREMU_UNIO: item?.enteredBy || "",
    ODOBRIO: item?.approvedBy || "",
    DATUM_UNOSA: item?.entryDate ? formatCompactDate(item.entryDate) : "",
    UMJERAVA_SE: requiresCalibration ? "DA" : "NE",
    DATUM_UMJERAVANJA: item?.calibrationDate ? formatCompactDate(item.calibrationDate) : "",
    PERIODIKA_UMJERAVANJA: item?.calibrationPeriod || "",
    VRIJEDI_DO: item?.validUntil ? formatCompactDate(item.validUntil) : "",
    ZAPISNICI: linkedTemplateTitles.join(", "),
    AKTIVNOSTI: activityAll.join("\n"),
    AKTIVNOSTI_UMJERAVANJE: activityCalibration.join("\n"),
    AKTIVNOSTI_PREGLED: activityReview.join("\n"),
    AKTIVNOSTI_SERVIS: activityService.join("\n"),
    DOKUMENTI: documentLines.join("\n"),
    MJERNE_STAVKE: specLines.join("\n"),
    NAPOMENA: item?.note || "",
    DATUM_GENERIRANJA: formatCompactDate(todayIso),
    DANAS: formatCompactDate(todayIso),
  };

  for (let index = 0; index < 6; index += 1) {
    const entry = specItems[index] ?? {};
    placeholders[`MJERNA_VELICINA_${index + 1}`] = entry.quantity || "";
    placeholders[`RASPON_${index + 1}`] = entry.range || "";
    placeholders[`OPASKA_${index + 1}`] = entry.remark || "";
  }

  return placeholders;
}

function buildMeasurementEquipmentCardExportFileBaseName() {
  const inventoryNumber = String(measurementEquipmentInventoryNumberInput?.value || "").trim();
  const equipmentName = String(measurementEquipmentNameInput?.value || "").trim();
  const fallbackName = inventoryNumber || equipmentName || "karton-uredaja";
  const datePart = new Date().toISOString().slice(0, 10);
  return `${sanitizeDocumentTemplateFileName(fallbackName, "karton-uredaja")}-${datePart}`;
}

function buildMeasurementEquipmentCardExportFileBaseNameForItem(item = {}) {
  const inventoryNumber = String(item?.inventoryNumber || "").trim();
  const equipmentName = String(item?.name || "").trim();
  const fallbackName = inventoryNumber || equipmentName || "karton-uredaja";
  const datePart = new Date().toISOString().slice(0, 10);
  return `${sanitizeDocumentTemplateFileName(fallbackName, "karton-uredaja")}-${datePart}`;
}

function getMeasurementEquipmentExportItems() {
  return sortMeasurementEquipmentItems(state.measurementEquipment ?? []);
}

function getMeasurementEquipmentZipCategoryOptions() {
  return MEASUREMENT_EQUIPMENT_DOCUMENT_CATEGORY_OPTIONS
    .filter((option) => {
      const normalizedValue = normalizeMeasurementEquipmentDocumentCategoryValue(option.value || "");
      return Boolean(normalizedValue && normalizedValue !== MEASUREMENT_EQUIPMENT_CARD_TEMPLATE_CATEGORY);
    });
}

const MEASUREMENT_EQUIPMENT_EXPORT_ALL_TOKEN = "__all__";

function getSelectedMultiSelectValues(select) {
  if (!(select instanceof HTMLSelectElement)) {
    return [];
  }
  return Array.from(select.selectedOptions)
    .map((option) => String(option.value || "").trim())
    .filter(Boolean);
}

function setMultiSelectSelectedValues(select, values = []) {
  if (!(select instanceof HTMLSelectElement)) {
    return;
  }
  const selectedSet = new Set((Array.isArray(values) ? values : []).map((value) => String(value)));
  Array.from(select.options).forEach((option) => {
    option.selected = selectedSet.has(String(option.value));
  });
}

function renderMeasurementEquipmentExportDialogOptions({ resetSelection = false } = {}) {
  const items = getMeasurementEquipmentExportItems();
  const categoryOptions = getMeasurementEquipmentZipCategoryOptions();

  if (measurementEquipmentExportDevicesInput) {
    const previousSelected = resetSelection ? [] : getSelectedMultiSelectValues(measurementEquipmentExportDevicesInput);
    const allDeviceOption = createOption(
      MEASUREMENT_EQUIPMENT_EXPORT_ALL_TOKEN,
      `ALL · svi uređaji (${items.length})`,
    );
    const deviceOptions = items.map((item) => createOption(
      String(item.id),
      [item.id ? `#${item.id}` : "", item.name || "Bez naziva", item.inventoryNumber ? `Inv ${item.inventoryNumber}` : ""]
        .filter(Boolean)
        .join(" · "),
    ));
    measurementEquipmentExportDevicesInput.replaceChildren(allDeviceOption, ...deviceOptions);

    const availableValues = new Set(items.map((item) => String(item.id)));
    const nextSelected = previousSelected.filter((value) => availableValues.has(value));
    if (nextSelected.length === 0 || previousSelected.includes(MEASUREMENT_EQUIPMENT_EXPORT_ALL_TOKEN)) {
      setMultiSelectSelectedValues(measurementEquipmentExportDevicesInput, [MEASUREMENT_EQUIPMENT_EXPORT_ALL_TOKEN]);
    } else {
      setMultiSelectSelectedValues(measurementEquipmentExportDevicesInput, nextSelected);
    }
  }

  if (measurementEquipmentExportCategoriesInput) {
    const previousSelected = resetSelection ? [] : getSelectedMultiSelectValues(measurementEquipmentExportCategoriesInput);
    const allCategoriesOption = createOption(
      MEASUREMENT_EQUIPMENT_EXPORT_ALL_TOKEN,
      `ALL · sve vrste (${categoryOptions.length})`,
    );
    const categoryOptionNodes = categoryOptions.map((option) => createOption(String(option.value), option.label));
    measurementEquipmentExportCategoriesInput.replaceChildren(allCategoriesOption, ...categoryOptionNodes);

    const availableValues = new Set(categoryOptions.map((option) => String(option.value)));
    const nextSelected = previousSelected.filter((value) => availableValues.has(value));
    if (nextSelected.length === 0 || previousSelected.includes(MEASUREMENT_EQUIPMENT_EXPORT_ALL_TOKEN)) {
      setMultiSelectSelectedValues(measurementEquipmentExportCategoriesInput, [MEASUREMENT_EQUIPMENT_EXPORT_ALL_TOKEN]);
    } else {
      setMultiSelectSelectedValues(measurementEquipmentExportCategoriesInput, nextSelected);
    }
  }

  if (measurementEquipmentExportCalibrationModeInput) {
    const current = String(measurementEquipmentExportCalibrationModeInput.value || "");
    if (resetSelection || (current !== "all" && current !== "valid")) {
      measurementEquipmentExportCalibrationModeInput.value = "valid";
    }
  }
}

