async function exportMeasurementEquipmentDocumentsZipFromDialog() {
  const items = getMeasurementEquipmentExportItems();
  if (items.length === 0) {
    throw new Error("Nema opreme za ZIP izvoz.");
  }

  const selectedEquipmentIds = resolveMeasurementEquipmentExportDialogDeviceIds(items);
  if (selectedEquipmentIds.length === 0) {
    throw new Error("Nije odabran nijedan uređaj za ZIP izvoz.");
  }

  const categoryOptions = getMeasurementEquipmentZipCategoryOptions();
  if (categoryOptions.length === 0) {
    throw new Error("Nema dostupnih kategorija datoteka za ZIP izvoz.");
  }

  const selectedDocumentCategories = resolveMeasurementEquipmentExportDialogDocumentCategories(categoryOptions);
  if (selectedDocumentCategories.length === 0) {
    throw new Error("Nije odabrana nijedna vrsta datoteke za ZIP izvoz.");
  }

  const onlyValidCalibrationCertificates = String(
    measurementEquipmentExportCalibrationModeInput?.value || "valid",
  ) !== "all";
  const fallbackName = `mjerna-oprema-dokumenti-${new Date().toISOString().slice(0, 10)}.zip`;
  measurementEquipmentBulkExporting = true;
  syncMeasurementEquipmentCardTemplateControls();
  try {
    const response = await apiBinaryRequest("/measurement-equipment/export-files-zip", {
      method: "POST",
      body: {
        equipmentIds: selectedEquipmentIds,
        documentCategories: selectedDocumentCategories,
        onlyValidCalibrationCertificates,
      },
    });
    triggerBlobDownload(response.blob, response.fileName || fallbackName);
    closeMeasurementEquipmentExportDialog();
  } finally {
    measurementEquipmentBulkExporting = false;
    syncMeasurementEquipmentCardTemplateControls();
  }
}

function renderMeasurementEquipmentDocuments() {
  if (!measurementEquipmentDocumentsList) {
    return;
  }

  if (measurementEquipmentDocumentDrafts.length === 0) {
    measurementEquipmentDocumentsList.replaceChildren();
    syncMeasurementEquipmentCardTemplateControls();
    return;
  }

  measurementEquipmentDocumentsList.replaceChildren(...measurementEquipmentDocumentDrafts.map((entry) => {
    const row = document.createElement("article");
    row.className = "module-attachment-row";
    row.classList.toggle("is-unclassified", !entry.documentCategory);

    const copy = document.createElement("div");
    copy.className = "module-attachment-copy";

    const title = document.createElement("strong");
    title.textContent = entry.fileName;

    const meta = document.createElement("span");
    meta.textContent = [
      formatFileSize(entry.fileSize),
      entry.updatedAt ? formatCompactDateTime(entry.updatedAt) : "",
    ].filter(Boolean).join(" | ");

    copy.append(title, meta);

    const categorySlot = document.createElement("div");
    categorySlot.className = "module-attachment-middle";

    if (entry.documentCategoryLocked && entry.documentCategory) {
      const categoryValue = document.createElement("div");
      categoryValue.className = "module-attachment-category-value is-locked";
      categoryValue.textContent = getMeasurementEquipmentDocumentCategoryLabel(entry.documentCategory);
      categoryValue.setAttribute("aria-label", "Vrsta dokumenta");
      categorySlot.append(categoryValue);
    } else {
      const categorySelect = document.createElement("select");
      categorySelect.className = "module-attachment-category-select";
      categorySelect.dataset.documentId = entry.id;
      categorySelect.setAttribute("aria-label", "Vrsta dokumenta");
      replaceSelectOptions(
        categorySelect,
        MEASUREMENT_EQUIPMENT_DOCUMENT_CATEGORY_OPTIONS,
        entry.documentCategory || "",
      );
      categorySelect.addEventListener("change", () => {
        const nextValue = categorySelect.value || "";
        updateMeasurementEquipmentDocumentDraft(entry.id, { documentCategory: nextValue });
        row.classList.toggle("is-unclassified", !nextValue);
        syncMeasurementEquipmentCardTemplateControls();
      });
      categorySlot.append(categorySelect);
    }

    if (entry.description) {
      const description = document.createElement("p");
      description.className = "module-attachment-description";
      description.textContent = entry.description;
      copy.append(description);
    }

    const actions = document.createElement("div");
    actions.className = "module-attachment-actions";

    const previewButton = createIconActionButton("Pregled", "preview", "", () => {
      openMeasurementEquipmentDocumentPreview(entry);
    });
    const openButton = createIconActionButton("Preuzmi", "download", "", () => {
      triggerModuleAttachmentDownload(entry);
    });
    const removeButton = createIconActionButton("Makni", "trash", "card-danger", () => {
      measurementEquipmentDocumentDrafts = measurementEquipmentDocumentDrafts.filter((item) => item.id !== entry.id);
      renderMeasurementEquipmentDocuments();
    });

    actions.append(previewButton, openButton, removeButton);
    row.append(copy, categorySlot, actions);
    return row;
  }));
  syncMeasurementEquipmentCardTemplateControls();
}

async function queueMeasurementEquipmentDocuments(
  files,
  {
    defaultCategory = "",
    defaultDescription = "",
    lockCategory = false,
    focusCategory = true,
  } = {},
) {
  const uploads = await buildWorkOrderDocumentUploadPayload(files);
  const normalizedCategory = String(defaultCategory || "").trim();
  const normalizedDescription = String(defaultDescription || "").trim();
  const nextDocuments = uploads.map((file) => createModuleAttachmentDraft({
    ...file,
    documentCategory: normalizedCategory || file.documentCategory || "",
    description: normalizedDescription || file.description || "",
    documentCategoryLocked: Boolean(lockCategory && normalizedCategory),
  }));
  measurementEquipmentDocumentDrafts = [
    ...measurementEquipmentDocumentDrafts,
    ...nextDocuments,
  ];
  renderMeasurementEquipmentDocuments();
  if (focusCategory) {
    focusMeasurementEquipmentDocumentCategory(nextDocuments[0]?.id || "");
  }
}

