function hydrateMeasurementEquipmentForm(item) {
  if (measurementEquipmentEditorChromeSyncTimer) {
    window.clearTimeout(measurementEquipmentEditorChromeSyncTimer);
    measurementEquipmentEditorChromeSyncTimer = 0;
  }

  state.activeView = "module";
  state.activeModuleItem = "measurement-equipment";
  renderActiveView();
  renderModuleView();
  state.activeMeasurementEquipmentId = item.id;
  measurementEquipmentIdInput.value = item.id || "";
  measurementEquipmentNameInput.value = item.name || "";
  measurementEquipmentKindInput.value = item.equipmentKind || "combined";
  measurementEquipmentManufacturerInput.value = item.manufacturer || "";
  measurementEquipmentTypeInput.value = item.deviceType || "";
  measurementEquipmentDeviceCodeInput.value = item.deviceCode || "";
  measurementEquipmentSerialNumberInput.value = item.serialNumber || "";
  measurementEquipmentInventoryNumberInput.value = item.inventoryNumber || "";
  measurementEquipmentEnteredByInput.value = item.enteredBy || "";
  measurementEquipmentApprovedByInput.value = item.approvedBy || "";
  measurementEquipmentEntryDateInput.value = item.entryDate || "";
  measurementEquipmentRequiresCalibrationInput.value = item.requiresCalibration ? "true" : "false";
  measurementEquipmentCalibrationDateInput.value = item.calibrationDate || "";
  measurementEquipmentCalibrationPeriodInput.value = item.calibrationPeriod || "";
  measurementEquipmentValidUntilInput.value = item.validUntil || "";
  measurementEquipmentNoteInput.value = item.note || "";
  if (measurementEquipmentError) {
    measurementEquipmentError.textContent = "";
  }
  resetMeasurementEquipmentSideActivityControls();
  setMeasurementEquipmentDocumentDrafts(item.documents ?? []);
  setMeasurementEquipmentActivityDrafts(item.activityItems ?? []);
  setMeasurementEquipmentSpecDrafts(item.measurementSpecs ?? []);
  renderMeasurementEquipmentDocuments();
  renderMeasurementEquipmentActivities();
  renderMeasurementEquipmentSpecs();
  renderMeasurementEquipmentTemplateChecklist(item.linkedTemplateIds ?? []);
  state.measurementEquipmentTemplateSectionExpanded = false;
  state.measurementEquipmentActivitySectionExpanded = (item.activityItems ?? []).length > 0;
  state.measurementEquipmentDocumentsSectionExpanded = false;
  syncMeasurementEquipmentCalibrationFields();
  syncMeasurementEquipmentEditorSections();
  syncMeasurementEquipmentEditorChrome();
  openMeasurementEquipmentEditor();
  renderMeasurementEquipmentSideActivityPanel();
  void ensureMeasurementEquipmentActivityFeedLoaded();
  requestAnimationFrame(() => {
    measurementEquipmentNameInput?.focus({ preventScroll: true });
  });
}

function getMeasurementEquipmentComparableLabel(item) {
  return `${item?.name || ""} ${item?.deviceCode || ""} ${item?.serialNumber || ""} ${item?.inventoryNumber || ""}`.trim();
}

function compareMeasurementEquipmentByName(left, right, { direction = "asc" } = {}) {
  const result = getMeasurementEquipmentComparableLabel(left).localeCompare(
    getMeasurementEquipmentComparableLabel(right),
    "hr",
    { sensitivity: "base", numeric: true },
  );
  return direction === "desc" ? result * -1 : result;
}

function compareMeasurementEquipmentByDueDate(left, right, { direction = "asc" } = {}) {
  const leftDueDate = String(left?.validUntil || "");
  const rightDueDate = String(right?.validUntil || "");

  if (leftDueDate && rightDueDate && leftDueDate !== rightDueDate) {
    const result = leftDueDate.localeCompare(rightDueDate);
    return direction === "desc" ? result * -1 : result;
  }

  if (leftDueDate && !rightDueDate) {
    return -1;
  }

  if (!leftDueDate && rightDueDate) {
    return 1;
  }

  return compareMeasurementEquipmentByName(left, right, { direction: "asc" });
}

function sortMeasurementEquipmentItemsForList(items, mode = "due-asc") {
  const sorted = [...(items ?? [])];

  if (mode === "name-asc") {
    return sorted.sort((left, right) => compareMeasurementEquipmentByName(left, right, { direction: "asc" }));
  }

  if (mode === "name-desc") {
    return sorted.sort((left, right) => compareMeasurementEquipmentByName(left, right, { direction: "desc" }));
  }

  if (mode === "due-desc") {
    return sorted.sort((left, right) => {
      const dueComparison = compareMeasurementEquipmentByDueDate(left, right, { direction: "desc" });
      if (dueComparison !== 0) {
        return dueComparison;
      }
      return compareMeasurementEquipmentByName(left, right, { direction: "desc" });
    });
  }

  return sorted.sort((left, right) => {
    const dueComparison = compareMeasurementEquipmentByDueDate(left, right, { direction: "asc" });
    if (dueComparison !== 0) {
      return dueComparison;
    }
    return compareMeasurementEquipmentByName(left, right, { direction: "asc" });
  });
}

function renderMeasurementEquipmentModule() {
  if (!measurementEquipmentModule || !measurementEquipmentList || !measurementEquipmentEmpty) {
    return;
  }

  const canManageMasterData = getCanManageMasterData();
  const filters = {
    query: measurementEquipmentSearchInput?.value?.trim() || state.measurementEquipmentFilters.query || "",
    sort: measurementEquipmentSortInput?.value || state.measurementEquipmentFilters.sort || "due-asc",
  };
  state.measurementEquipmentFilters = filters;

  const allItems = [...(state.measurementEquipment ?? [])];
  const visibleItems = sortMeasurementEquipmentItemsForList(
    filterMeasurementEquipmentItems(state.measurementEquipment ?? [], { query: filters.query }),
    filters.sort,
  );

  if (measurementEquipmentOpenFormButton) {
    measurementEquipmentOpenFormButton.hidden = !canManageMasterData;
  }
  if (measurementEquipmentDeleteButton) {
    measurementEquipmentDeleteButton.hidden = !measurementEquipmentIdInput?.value || !canManageMasterData;
  }
  if (measurementEquipmentTotalCount) {
    measurementEquipmentTotalCount.textContent = String(allItems.length);
  }
  if (measurementEquipmentCalibrationCount) {
    measurementEquipmentCalibrationCount.textContent = String(allItems.filter((item) => item.requiresCalibration).length);
  }
  if (measurementEquipmentExpiringCount) {
    measurementEquipmentExpiringCount.textContent = String(allItems.filter((item) => isUpcomingIsoDate(item.validUntil)).length);
  }
  if (measurementEquipmentFilesCount) {
    measurementEquipmentFilesCount.textContent = String(allItems.filter((item) => (item.documents ?? []).length > 0).length);
  }
  if (measurementEquipmentHelper) {
    measurementEquipmentHelper.textContent = visibleItems.length === allItems.length
      ? `Prikazano ${visibleItems.length} stavki opreme.`
      : `Prikazano ${visibleItems.length} od ${allItems.length} stavki opreme.`;
  }
  const hasCardTemplateDocument = Boolean(getMeasurementEquipmentCardTemplateDocument());

  measurementEquipmentList.replaceChildren(...visibleItems.map((item) => {
    const card = document.createElement("article");
    card.className = `measurement-equipment-card is-${slugifyValue(item.equipmentKind || "measurement")}`;
    card.classList.add("measurement-equipment-card--emphasized");
    if (String(item.id) === String(measurementEquipmentIdInput?.value || "")) {
      card.classList.add("is-active");
    }

    if (canManageMasterData) {
      card.tabIndex = 0;
      card.setAttribute("role", "button");
    }

    const head = document.createElement("div");
    head.className = "measurement-equipment-card-head";

    const copy = document.createElement("div");
    copy.className = "measurement-equipment-card-copy";
    const title = document.createElement("h4");
    title.textContent = item.name || "Bez naziva";
    const meta = document.createElement("p");
    meta.className = "measurement-equipment-card-meta";
    meta.textContent = [
      item.manufacturer || "",
      item.deviceType || "",
      item.deviceCode ? `Ozn. ${item.deviceCode}` : "",
      item.serialNumber ? `Ser. ${item.serialNumber}` : "",
      item.inventoryNumber ? `Inv. ${item.inventoryNumber}` : "",
    ].filter(Boolean).join(" | ") || "Bez dodatnih podataka";
    copy.append(title, meta);

    const badges = document.createElement("div");
    badges.className = "measurement-equipment-card-badges";
    badges.append(
      createBadge(item.requiresCalibration ? "Umjerava se" : "Ne umjerava se", item.requiresCalibration ? "document-template-status-badge is-active" : "document-template-status-badge is-archived"),
    );
    if (canManageMasterData) {
      const actions = document.createElement("div");
      actions.className = "measurement-equipment-card-actions";

      const exportWordButton = document.createElement("button");
      exportWordButton.type = "button";
      exportWordButton.className = "ghost-button measurement-equipment-card-action-button";
      exportWordButton.title = "Preuzmi karton (Word)";
      exportWordButton.setAttribute("aria-label", `Preuzmi Word karton za ${item.name || "uređaj"}`);
      exportWordButton.disabled = !hasCardTemplateDocument || measurementEquipmentCardExporting;
      exportWordButton.innerHTML = `
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
          <path d="M14 2H7a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7z" />
          <path d="M14 2v5h5" />
          <path d="M8 13l1.4 4L11 13l1.6 4L14 13" />
        </svg>
      `;

      const exportPdfButton = document.createElement("button");
      exportPdfButton.type = "button";
      exportPdfButton.className = "ghost-button measurement-equipment-card-action-button";
      exportPdfButton.title = "Preuzmi karton (PDF)";
      exportPdfButton.setAttribute("aria-label", `Preuzmi PDF karton za ${item.name || "uređaj"}`);
      exportPdfButton.disabled = !hasCardTemplateDocument || measurementEquipmentCardExporting;
      exportPdfButton.innerHTML = `
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
          <path d="M14 2H7a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7z" />
          <path d="M14 2v5h5" />
          <path d="M8 17h8" />
          <path d="M8 13h8" />
        </svg>
      `;

      exportWordButton.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        void runMutation(() => exportMeasurementEquipmentCardDocumentForItem(item, "word"), measurementEquipmentError);
      });
      exportPdfButton.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        void runMutation(() => exportMeasurementEquipmentCardDocumentForItem(item, "pdf"), measurementEquipmentError);
      });

      actions.append(exportWordButton, exportPdfButton);
      badges.append(actions);
    }
    head.append(copy, badges);

    const footer = document.createElement("div");
    footer.className = "measurement-equipment-card-groups";

    const calibrationGroup = document.createElement("section");
    calibrationGroup.className = "measurement-equipment-card-group";
    const calibrationLabel = document.createElement("p");
    calibrationLabel.className = "measurement-equipment-card-group-label";
    calibrationLabel.textContent = "Umjernica";
    const dates = document.createElement("div");
    dates.className = "measurement-equipment-card-chips";
    if (item.requiresCalibration) {
      dates.append(
        createBadge(
          item.validUntil ? `Vrijedi do ${formatCompactDate(item.validUntil)}` : "Vrijedi do: bez roka",
          item.validUntil && isUpcomingIsoDate(item.validUntil) ? "measurement-equipment-chip is-warning" : "measurement-equipment-chip",
        ),
      );
    } else {
      dates.append(createBadge("Nije potrebno umjeravanje", "measurement-equipment-chip"));
    }
    calibrationGroup.append(calibrationLabel, dates);

    const templatesGroup = document.createElement("section");
    templatesGroup.className = "measurement-equipment-card-group";
    const templatesLabel = document.createElement("p");
    templatesLabel.className = "measurement-equipment-card-group-label";
    templatesLabel.textContent = "Koristi se u zapisnicima";
    const templates = document.createElement("div");
    templates.className = "measurement-equipment-card-chips";
    if ((item.linkedTemplateTitles ?? []).length > 0) {
      (item.linkedTemplateTitles ?? []).slice(0, 4).forEach((entry) => {
        templates.append(createBadge(entry, "service-catalog-template-badge"));
      });
    } else {
      templates.append(createBadge("Bez zapisnika", "service-catalog-template-badge is-muted"));
    }
    templatesGroup.append(templatesLabel, templates);

    footer.append(calibrationGroup, templatesGroup);
    card.append(head, footer);

    const openItem = () => {
      if (!canManageMasterData) {
        return;
      }
      hydrateMeasurementEquipmentForm(item);
    };

    if (canManageMasterData) {
      card.addEventListener("click", openItem);
      card.addEventListener("keydown", (event) => {
        if (event.key !== "Enter" && event.key !== " ") {
          return;
        }
        event.preventDefault();
        openItem();
      });
    }

    return card;
  }));

  measurementEquipmentEmpty.hidden = visibleItems.length !== 0;
  if (visibleItems.length === 0) {
    const empty = document.createElement("div");
    empty.className = "offers-empty-card";
    empty.textContent = canManageMasterData
      ? "Nema opreme za ove filtere. Dodaj prvu stavku opreme i povezi je sa zapisnicima."
      : "Nema opreme za prikaz u odabranoj organizaciji.";
    measurementEquipmentList.replaceChildren(empty);
  }

  syncMeasurementEquipmentCardTemplateControls();
  if (state.measurementEquipmentExportDialogOpen) {
    syncMeasurementEquipmentExportDialogModal();
  }
}

function getSafetyAuthorizationTemplateSelectionIds() {
  return getCheckedValues(safetyAuthorizationTemplateList, "safety-authorization-template-id");
}

function isSafetyAuthorizationDocumentFileAllowed(file) {
  return isLegalFrameworkDocumentFileAllowed(file);
}

function setSafetyAuthorizationDocumentDrafts(items = []) {
  safetyAuthorizationDocumentDrafts = (Array.isArray(items) ? items : [])
    .map((item) => createModuleAttachmentDraft({
      ...item,
      documentCategory: item?.documentCategory || "pdf",
    }))
    .filter((item) => item.fileName && (item.dataUrl || item.storageUrl));
}

function createSafetyAuthorizationCardDocumentActions(item = {}) {
  const documents = (Array.isArray(item.documents) ? item.documents : [])
    .map((entry) => createModuleAttachmentDraft(entry))
    .filter((entry) => entry.fileName && (entry.dataUrl || entry.storageUrl));

  if (documents.length === 0) {
    return null;
  }

  const actions = document.createElement("div");
  actions.className = "safety-authorization-card-actions";

  documents.slice(0, 3).forEach((entry) => {
    const downloadButton = createIconActionButton(
      `Preuzmi ${entry.fileName || "PDF dokument"}`,
      "download",
      "",
      (event) => {
        event.preventDefault();
        event.stopPropagation();
        triggerModuleAttachmentDownload(entry);
      },
    );
    downloadButton.classList.add("safety-authorization-card-download-button");
    actions.append(downloadButton);
  });

  if (documents.length > 3) {
    actions.append(createBadge(`+${documents.length - 3}`, "legal-framework-meta-badge"));
  }

  return actions;
}

function renderSafetyAuthorizationDocuments() {
  if (!safetyAuthorizationDocumentsList) {
    return;
  }

  if (safetyAuthorizationDocumentDrafts.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy module-copy";
    empty.textContent = "Jos nema dodanih PDF dokumenata za ovo ovlastenje.";
    safetyAuthorizationDocumentsList.replaceChildren(empty);
    return;
  }

  safetyAuthorizationDocumentsList.replaceChildren(...safetyAuthorizationDocumentDrafts.map((entry) => {
    const row = document.createElement("article");
    row.className = "module-attachment-row legal-framework-document-row";

    const copy = document.createElement("div");
    copy.className = "module-attachment-copy";

    const title = document.createElement("strong");
    title.textContent = entry.fileName || "PDF dokument";

    const meta = document.createElement("span");
    meta.textContent = [
      "PDF",
      formatFileSize(entry.fileSize),
      entry.updatedAt ? formatCompactDateTime(entry.updatedAt) : "",
    ].filter(Boolean).join(" | ");

    copy.append(title, meta);

    if (entry.description) {
      const description = document.createElement("p");
      description.className = "module-attachment-description";
      description.textContent = entry.description;
      copy.append(description);
    }

    const actions = document.createElement("div");
    actions.className = "module-attachment-actions";
    actions.append(
      createIconActionButton("Preuzmi PDF", "download", "", () => {
        triggerModuleAttachmentDownload(entry);
      }),
      createIconActionButton("Makni PDF", "trash", "card-danger", () => {
        safetyAuthorizationDocumentDrafts = safetyAuthorizationDocumentDrafts.filter((item) => String(item.id) !== String(entry.id));
        renderSafetyAuthorizationDocuments();
      }),
    );

    row.append(copy, actions);
    return row;
  }));
}

async function queueSafetyAuthorizationDocuments(files) {
  const uploadFiles = Array.from(files ?? []).filter((file) => file instanceof File);

  if (!uploadFiles.length) {
    return;
  }

  for (const file of uploadFiles) {
    if (!isSafetyAuthorizationDocumentFileAllowed(file)) {
      throw new Error(`Format ${file.name} nije podrzan. Dozvoljen je samo PDF.`);
    }

    if (file.size > WORK_ORDER_DOCUMENT_MAX_SIZE_BYTES) {
      throw new Error(`Datoteka ${file.name} mora biti manja od 12 MB.`);
    }
  }

  const nextDocuments = await Promise.all(uploadFiles.map(async (file) => createModuleAttachmentDraft({
    fileName: file.name,
    fileType: file.type || "application/pdf",
    fileSize: file.size || 0,
    documentCategory: "pdf",
    dataUrl: await readFileAsDataUrl(file, `Ne mogu ucitati datoteku ${file.name}.`),
    updatedAt: new Date().toISOString(),
  })));

  safetyAuthorizationDocumentDrafts = [
    ...safetyAuthorizationDocumentDrafts,
    ...nextDocuments,
  ];
  renderSafetyAuthorizationDocuments();
}

function syncSafetyAuthorizationValidityInput() {
  syncQualificationValidityInput(safetyAuthorizationValidUntilInput, safetyAuthorizationValidForeverInput);

  if (safetyAuthorizationValidForeverInput?.checked && safetyAuthorizationValidUntilInput) {
    safetyAuthorizationValidUntilInput.value = "";
  }
}

function renderSafetyAuthorizationTemplateChecklist(selectedIds = []) {
  renderTemplateSelectionChecklist(safetyAuthorizationTemplateList, {
    selectedIds,
    inputName: "safety-authorization-template-id",
    emptyText: "Prvo dodaj zapisnike u Template Development pa ih ovdje poveži s ovlaštenjem.",
  });
}

function buildSafetyAuthorizationPayload() {
  return {
    organizationId: state.activeOrganizationId || "",
    title: safetyAuthorizationTitleInput?.value || "",
    scope: safetyAuthorizationScopeInput?.value || "",
    issuedOn: safetyAuthorizationIssuedOnInput?.value || "",
    validUntil: safetyAuthorizationValidForeverInput?.checked ? "" : (safetyAuthorizationValidUntilInput?.value || ""),
    validForever: Boolean(safetyAuthorizationValidForeverInput?.checked),
    linkedTemplateIds: getSafetyAuthorizationTemplateSelectionIds(),
    documents: safetyAuthorizationDocumentDrafts.map((entry) => ({ ...entry })),
    note: safetyAuthorizationNoteInput?.value || "",
  };
}

function syncSafetyAuthorizationEditorChrome() {
  if (safetyAuthorizationEditorTitle) {
    safetyAuthorizationEditorTitle.textContent = safetyAuthorizationIdInput?.value
      ? `Uredi ovlaštenje | ${safetyAuthorizationTitleInput?.value?.trim() || "Bez naziva"}`
      : "Novo ovlaštenje";
  }

  if (safetyAuthorizationDeleteButton) {
    safetyAuthorizationDeleteButton.hidden = !safetyAuthorizationIdInput?.value;
  }
}

function resetSafetyAuthorizationForm() {
  if (!safetyAuthorizationForm) {
    return;
  }

  safetyAuthorizationForm.reset();
  state.activeSafetyAuthorizationId = "";
  if (safetyAuthorizationIdInput) {
    safetyAuthorizationIdInput.value = "";
  }
  if (safetyAuthorizationError) {
    safetyAuthorizationError.textContent = "";
  }
  if (safetyAuthorizationValidForeverInput) {
    safetyAuthorizationValidForeverInput.checked = false;
  }
  setSafetyAuthorizationDocumentDrafts([]);
  renderSafetyAuthorizationDocuments();
  syncSafetyAuthorizationValidityInput();
  renderSafetyAuthorizationTemplateChecklist([]);
  syncSafetyAuthorizationEditorChrome();
}

function hydrateSafetyAuthorizationForm(item) {
  state.activeView = "module";
  state.activeModuleItem = "safety-authorization";
  renderActiveView();
  renderModuleView();
  state.activeSafetyAuthorizationId = item.id;
  safetyAuthorizationIdInput.value = item.id || "";
  safetyAuthorizationTitleInput.value = item.title || "";
  safetyAuthorizationScopeInput.value = item.scope || "";
  safetyAuthorizationIssuedOnInput.value = item.issuedOn || "";
  safetyAuthorizationValidUntilInput.value = item.validUntil || "";
  if (safetyAuthorizationValidForeverInput) {
    safetyAuthorizationValidForeverInput.checked = Boolean(item.validForever);
  }
  safetyAuthorizationNoteInput.value = item.note || "";
  if (safetyAuthorizationError) {
    safetyAuthorizationError.textContent = "";
  }
  setSafetyAuthorizationDocumentDrafts(item.documents ?? []);
  renderSafetyAuthorizationDocuments();
  syncSafetyAuthorizationValidityInput();
  renderSafetyAuthorizationTemplateChecklist(item.linkedTemplateIds ?? []);
  syncSafetyAuthorizationEditorChrome();
  openSafetyAuthorizationEditor();
  requestAnimationFrame(() => {
    safetyAuthorizationTitleInput?.focus({ preventScroll: true });
  });
}

function renderSafetyAuthorizationModule() {
  if (!safetyAuthorizationModule || !safetyAuthorizationList || !safetyAuthorizationEmpty) {
    return;
  }

  const canManageMasterData = getCanManageMasterData();
  const filters = {
    query: safetyAuthorizationSearchInput?.value?.trim() || state.safetyAuthorizationFilters.query || "",
  };
  state.safetyAuthorizationFilters = filters;

  const allItems = sortSafetyAuthorizations(state.safetyAuthorizations ?? []);
  const visibleItems = sortSafetyAuthorizations(filterSafetyAuthorizations(state.safetyAuthorizations ?? [], filters));
  const today = new Date(new Date().setHours(0, 0, 0, 0));
  const activeItems = allItems.filter((item) => (
    item.validForever
    || !item.validUntil
    || !parseDateValue(item.validUntil)
    || parseDateValue(item.validUntil) >= today
  ));

  if (safetyAuthorizationOpenFormButton) {
    safetyAuthorizationOpenFormButton.hidden = !canManageMasterData;
  }
  if (safetyAuthorizationDeleteButton) {
    safetyAuthorizationDeleteButton.hidden = !safetyAuthorizationIdInput?.value || !canManageMasterData;
  }
  if (safetyAuthorizationTotalCount) {
    safetyAuthorizationTotalCount.textContent = String(allItems.length);
  }
  if (safetyAuthorizationActiveCount) {
    safetyAuthorizationActiveCount.textContent = String(activeItems.length);
  }
  if (safetyAuthorizationExpiringCount) {
    safetyAuthorizationExpiringCount.textContent = String(allItems.filter((item) => isUpcomingIsoDate(item.validUntil)).length);
  }
  if (safetyAuthorizationHelper) {
    safetyAuthorizationHelper.textContent = visibleItems.length === allItems.length
      ? `Prikazano ${visibleItems.length} ovlaštenja. Ovdje ih povezuješ sa zapisnicima.`
      : `Prikazano ${visibleItems.length} od ${allItems.length} ovlaštenja.`;
  }

  safetyAuthorizationList.replaceChildren(...visibleItems.map((item) => {
    const card = document.createElement("article");
    card.className = "safety-authorization-card";
    if (String(item.id) === String(safetyAuthorizationIdInput?.value || "")) {
      card.classList.add("is-active");
    }

    if (canManageMasterData) {
      card.tabIndex = 0;
      card.setAttribute("role", "button");
    }

    const head = document.createElement("div");
    head.className = "safety-authorization-card-head";

    const copy = document.createElement("div");
    copy.className = "safety-authorization-card-copy";
    const title = document.createElement("h4");
    title.textContent = item.title || "Bez naziva";
    const meta = document.createElement("p");
    meta.className = "safety-authorization-card-meta";
    meta.textContent = item.scope || "Bez definiranog opsega";
    copy.append(title, meta);

    const dates = document.createElement("div");
    dates.className = "safety-authorization-card-chips";
    if (item.issuedOn) {
      dates.append(createBadge(`Izdano ${formatCompactDate(item.issuedOn)}`, "measurement-equipment-chip"));
    }
    const validityLabel = item.validForever
      ? "Vrijedi trajno"
      : item.validUntil
        ? `Vrijedi do ${formatCompactDate(item.validUntil)}`
        : "Bez roka";
    dates.append(createBadge(
      validityLabel,
      !item.validForever && isUpcomingIsoDate(item.validUntil)
        ? "measurement-equipment-chip is-warning"
        : "measurement-equipment-chip",
    ));
    head.append(copy, dates);

    const templates = document.createElement("div");
    templates.className = "safety-authorization-card-chips";
    if ((item.linkedTemplateTitles ?? []).length > 0) {
      (item.linkedTemplateTitles ?? []).slice(0, 4).forEach((entry) => {
        templates.append(createBadge(entry, "service-catalog-template-badge"));
      });
    } else {
      templates.append(createBadge("Bez zapisnika", "service-catalog-template-badge is-muted"));
    }

    const note = document.createElement("p");
    note.className = "safety-authorization-card-note";
    note.textContent = item.note || "Bez dodatne napomene.";

    const footer = document.createElement("div");
    footer.className = "safety-authorization-card-footer";

    const documentInfo = document.createElement("div");
    documentInfo.className = "safety-authorization-card-chips";
    const documentCount = Array.isArray(item.documents) ? item.documents.length : 0;
    documentInfo.append(createBadge(
      documentCount > 0
        ? `${documentCount} PDF`
        : "Bez PDF-a",
      documentCount > 0
        ? "service-catalog-template-badge"
        : "service-catalog-template-badge is-muted",
    ));

    const documentActions = createSafetyAuthorizationCardDocumentActions(item);
    footer.append(documentInfo);
    if (documentActions) {
      footer.append(documentActions);
    }

    card.append(head, templates, note, footer);

    const openItem = () => {
      if (!canManageMasterData) {
        return;
      }
      hydrateSafetyAuthorizationForm(item);
    };

    if (canManageMasterData) {
      card.addEventListener("click", openItem);
      card.addEventListener("keydown", (event) => {
        if (event.key !== "Enter" && event.key !== " ") {
          return;
        }
        event.preventDefault();
        openItem();
      });
    }

    return card;
  }));

  safetyAuthorizationEmpty.hidden = visibleItems.length !== 0;
  if (visibleItems.length === 0) {
    const empty = document.createElement("div");
    empty.className = "offers-empty-card";
    empty.textContent = canManageMasterData
      ? "Nema ovlaštenja za ove filtere. Dodaj prvo ovlaštenje i poveži ga sa zapisnicima."
      : "Nema ovlaštenja za prikaz u odabranoj organizaciji.";
    safetyAuthorizationList.replaceChildren(empty);
  }
}

function getCurrentAbsenceModuleMode() {
  const activePeopleTab = normalizePeopleWorkspaceTab(state.peopleWorkspaceTab);
  if (activePeopleTab === "sick-leave") {
    return "medical";
  }
  if (activePeopleTab === "annual-leave") {
    return "request";
  }
  return state.activeModuleItem === "sick-leave" ? "medical" : "request";
}

function getAbsenceModuleConfig() {
  if (getCurrentAbsenceModuleMode() === "medical") {
    return {
      kicker: "Medical",
      title: "Bolovanja i posebni dopusti",
      copy: "Evidencija bolovanja, porodiljnih, roditeljskih i drugih opravdanih izostanaka uz dokumentaciju.",
      createLabel: "+ Nova odsutnost",
      balanceLabel: "Bolovanje saldo",
      typeOptions: ABSENCE_MEDICAL_TYPE_OPTIONS,
    };
  }

  return {
    kicker: "Requests",
    title: "Godišnji odmori i dopusti",
    copy: "Zahtjevi za godišnji, plaćene i druge dopuste s admin odobrenjima i pregledom stanja dana.",
    createLabel: "+ Novi zahtjev",
    balanceLabel: "GO saldo",
    typeOptions: ABSENCE_REQUEST_TYPE_OPTIONS,
  };
}

function getAbsenceFiltersStateForCurrentMode() {
  return getCurrentAbsenceModuleMode() === "medical"
    ? state.sickLeaveFilters
    : state.annualLeaveFilters;
}

function updateAbsenceFiltersStateForCurrentMode(patch = {}) {
  if (getCurrentAbsenceModuleMode() === "medical") {
    state.sickLeaveFilters = {
      ...state.sickLeaveFilters,
      ...patch,
    };
    return;
  }

  state.annualLeaveFilters = {
    ...state.annualLeaveFilters,
    ...patch,
  };
}

function getAbsenceEntriesForCurrentMode() {
  const allowedTypes = new Set(getAbsenceModuleConfig().typeOptions.map((option) => option.value));
  return (state.absenceEntries ?? []).filter((entry) => allowedTypes.has(String(entry.type || "").trim().toLowerCase()));
}

function canManageAbsenceEntryClient(entry = {}) {
  if (getCanManageMasterData()) {
    return true;
  }

  const actorId = String(state.user?.id ?? "");
  return Boolean(actorId) && (
    String(entry.userId ?? "") === actorId
    || String(entry.requestedByUserId ?? "") === actorId
  );
}

function getAbsenceBalanceSummaryForUser(userId = "") {
  return buildAbsenceBalanceSummaries(state.absenceBalances ?? [], state.absenceEntries ?? [], { userIds: [userId] })[0] ?? {
    userId: String(userId || ""),
    userLabel: "",
    annualLeaveInitialDays: 0,
    annualLeaveUsedDays: 0,
    annualLeaveRemainingDays: 0,
    sickLeaveInitialDays: 0,
    sickLeaveUsedDays: 0,
    sickLeaveRemainingDays: 0,
  };
}

function getAbsenceTypeLabelClient(type = "") {
  return ABSENCE_TYPE_LABELS.get(String(type || "").trim().toLowerCase()) || "Izostanak";
}

function getAbsenceStatusLabelClient(status = "") {
  return ABSENCE_STATUS_LABELS.get(String(status || "").trim().toLowerCase()) || "Na čekanju";
}

function getAbsenceStatusBadgeClass(status = "") {
  const normalized = String(status || "").trim().toLowerCase();
  if (normalized === "approved") {
    return "document-template-status-badge is-active";
  }
  if (normalized === "rejected" || normalized === "cancelled") {
    return "document-template-status-badge is-archived";
  }
  return "document-template-status-badge";
}

function getApprovedAbsenceEntries(source = state.absenceEntries ?? []) {
  return (source ?? []).filter((entry) => String(entry?.status || "").trim().toLowerCase() === "approved");
}

function isAbsenceEntryActiveOnDate(entry = {}, dateKey = "") {
  const safeDateKey = String(dateKey || "").trim();
  if (!safeDateKey) {
    return false;
  }

  const startDate = String(entry?.startDate || "").trim();
  const endDate = String(entry?.endDate || startDate).trim();
  return Boolean(startDate) && safeDateKey >= startDate && safeDateKey <= endDate;
}

function getAbsenceEntriesForDate(dateKey = "", { approvedOnly = true } = {}) {
  const source = approvedOnly ? getApprovedAbsenceEntries() : (state.absenceEntries ?? []);
  return source.filter((entry) => isAbsenceEntryActiveOnDate(entry, dateKey));
}

function getExecutorAbsenceEntriesForWorkOrder(workOrder = {}, dateKey = "") {
  const matchedUserIds = new Set(
    getWorkOrderExecutors(workOrder)
      .map((executor) => findUserForExecutor(executor)?.id)
      .map((value) => String(value || "").trim())
      .filter(Boolean),
  );

  if (matchedUserIds.size === 0) {
    return [];
  }

  return getAbsenceEntriesForDate(dateKey, { approvedOnly: true })
    .filter((entry) => matchedUserIds.has(String(entry.userId || "").trim()));
}

function createAbsenceCalendarBadge(entry = {}, {
  compact = false,
  showUserLabel = true,
  showDateRange = false,
} = {}) {
  const typeKey = String(entry.type || "").trim().toLowerCase();
  const tone = ABSENCE_CALENDAR_BADGE_TONES[typeKey] || "is-other";
  const parts = [];

  if (showUserLabel && entry.userLabel) {
    parts.push(entry.userLabel);
  }
  parts.push(getAbsenceTypeLabelClient(typeKey));
  if (showDateRange && entry.startDate) {
    parts.push(
      entry.endDate && entry.endDate !== entry.startDate
        ? `${formatCompactDate(entry.startDate)} - ${formatCompactDate(entry.endDate)}`
        : formatCompactDate(entry.startDate),
    );
  }

  const badge = document.createElement("span");
  badge.className = `work-order-calendar-absence-badge ${tone}${compact ? " is-compact" : ""}`;
  badge.textContent = parts.filter(Boolean).join(" · ") || "Odsutnost";
  badge.title = [
    entry.userLabel || "",
    getAbsenceTypeLabelClient(typeKey),
    entry.startDate
      ? (entry.endDate && entry.endDate !== entry.startDate
        ? `${formatCompactDate(entry.startDate)} - ${formatCompactDate(entry.endDate)}`
        : formatCompactDate(entry.startDate))
      : "",
  ].filter(Boolean).join(" · ");
  return badge;
}

function setAbsenceDocumentDrafts(items = []) {
  absenceDocumentDrafts = (Array.isArray(items) ? items : [])
    .map((item) => createModuleAttachmentDraft(item))
    .filter((entry) => entry.fileName && (entry.dataUrl || entry.storageUrl));
}

function renderAbsenceDocuments() {
  if (!absenceDocumentsList) {
    return;
  }

  if (absenceDocumentDrafts.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy module-copy";
    empty.textContent = "Još nema dodanih dokumenata.";
    absenceDocumentsList.replaceChildren(empty);
    return;
  }

  absenceDocumentsList.replaceChildren(...absenceDocumentDrafts.map((entry) => {
    const row = document.createElement("article");
    row.className = "module-attachment-row";

    const copy = document.createElement("div");
    copy.className = "module-attachment-copy";

    const title = document.createElement("strong");
    title.textContent = entry.fileName || "Dokument";

    const meta = document.createElement("span");
    meta.textContent = [
      entry.fileType || "Dokument",
      formatFileSize(entry.fileSize),
      entry.updatedAt ? formatCompactDateTime(entry.updatedAt) : "",
    ].filter(Boolean).join(" | ");

    copy.append(title, meta);

    const actions = document.createElement("div");
    actions.className = "module-attachment-actions";
    actions.append(
      createIconActionButton("Preuzmi dokument", "download", "", () => {
        triggerModuleAttachmentDownload(entry);
      }),
      createIconActionButton("Makni dokument", "trash", "card-danger", () => {
        absenceDocumentDrafts = absenceDocumentDrafts.filter((item) => String(item.id) !== String(entry.id));
        renderAbsenceDocuments();
      }),
    );

    row.append(copy, actions);
    return row;
  }));
}

async function queueAbsenceDocuments(files) {
  const uploads = Array.from(files ?? []).filter((file) => file instanceof File);

  if (uploads.length === 0) {
    return;
  }

  for (const file of uploads) {
    if (!isWorkOrderDocumentFileAllowed(file)) {
      throw new Error(`Format ${file.name} nije podržan. Dozvoljeno: ${WORK_ORDER_DOCUMENT_ACCEPT_LABEL}`);
    }
    if (file.size > WORK_ORDER_DOCUMENT_MAX_SIZE_BYTES) {
      throw new Error(`Datoteka ${file.name} mora biti manja od 12 MB.`);
    }
  }

  const nextDocuments = await Promise.all(uploads.map(async (file) => createModuleAttachmentDraft({
    fileName: file.name,
    fileType: file.type || "application/octet-stream",
    fileSize: file.size || 0,
    dataUrl: await readFileAsDataUrl(file, `Ne mogu učitati datoteku ${file.name}.`),
    updatedAt: new Date().toISOString(),
  })));

  absenceDocumentDrafts = [
    ...absenceDocumentDrafts,
    ...nextDocuments,
  ];
  renderAbsenceDocuments();
}

function renderAbsenceUserSelectOptions(selectedValue = "") {
  const options = [
    { value: "", label: "Odaberi korisnika" },
    ...state.users
      .filter((user) => user?.isActive !== false)
      .slice()
      .sort((left, right) => getUserDisplayLabel(left).localeCompare(getUserDisplayLabel(right), "hr"))
      .map((user) => ({
        value: String(user.id),
        label: getUserDisplayLabel(user),
      })),
  ];
  replaceSelectOptions(absenceUserIdInput, options, selectedValue || "");
}

function renderAbsenceFilterOptions() {
  const config = getAbsenceModuleConfig();
  const filters = getAbsenceFiltersStateForCurrentMode();
  const typeOptions = [
    { value: "all", label: "Sve vrste" },
    ...config.typeOptions.map((option) => ({ value: option.value, label: option.label })),
  ];
  const statusOptions = [
    { value: "all", label: "Svi statusi" },
    ...ABSENCE_STATUS_OPTIONS.map((option) => ({ value: option.value, label: option.label })),
  ];
  const userOptions = [
    { value: "all", label: "Svi korisnici" },
    ...state.users
      .filter((user) => user?.isActive !== false)
      .slice()
      .sort((left, right) => getUserDisplayLabel(left).localeCompare(getUserDisplayLabel(right), "hr"))
      .map((user) => ({
        value: String(user.id),
        label: getUserDisplayLabel(user),
      })),
  ];

  replaceSelectOptions(absenceTypeFilterInput, typeOptions, filters.type || "all");
  replaceSelectOptions(absenceStatusFilterInput, statusOptions, filters.status || "all");
  replaceSelectOptions(absenceUserFilterInput, userOptions, filters.userId || "all");
}

function syncAbsenceDayCountPreview() {
  if (!absenceDayCountPreview) {
    return;
  }

  const startDate = absenceStartDateInput?.value || "";
  const endDate = absenceEndDateInput?.value || startDate;
  const dayCount = startDate ? getAbsenceBusinessDayCount(startDate, endDate) : 0;
  absenceDayCountPreview.textContent = startDate
    ? `${dayCount} radnih dana`
    : "Odaberi datume";
}

function syncAbsenceBalancePreview() {
  if (!absenceBalancePreview) {
    return;
  }

  const selectedUserId = String(absenceUserIdInput?.value || state.user?.id || "").trim();
  if (!selectedUserId) {
    absenceBalancePreview.textContent = "Saldo će se prikazati nakon odabira korisnika.";
    return;
  }

  const summary = getAbsenceBalanceSummaryForUser(selectedUserId);
  if (getCurrentAbsenceModuleMode() === "medical") {
    absenceBalancePreview.textContent = `Početno ${summary.sickLeaveInitialDays} · iskorišteno ${summary.sickLeaveUsedDays} · preostalo ${summary.sickLeaveRemainingDays}`;
    return;
  }

  absenceBalancePreview.textContent = `Početno ${summary.annualLeaveInitialDays} · iskorišteno ${summary.annualLeaveUsedDays} · preostalo ${summary.annualLeaveRemainingDays}`;
}

function syncAbsenceEditorChrome() {
  const config = getAbsenceModuleConfig();
  const isAdmin = getCanManageMasterData();
  const selectedType = String(absenceTypeInput?.value || config.typeOptions[0]?.value || "").trim().toLowerCase();
  const requiresApproval = doesAbsenceTypeRequireApproval(selectedType);
  const ownUserId = String(state.user?.id || "");

  renderAbsenceUserSelectOptions(absenceUserIdInput?.value || ownUserId);
  replaceSelectOptions(
    absenceTypeInput,
    config.typeOptions.map((option) => ({ value: option.value, label: option.label })),
    absenceTypeInput?.value || config.typeOptions[0]?.value || "",
  );
  replaceSelectOptions(absenceStatusInput, ABSENCE_STATUS_OPTIONS, absenceStatusInput?.value || (requiresApproval ? "pending" : "approved"));

  if (!isAdmin) {
    if (absenceUserIdInput) {
      absenceUserIdInput.value = ownUserId;
      absenceUserIdInput.disabled = true;
    }
    if (absenceStatusInput) {
      absenceStatusInput.value = requiresApproval ? "pending" : "approved";
      absenceStatusInput.disabled = true;
    }
  } else {
    if (absenceUserIdInput) {
      absenceUserIdInput.disabled = false;
    }
    if (absenceStatusInput) {
      absenceStatusInput.disabled = false;
    }
  }

  if (absenceEditorTitle) {
    const titlePrefix = getCurrentAbsenceModuleMode() === "medical" ? "Bolovanje / dopust" : "Zahtjev za dopust";
    absenceEditorTitle.textContent = absenceIdInput?.value
      ? `Uredi odsutnost | ${titlePrefix}`
      : titlePrefix;
  }

  if (absenceDeleteButton) {
    const canDelete = getCanManageMasterData() || String(state.user?.id ?? "") === String(absenceUserIdInput?.value || "");
    absenceDeleteButton.hidden = !absenceIdInput?.value || !canDelete;
  }

  if (absenceOpenFormButton) {
    absenceOpenFormButton.textContent = config.createLabel;
  }

  syncAbsenceDayCountPreview();
  syncAbsenceBalancePreview();
}

function buildAbsencePayload() {
  return {
    organizationId: state.activeOrganizationId || "",
    userId: absenceUserIdInput?.value || state.user?.id || "",
    type: absenceTypeInput?.value || "",
    status: absenceStatusInput?.value || "",
    startDate: absenceStartDateInput?.value || "",
    endDate: absenceEndDateInput?.value || absenceStartDateInput?.value || "",
    note: absenceNoteInput?.value || "",
    documents: absenceDocumentDrafts.map((entry) => ({ ...entry })),
  };
}

function syncAbsenceEditorModal() {
  const isOpen = Boolean(state.absenceEditorOpen);
  if (absenceEditorBackdrop) {
    absenceEditorBackdrop.hidden = !isOpen;
  }
  if (absenceEditorPanel) {
    absenceEditorPanel.hidden = !isOpen;
  }
  absenceEditorPanel?.classList.toggle("is-modal-open", isOpen);
  document.body.classList.toggle("is-absence-editor-open", isOpen);
}

function openAbsenceEditor() {
  state.absenceEditorOpen = true;
  syncAbsenceEditorModal();
}

function closeAbsenceEditor({ reset = false } = {}) {
  state.absenceEditorOpen = false;
  syncAbsenceEditorModal();
  if (reset) {
    resetAbsenceForm();
  }
}

function dismissAbsenceEditor() {
  closeAbsenceEditor({ reset: true });
}

function syncAbsenceBalanceModal() {
  const isOpen = Boolean(state.absenceBalanceEditorOpen);
  if (absenceBalanceBackdrop) {
    absenceBalanceBackdrop.hidden = !isOpen;
  }
  if (absenceBalancePanel) {
    absenceBalancePanel.hidden = !isOpen;
  }
  absenceBalancePanel?.classList.toggle("is-modal-open", isOpen);
}

function openAbsenceBalanceEditor() {
  state.absenceBalanceEditorOpen = true;
  syncAbsenceBalanceModal();
}

function closeAbsenceBalanceEditor() {
  state.absenceBalanceEditorOpen = false;
  syncAbsenceBalanceModal();
}

function resetAbsenceForm() {
  absenceForm?.reset();
  state.activeAbsenceId = "";
  if (absenceIdInput) {
    absenceIdInput.value = "";
  }
  if (absenceError) {
    absenceError.textContent = "";
  }
  if (absenceStartDateInput) {
    absenceStartDateInput.value = new Date().toISOString().slice(0, 10);
  }
  if (absenceEndDateInput) {
    absenceEndDateInput.value = new Date().toISOString().slice(0, 10);
  }
  if (absenceUserIdInput) {
    absenceUserIdInput.value = String(state.user?.id || "");
  }
  setAbsenceDocumentDrafts([]);
  renderAbsenceDocuments();
  syncAbsenceEditorChrome();
}

function hydrateAbsenceForm(entry) {
  setPeopleWorkspaceTab(
    ABSENCE_MEDICAL_TYPE_OPTIONS.some((option) => option.value === entry.type)
      ? "sick-leave"
      : "annual-leave",
  );
  state.activeSidebarGroup = "organisations";
  state.activeSidebarItem = "people";
  state.activeView = "management";
  renderActiveView();
  renderManagement();
  state.activeAbsenceId = entry.id;
  if (absenceIdInput) {
    absenceIdInput.value = entry.id || "";
  }
  if (absenceUserIdInput) {
    absenceUserIdInput.value = entry.userId || "";
  }
  if (absenceTypeInput) {
    absenceTypeInput.value = entry.type || "";
  }
  if (absenceStatusInput) {
    absenceStatusInput.value = entry.status || "pending";
  }
  if (absenceStartDateInput) {
    absenceStartDateInput.value = entry.startDate || "";
  }
  if (absenceEndDateInput) {
    absenceEndDateInput.value = entry.endDate || "";
  }
  if (absenceNoteInput) {
    absenceNoteInput.value = entry.note || "";
  }
  if (absenceError) {
    absenceError.textContent = "";
  }
  setAbsenceDocumentDrafts(entry.documents ?? []);
  renderAbsenceDocuments();
  syncAbsenceEditorChrome();
  openAbsenceEditor();
  requestAnimationFrame(() => {
    absenceStartDateInput?.focus({ preventScroll: true });
  });
}

function resetAbsenceBalanceDrafts() {
  const currentByUserId = new Map((state.absenceBalances ?? []).map((entry) => [String(entry.userId), entry]));
  absenceBalanceDrafts = state.users
    .filter((user) => user?.isActive !== false)
    .slice()
    .sort((left, right) => getUserDisplayLabel(left).localeCompare(getUserDisplayLabel(right), "hr"))
    .map((user) => {
      const current = currentByUserId.get(String(user.id));
      return {
        userId: String(user.id),
        userLabel: getUserDisplayLabel(user),
        annualLeaveInitialDays: Number(current?.annualLeaveInitialDays ?? 0) || 0,
        sickLeaveInitialDays: Number(current?.sickLeaveInitialDays ?? 0) || 0,
      };
    });
}

function renderAbsenceBalanceList() {
  if (!absenceBalanceList) {
    return;
  }

  absenceBalanceList.replaceChildren(...absenceBalanceDrafts.map((entry) => {
    const row = document.createElement("article");
    row.className = "absence-balance-row";

    const name = document.createElement("div");
    name.className = "absence-balance-row-copy";
    const title = document.createElement("strong");
    title.textContent = entry.userLabel;
    const meta = document.createElement("span");
    meta.textContent = "Početni saldo po korisniku";
    name.append(title, meta);

    const controls = document.createElement("div");
    controls.className = "absence-balance-row-fields";

    const annualField = document.createElement("label");
    annualField.className = "field";
    annualField.innerHTML = `<span>GO početno</span>`;
    const annualInput = document.createElement("input");
    annualInput.type = "number";
    annualInput.min = "0";
    annualInput.max = "365";
    annualInput.value = String(entry.annualLeaveInitialDays ?? 0);
    annualInput.addEventListener("input", () => {
      entry.annualLeaveInitialDays = Math.max(0, Number(annualInput.value || 0) || 0);
    });
    annualField.append(annualInput);

    const sickField = document.createElement("label");
    sickField.className = "field";
    sickField.innerHTML = `<span>Bolovanje početno</span>`;
    const sickInput = document.createElement("input");
    sickInput.type = "number";
    sickInput.min = "0";
    sickInput.max = "365";
    sickInput.value = String(entry.sickLeaveInitialDays ?? 0);
    sickInput.addEventListener("input", () => {
      entry.sickLeaveInitialDays = Math.max(0, Number(sickInput.value || 0) || 0);
    });
    sickField.append(sickInput);

    controls.append(annualField, sickField);
    row.append(name, controls);
    return row;
  }));
}

async function saveAbsenceBalanceDrafts() {
  const currentByUserId = new Map((state.absenceBalances ?? []).map((entry) => [String(entry.userId), entry]));
  const changedEntries = absenceBalanceDrafts.filter((entry) => {
    const current = currentByUserId.get(String(entry.userId));
    return Number(current?.annualLeaveInitialDays ?? 0) !== Number(entry.annualLeaveInitialDays ?? 0)
      || Number(current?.sickLeaveInitialDays ?? 0) !== Number(entry.sickLeaveInitialDays ?? 0);
  });

  if (changedEntries.length === 0) {
    if (absenceBalanceError) {
      absenceBalanceError.textContent = "Nema promjena za spremanje.";
    }
    return true;
  }

  const success = await runMutation(async () => {
    for (const entry of changedEntries) {
      await apiRequest("/absence-balances", {
        method: "POST",
        body: {
          userId: entry.userId,
          annualLeaveInitialDays: entry.annualLeaveInitialDays,
          sickLeaveInitialDays: entry.sickLeaveInitialDays,
        },
      });
    }
  }, absenceBalanceError);

  if (success && absenceBalanceError) {
    absenceBalanceError.textContent = "Saldo dana je spremljen.";
  }
  return success;
}

function createAbsenceCardDocumentActions(entry = {}) {
  const documents = (Array.isArray(entry.documents) ? entry.documents : [])
    .map((item) => createModuleAttachmentDraft(item))
    .filter((item) => item.fileName && (item.dataUrl || item.storageUrl));
  if (documents.length === 0) {
    return null;
  }

  const actions = document.createElement("div");
  actions.className = "safety-authorization-card-actions";
  documents.slice(0, 3).forEach((item) => {
    const button = createIconActionButton(`Preuzmi ${item.fileName}`, "download", "", (event) => {
      event.preventDefault();
      event.stopPropagation();
      triggerModuleAttachmentDownload(item);
    });
    button.classList.add("safety-authorization-card-download-button");
    actions.append(button);
  });
  return actions;
}

function renderAbsenceModule() {
  if (!absenceModule || !absenceList || !absenceEmpty) {
    return;
  }

  const config = getAbsenceModuleConfig();
  const filters = getAbsenceFiltersStateForCurrentMode();
  const canManage = getCanManageMasterData();
  const allItems = sortAbsenceEntries(getAbsenceEntriesForCurrentMode());
  const visibleItems = sortAbsenceEntries(filterAbsenceEntries(allItems, filters));
  const selectedUserId = filters.userId && filters.userId !== "all"
    ? filters.userId
    : String(state.user?.id || "");
  const selectedBalance = selectedUserId ? getAbsenceBalanceSummaryForUser(selectedUserId) : null;

  if (absenceModuleKicker) {
    absenceModuleKicker.textContent = config.kicker;
  }
  if (absenceModuleTitle) {
    absenceModuleTitle.textContent = config.title;
  }
  if (absenceModuleCopy) {
    absenceModuleCopy.textContent = config.copy;
  }
  if (absenceOpenFormButton) {
    absenceOpenFormButton.textContent = config.createLabel;
  }
  if (absenceOpenBalancesButton) {
    absenceOpenBalancesButton.hidden = !canManage;
  }

  if (absenceSearchInput && document.activeElement !== absenceSearchInput) {
    absenceSearchInput.value = filters.query || "";
  }
  renderAbsenceFilterOptions();

  if (absenceSummaryTotal) {
    absenceSummaryTotal.textContent = String(allItems.length);
  }
  if (absenceSummaryPending) {
    absenceSummaryPending.textContent = String(allItems.filter((entry) => String(entry.status).toLowerCase() === "pending").length);
  }
  if (absenceSummaryApproved) {
    absenceSummaryApproved.textContent = String(allItems.filter((entry) => String(entry.status).toLowerCase() === "approved").length);
  }
  if (absenceSummaryBalance) {
    absenceSummaryBalance.textContent = selectedBalance
      ? String(getCurrentAbsenceModuleMode() === "medical"
        ? selectedBalance.sickLeaveRemainingDays
        : selectedBalance.annualLeaveRemainingDays)
      : "0";
  }
  if (absenceHelper) {
    const balanceText = selectedBalance
      ? `${config.balanceLabel}: ${getCurrentAbsenceModuleMode() === "medical" ? selectedBalance.sickLeaveRemainingDays : selectedBalance.annualLeaveRemainingDays}`
      : "Bez odabranog salda";
    absenceHelper.textContent = visibleItems.length === allItems.length
      ? `Prikazano ${visibleItems.length} stavki. ${balanceText}.`
      : `Prikazano ${visibleItems.length} od ${allItems.length} stavki. ${balanceText}.`;
  }

  absenceList.replaceChildren(...visibleItems.map((entry) => {
    const card = document.createElement("article");
    card.className = "safety-authorization-card absence-card";
    if (String(entry.id) === String(state.activeAbsenceId || "")) {
      card.classList.add("is-active");
    }

    const canOpen = canManageAbsenceEntryClient(entry);
    if (canOpen) {
      card.tabIndex = 0;
      card.setAttribute("role", "button");
    }

    const head = document.createElement("div");
    head.className = "safety-authorization-card-head";

    const copy = document.createElement("div");
    copy.className = "safety-authorization-card-copy";
    const title = document.createElement("h4");
    title.textContent = entry.userLabel || "Korisnik";
    const meta = document.createElement("p");
    meta.className = "safety-authorization-card-meta";
    meta.textContent = `${formatCompactDate(entry.startDate)} - ${formatCompactDate(entry.endDate)} · ${entry.dayCount || 0} dana`;
    copy.append(title, meta);

    const chips = document.createElement("div");
    chips.className = "safety-authorization-card-chips";
    chips.append(
      createBadge(getAbsenceTypeLabelClient(entry.type), "measurement-equipment-chip"),
      createBadge(getAbsenceStatusLabelClient(entry.status), getAbsenceStatusBadgeClass(entry.status)),
    );
    head.append(copy, chips);

    const note = document.createElement("p");
    note.className = "safety-authorization-card-note";
    note.textContent = entry.note || "Bez dodatne napomene.";

    const footer = document.createElement("div");
    footer.className = "safety-authorization-card-footer";
    const info = document.createElement("div");
    info.className = "safety-authorization-card-chips";
    const requestedLabel = entry.requestedByLabel ? `Zahtjev: ${entry.requestedByLabel}` : "Bez pošiljatelja";
    info.append(createBadge(requestedLabel, "service-catalog-template-badge"));
    if (entry.approvedByLabel && String(entry.status).toLowerCase() === "approved") {
      info.append(createBadge(`Odobrio: ${entry.approvedByLabel}`, "service-catalog-template-badge"));
    }
    const documentCount = Array.isArray(entry.documents) ? entry.documents.length : 0;
    info.append(createBadge(
      documentCount > 0 ? `${documentCount} dok.` : "Bez dokumenata",
      documentCount > 0 ? "service-catalog-template-badge" : "service-catalog-template-badge is-muted",
    ));
    footer.append(info);

    if (canManage && String(entry.status).toLowerCase() === "pending" && doesAbsenceTypeRequireApproval(entry.type)) {
      const actions = document.createElement("div");
      actions.className = "absence-card-actions";
      const approveButton = document.createElement("button");
      approveButton.type = "button";
      approveButton.className = "ghost-button";
      approveButton.textContent = "Odobri";
      approveButton.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        void runMutation(() => apiRequest(`/absence-entries/${entry.id}`, {
          method: "PATCH",
          body: { status: "approved" },
        }), absenceError).then(() => {
          renderAbsenceModule();
          renderAbsenceReportModule();
          renderNotifications();
          renderWorkOrderCalendarView();
        });
      });

      const rejectButton = document.createElement("button");
      rejectButton.type = "button";
      rejectButton.className = "ghost-button card-danger";
      rejectButton.textContent = "Odbij";
      rejectButton.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        void runMutation(() => apiRequest(`/absence-entries/${entry.id}`, {
          method: "PATCH",
          body: { status: "rejected" },
        }), absenceError).then(() => {
          renderAbsenceModule();
          renderAbsenceReportModule();
          renderNotifications();
          renderWorkOrderCalendarView();
        });
      });

      actions.append(approveButton, rejectButton);
      footer.append(actions);
    }

    const documentActions = createAbsenceCardDocumentActions(entry);
    if (documentActions) {
      footer.append(documentActions);
    }

    card.append(head, note, footer);

    if (canOpen) {
      const openEntry = () => hydrateAbsenceForm(entry);
      card.addEventListener("click", openEntry);
      card.addEventListener("keydown", (event) => {
        if (event.key !== "Enter" && event.key !== " ") {
          return;
        }
        event.preventDefault();
        openEntry();
      });
    }

    return card;
  }));

  absenceEmpty.hidden = visibleItems.length !== 0;
  if (visibleItems.length === 0) {
    const empty = document.createElement("div");
    empty.className = "offers-empty-card";
    empty.textContent = getCurrentAbsenceModuleMode() === "medical"
      ? "Nema evidentiranih bolovanja ili posebnih dopusta za zadane filtere."
      : "Nema zahtjeva za godišnji ili druge dopuste za zadane filtere.";
    absenceList.replaceChildren(empty);
  }
}

function getAbsenceReportRows() {
  const rows = buildMonthlyWorkStatusReport({
    users: state.users ?? [],
    absenceEntries: state.absenceEntries ?? [],
    absenceBalances: state.absenceBalances ?? [],
    workOrders: state.workOrders ?? [],
  }, state.absenceReportMonth || new Date().toISOString().slice(0, 7));

  if (!state.absenceReportFilters.userId || state.absenceReportFilters.userId === "all") {
    return rows;
  }

  return rows.filter((row) => String(row.userId) === String(state.absenceReportFilters.userId));
}

function exportAbsenceReportCsv() {
  const rows = getAbsenceReportRows();
  const breakdownHeaders = ABSENCE_TYPE_OPTIONS.map((option) => ({
    key: option.value,
    label: option.label,
  }));
  const headers = [
    "Korisnik",
    "Mjesec",
    "Radni dani u mjesecu",
    "Redovni rad",
    "Dani odsutnosti",
    "Dodijeljeni RN",
    "GO početno",
    "GO iskorišteno",
    "GO preostalo",
    "Bolovanje početno",
    "Bolovanje iskorišteno",
    "Bolovanje preostalo",
    ...breakdownHeaders.map((entry) => entry.label),
  ];

  const csvRows = [
    headers.join(";"),
    ...rows.map((row) => [
      row.userLabel,
      state.absenceReportMonth,
      row.businessDayCount,
      row.regularWorkDays,
      row.absenceDays,
      row.assignedWorkOrderCount,
      row.annualLeaveInitialDays,
      row.annualLeaveUsedDays,
      row.annualLeaveRemainingDays,
      row.sickLeaveInitialDays,
      row.sickLeaveUsedDays,
      row.sickLeaveRemainingDays,
      ...breakdownHeaders.map((entry) => row.dayBreakdown?.[entry.key] ?? 0),
    ].map((value) => `"${String(value ?? "").replace(/"/g, "\"\"")}"`).join(";")),
  ];

  triggerBlobDownload(
    new Blob(["\ufeff", csvRows.join("\r\n")], { type: "text/csv;charset=utf-8" }),
    `work-status-report-${state.absenceReportMonth || new Date().toISOString().slice(0, 7)}.csv`,
  );
}

function renderAbsenceReportModule() {
  if (!absenceReportModule || !absenceReportList || !absenceReportEmpty) {
    return;
  }

  const userOptions = [
    { value: "all", label: "Svi korisnici" },
    ...state.users
      .filter((user) => user?.isActive !== false)
      .slice()
      .sort((left, right) => getUserDisplayLabel(left).localeCompare(getUserDisplayLabel(right), "hr"))
      .map((user) => ({
        value: String(user.id),
        label: getUserDisplayLabel(user),
      })),
  ];
  replaceSelectOptions(absenceReportUserFilterInput, userOptions, state.absenceReportFilters.userId || "all");

  if (absenceReportMonthInput && document.activeElement !== absenceReportMonthInput) {
    absenceReportMonthInput.value = state.absenceReportMonth || new Date().toISOString().slice(0, 7);
  }

  const rows = getAbsenceReportRows();
  const totalRegularDays = rows.reduce((sum, row) => sum + Number(row.regularWorkDays || 0), 0);
  const totalAbsenceDays = rows.reduce((sum, row) => sum + Number(row.absenceDays || 0), 0);

  if (absenceReportSummary) {
    absenceReportSummary.textContent = `${rows.length} korisnika · ${totalRegularDays} dana redovnog rada · ${totalAbsenceDays} dana odsutnosti`;
  }

  absenceReportList.replaceChildren(...rows.map((row) => {
    const card = document.createElement("article");
    card.className = "absence-report-card";

    const head = document.createElement("div");
    head.className = "absence-report-card-head";
    const title = document.createElement("strong");
    title.textContent = row.userLabel;
    const meta = document.createElement("span");
    meta.textContent = `${row.businessDayCount} radnih dana · ${row.assignedWorkOrderCount} RN`;
    head.append(title, meta);

    const stats = document.createElement("div");
    stats.className = "absence-report-card-stats";
    [
      { label: "Redovni rad", value: row.regularWorkDays },
      { label: "Odsutnosti", value: row.absenceDays },
      { label: "GO preostalo", value: row.annualLeaveRemainingDays },
      { label: "Bolovanje preostalo", value: row.sickLeaveRemainingDays },
    ].forEach((entry) => {
      const item = document.createElement("div");
      item.className = "absence-report-card-stat";
      item.innerHTML = `<span>${entry.label}</span><strong>${entry.value}</strong>`;
      stats.append(item);
    });

    const breakdown = document.createElement("div");
    breakdown.className = "absence-report-card-breakdown";
    Object.entries(row.dayBreakdown || {})
      .filter(([, count]) => Number(count || 0) > 0)
      .forEach(([key, count]) => {
        breakdown.append(createBadge(
          key === "regular_work"
            ? `Redovni rad ${count}`
            : `${getAbsenceTypeLabelClient(key)} ${count}`,
          key === "regular_work" ? "service-catalog-template-badge" : "measurement-equipment-chip",
        ));
      });

    card.append(head, stats, breakdown);
    return card;
  }));

  absenceReportEmpty.hidden = rows.length !== 0;
  if (rows.length === 0) {
    const empty = document.createElement("div");
    empty.className = "offers-empty-card";
    empty.textContent = "Nema podataka za odabrani mjesec i filtere.";
    absenceReportList.replaceChildren(empty);
  }
}

function renderDocumentTemplatePlaceholderPalette(template = buildDocumentTemplateDraft()) {
  if (!documentTemplatePlaceholderPalette) {
    return;
  }

  const definitions = getDocumentTemplatePlaceholderDefinitions(template);
  if (definitions.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy module-copy";
    empty.textContent = "Dodaj barem jedno polje ili Excel tablicu pa će se ovdje pojaviti tokeni za Word.";
    documentTemplatePlaceholderPalette.replaceChildren(empty);
    return;
  }

  documentTemplatePlaceholderPalette.replaceChildren(...definitions.map((entry) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "document-template-placeholder-chip";
    button.title = `${entry.label} | ${formatDocumentTemplateLookupResolvedValue(entry.value) || ""}`.trim();

    const token = document.createElement("strong");
    token.textContent = entry.token;
    const label = document.createElement("span");
    label.textContent = entry.label;

    button.append(token, label);
    button.addEventListener("click", () => {
      insertTextIntoDocumentTemplateTarget(entry.token);
    });
    return button;
  }));
}

function renderDocumentTemplateLinkSummary(template = buildDocumentTemplateDraft()) {
  if (!documentTemplateLinkSummary) {
    return;
  }

  const legalFrameworks = getDocumentTemplateSelectedLegalFrameworks(template);
  const equipmentItems = getDocumentTemplateLinkedEquipmentItems(template);
  const fields = Array.isArray(template.customFields) ? template.customFields : [];
  const blockCount = fields.filter((field) => String(field?.type || "").trim().toLowerCase() === "chapter").length;
  const placeholderCount = fields.filter((field) => String(field?.type || "").trim().toLowerCase() !== "chapter").length;

  const placeholderCard = document.createElement("article");
  placeholderCard.className = "document-template-link-card";
  placeholderCard.innerHTML = `
    <span>Placeholderi</span>
    <strong>${placeholderCount}</strong>
    <p>${blockCount > 0 ? `${blockCount} blokova organizira sadržaj predloška.` : "Dodaj blokove za jasnije grupiranje sadržaja."}</p>
  `;

  const wordCard = document.createElement("article");
  wordCard.className = `document-template-link-card ${template.referenceDocument?.fileName ? "is-ready" : "is-pending"}`;
  wordCard.innerHTML = `
    <span>Word</span>
    <strong>${template.referenceDocument?.fileName ? "Spreman" : "Čeka upload"}</strong>
    <p>${template.referenceDocument?.fileName ? escapeHtml(template.referenceDocument.fileName) : "Predložak još nije vraćen u app."}</p>
  `;

  const legalCard = document.createElement("article");
  legalCard.className = "document-template-link-card";
  legalCard.innerHTML = `
    <span>Propisi</span>
    <strong>${legalFrameworks.length}</strong>
    <p>${legalFrameworks.length > 0 ? "Povezano kroz Legal Framework modul." : "Još nema povezanih propisa za ovaj template."}</p>
  `;

  const equipmentCard = document.createElement("article");
  equipmentCard.className = "document-template-link-card";
  equipmentCard.innerHTML = `
    <span>Oprema</span>
    <strong>${equipmentItems.length}</strong>
    <p>${equipmentItems.length > 0 ? "Povezano kroz Measurement Equipment modul." : "Još nema povezane opreme za ovaj template."}</p>
  `;

  documentTemplateLinkSummary.replaceChildren(placeholderCard, wordCard, legalCard, equipmentCard);
}

function isDocumentTemplateRuntimeVisibleField(field = {}) {
  const type = String(field?.type || "text").trim().toLowerCase();
  return type !== "page_break";
}

function getDocumentTemplateFieldDefaultRuntimeValue(field = {}) {
  if (String(field?.type || "").trim().toLowerCase() === "system_description") {
    return normalizeDocumentTemplateSystemDescriptionRuntimeValue(field);
  }

  if (field.type === "checkbox" || field.type === "toggle") {
    return ["1", "true", "da", "yes", "on"].includes(String(field.defaultValue || "").trim().toLowerCase());
  }
  return field.defaultValue ?? "";
}

function getDocumentTemplateRuntimeInitialValue(field = {}, workOrderId = "") {
  const runtimeValue = getDocumentTemplateRuntimeFieldValue(workOrderId, field.id);
  if (runtimeValue !== undefined) {
    return runtimeValue;
  }

  const normalizedWorkOrderId = String(workOrderId || state.documentTemplateRuntime.activeWorkOrderId || "").trim();
  const workOrder = (state.workOrders ?? []).find((item) => String(item.id) === normalizedWorkOrderId) ?? null;
  const template = buildDocumentTemplateDraft();
  const sourceId = getDocumentTemplateRuntimeFieldSource(normalizedWorkOrderId, field.id);

  if (sourceId === "blank") {
    if (String(field?.type || "").trim().toLowerCase() === "system_description") {
      return createDocumentTemplateSystemDescriptionBlankValue(field);
    }
    return field.type === "checkbox" || field.type === "toggle" ? false : "";
  }

  if (workOrder && sourceId === "template") {
    return getDocumentTemplateFieldDefaultRuntimeValue(field);
  }

  if (workOrder && sourceId.startsWith("record:")) {
    const selectedCandidate = getDocumentTemplatePreviousRecordFieldCandidateById(
      field,
      workOrder,
      template,
      sourceId,
    );
    if (selectedCandidate) {
      return selectedCandidate.value;
    }
  }

  if (isDocumentTemplatePreviousDocumentLookupField(field)) {
    return getDocumentTemplatePreviousDocumentFallbackValue(field, workOrderId, template);
  }

  if (workOrder && isDocumentTemplateRuntimePersistedField(field)) {
    const { candidates } = getDocumentTemplatePreviousRecordFieldCandidates(field, workOrder, template);
    if (candidates.length > 0) {
      return candidates[0].value;
    }
  }

  if (workOrder) {
    const boundValue = getDocumentTemplateSourceRuntimeValue(
      field,
      buildDocumentTemplatePreviewContext(template, { workOrder }),
    );
    if (hasMeaningfulDocumentRecordValue(boundValue)) {
      return normalizeDocumentTemplateRuntimeFieldValueByType(field, boundValue);
    }
  }

  return normalizeDocumentTemplateRuntimeFieldValueByType(field, getDocumentTemplateFieldDefaultRuntimeValue(field));
}

function buildDocumentTemplateRuntimeBlockGroups(fields = documentTemplateFieldDrafts) {
  const blocks = [];
  let currentBlock = null;

  (Array.isArray(fields) ? fields : []).forEach((field, index) => {
    if (!field) {
      return;
    }

    if (String(field.type || "").trim().toLowerCase() === "chapter") {
      currentBlock = {
        chapter: field,
        chapterIndex: index,
        items: [],
      };
      blocks.push(currentBlock);
      return;
    }

    if (!isDocumentTemplateRuntimeVisibleField(field)) {
      return;
    }

    if (!currentBlock) {
      currentBlock = {
        chapter: null,
        chapterIndex: -1,
        items: [],
      };
      blocks.push(currentBlock);
    }

    currentBlock.items.push({ field, index });
  });

  return blocks;
}

function getDocumentTemplateRuntimeBlockId(block = {}, blockIndex = 0) {
  const chapterId = String(block?.chapter?.id || "").trim();
  return chapterId || `runtime-block:${blockIndex + 1}`;
}

function isDocumentTemplateRuntimeBlockCollapsed(block = {}, blockIndex = 0) {
  const blockId = getDocumentTemplateRuntimeBlockId(block, blockIndex);
  return Boolean(state.documentTemplateRuntime.collapsedBlocks?.[blockId]);
}

function setDocumentTemplateRuntimeBlockCollapsed(block = {}, blockIndex = 0, collapsed = false, { render = true } = {}) {
  const blockId = getDocumentTemplateRuntimeBlockId(block, blockIndex);
  const nextCollapsedBlocks = {
    ...(state.documentTemplateRuntime.collapsedBlocks ?? {}),
  };

  if (collapsed) {
    nextCollapsedBlocks[blockId] = true;
  } else {
    delete nextCollapsedBlocks[blockId];
  }

  state.documentTemplateRuntime = {
    ...state.documentTemplateRuntime,
    collapsedBlocks: nextCollapsedBlocks,
  };

  if (render) {
    renderDocumentTemplateFieldRows();
  }
}

const LEARNING_QUESTION_OPTION_KEYS = ["A", "B", "C", "D"];
const LEARNING_QUESTION_TYPE_OPTIONS = [
  { value: "single_choice", label: "Jedan točan odgovor" },
  { value: "multiple_choice", label: "Višestruki odgovor" },
  { value: "ordered_text", label: "Pisanje brojeva ispred teksta" },
];
const LEARNING_TEST_MATERIAL_MAX_SIZE_BYTES = 30 * 1024 * 1024;
const LEARNING_TEST_MATERIAL_ACCEPT_LABEL = ".pdf,.png,.jpg,.jpeg,.gif,.webp,.bmp,.svg,.tif,.tiff,.heic,.ppt,.pptx,.pps,.ppsx,.doc,.docx,.xls,.xlsx,.txt,.mp4,.webm,.mov,.m4v";
const LEARNING_TEST_MATERIAL_ALLOWED_EXTENSIONS = new Set([
  ".pdf", ".png", ".jpg", ".jpeg", ".gif", ".webp", ".bmp", ".svg", ".tif", ".tiff", ".heic",
  ".ppt", ".pptx", ".pps", ".ppsx", ".doc", ".docx", ".xls", ".xlsx", ".txt",
  ".mp4", ".webm", ".mov", ".m4v",
]);
const LEARNING_TEST_MATERIAL_CATEGORY_OPTIONS = [
  { value: "Materijal", label: "Materijal" },
  { value: "PDF", label: "PDF" },
  { value: "Slika", label: "Slika" },
  { value: "Video", label: "Video" },
  { value: "Prezentacija", label: "Prezentacija" },
  { value: "Priručnik", label: "Priručnik" },
];

function getLearningQuestionTypeLabel(value = "") {
  return LEARNING_QUESTION_TYPE_OPTIONS.find((option) => option.value === String(value || "").trim().toLowerCase())?.label
    || "Jedan točan odgovor";
}

function normalizeLearningQuestionTypeClient(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  return LEARNING_QUESTION_TYPE_OPTIONS.some((option) => option.value === normalized)
    ? normalized
    : "single_choice";
}

function inferLearningTestMaterialCategory(fileName = "", fileType = "") {
  const normalizedType = String(fileType || "").trim().toLowerCase();
  const normalizedName = String(fileName || "").trim().toLowerCase();
  if (normalizedType.startsWith("image/") || /\.(png|jpe?g|gif|webp|bmp|svg|tiff?|heic)$/i.test(normalizedName)) {
    return "Slika";
  }
  if (normalizedType.startsWith("video/") || /\.(mp4|webm|mov|m4v)$/i.test(normalizedName)) {
    return "Video";
  }
  if (normalizedType.includes("pdf") || /\.pdf$/i.test(normalizedName)) {
    return "PDF";
  }
  if (/\.(ppt|pptx|pps|ppsx)$/i.test(normalizedName)) {
    return "Prezentacija";
  }
  if (/\.(doc|docx)$/i.test(normalizedName)) {
    return "Priručnik";
  }
  return "Materijal";
}

function isLearningTestMaterialFileAllowed(file) {
  if (!(file instanceof File)) {
    return false;
  }
  const normalizedName = String(file.name || "").trim().toLowerCase();
  return [...LEARNING_TEST_MATERIAL_ALLOWED_EXTENSIONS].some((extension) => normalizedName.endsWith(extension));
}

function createLearningTestMaterialDraft(document = {}) {
  return createModuleAttachmentDraft({
    ...document,
    documentCategory: String(document.documentCategory || "").trim()
      || inferLearningTestMaterialCategory(document.fileName, document.fileType),
  });
}

function normalizeLearningQuestionCorrectKeysClient(values = [], fallbackValue = "A") {
  const fallback = String(fallbackValue || "A").trim().toUpperCase() || "A";
  return Array.from(new Set(
    (Array.isArray(values) ? values : [values])
      .map((value) => String(value || "").trim().toUpperCase())
      .filter((value) => LEARNING_QUESTION_OPTION_KEYS.includes(value)),
  )).filter(Boolean).length
    ? Array.from(new Set(
      (Array.isArray(values) ? values : [values])
        .map((value) => String(value || "").trim().toUpperCase())
        .filter((value) => LEARNING_QUESTION_OPTION_KEYS.includes(value)),
    ))
    : [fallback];
}

function createEmptyLearningQuestionDraft(initial = {}, index = 0) {
  const normalizedOptions = Array.isArray(initial.options) ? initial.options : [];
  const questionType = normalizeLearningQuestionTypeClient(initial.questionType);
  const correctLetter = LEARNING_QUESTION_OPTION_KEYS.find((letter, optionIndex) => Boolean(normalizedOptions[optionIndex]?.isCorrect))
    || String(initial.correctOptionKey || "").trim().toUpperCase()
    || "A";
  const correctOptionKeys = normalizeLearningQuestionCorrectKeysClient(
    initial.correctOptionKeys
      || normalizedOptions
        .filter((option, optionIndex) => Boolean(option?.isCorrect) && LEARNING_QUESTION_OPTION_KEYS[optionIndex])
        .map((option, optionIndex) => LEARNING_QUESTION_OPTION_KEYS[optionIndex]),
    correctLetter,
  );
  const imageDocument = initial.imageDocument ? createModuleAttachmentDraft(initial.imageDocument) : null;

  return {
    id: String(initial.id || crypto.randomUUID()),
    code: String(initial.code || `P${index + 1}`).trim() || `P${index + 1}`,
    prompt: String(initial.prompt || "").trim(),
    questionType,
    correctOptionKey: LEARNING_QUESTION_OPTION_KEYS.includes(correctLetter) ? correctLetter : "A",
    correctOptionKeys: questionType === "ordered_text" ? [] : correctOptionKeys,
    optionA: String(initial.optionA || normalizedOptions[0]?.text || "").trim(),
    optionB: String(initial.optionB || normalizedOptions[1]?.text || "").trim(),
    optionC: String(initial.optionC || normalizedOptions[2]?.text || "").trim(),
    optionD: String(initial.optionD || normalizedOptions[3]?.text || "").trim(),
    orderA: String(initial.orderA || normalizedOptions[0]?.orderIndex || "").trim(),
    orderB: String(initial.orderB || normalizedOptions[1]?.orderIndex || "").trim(),
    orderC: String(initial.orderC || normalizedOptions[2]?.orderIndex || "").trim(),
    orderD: String(initial.orderD || normalizedOptions[3]?.orderIndex || "").trim(),
    imageDocument: imageDocument?.fileName ? imageDocument : null,
  };
}

function createEmptyLearningQuestionGroupDraft(initial = {}, index = 0) {
  return {
    id: String(initial.id || crypto.randomUUID()),
    title: String(initial.title || initial.groupLabel || `Grupa ${index + 1}`).trim() || `Grupa ${index + 1}`,
    questions: (Array.isArray(initial.questions) ? initial.questions : [])
      .map((question, questionIndex) => createEmptyLearningQuestionDraft(question, questionIndex)),
  };
}

function buildLearningQuestionGroupDraftsFromItems(items = []) {
  return [
    createEmptyLearningQuestionGroupDraft({
      title: "Pitanja",
      questions: Array.isArray(items) ? items : [],
    }, 0),
  ];
}

function serializeLearningQuestionGroupDrafts() {
  return learningTestQuestionGroupDrafts.flatMap((group, groupIndex) => (
    (group.questions ?? []).map((question, questionIndex) => ({
      id: question.id || crypto.randomUUID(),
      code: String(question.code || `G${groupIndex + 1}-P${questionIndex + 1}`).trim() || `G${groupIndex + 1}-P${questionIndex + 1}`,
      groupLabel: String(group.title || `Grupa ${groupIndex + 1}`).trim() || `Grupa ${groupIndex + 1}`,
      prompt: String(question.prompt || "").trim(),
      explanation: "",
      questionType: normalizeLearningQuestionTypeClient(question.questionType),
      correctOptionKeys: normalizeLearningQuestionTypeClient(question.questionType) === "ordered_text"
        ? []
        : normalizeLearningQuestionCorrectKeysClient(
          question.correctOptionKeys,
          question.correctOptionKey || "A",
        ),
      imageDocument: question.imageDocument?.fileName ? createModuleAttachmentDraft(question.imageDocument) : null,
      options: LEARNING_QUESTION_OPTION_KEYS.map((letter) => ({
        id: crypto.randomUUID(),
        text: String(question[`option${letter}`] || "").trim(),
        isCorrect: normalizeLearningQuestionTypeClient(question.questionType) === "multiple_choice"
          ? normalizeLearningQuestionCorrectKeysClient(question.correctOptionKeys, question.correctOptionKey || "A").includes(letter)
          : (normalizeLearningQuestionTypeClient(question.questionType) === "single_choice"
            ? String(question.correctOptionKey || "A").trim().toUpperCase() === letter
            : false),
        orderIndex: normalizeLearningQuestionTypeClient(question.questionType) === "ordered_text"
          ? (Number.isFinite(Number(question[`order${letter}`]))
            ? Math.max(1, Math.round(Number(question[`order${letter}`])))
            : null)
          : null,
      })),
    }))
  )).filter((question) => (
    question.prompt
    && question.options.some((option) => option.text)
  ));
}

function setLearningTestMaterialDrafts(items = []) {
  learningTestMaterialDrafts = (Array.isArray(items) ? items : [])
    .map((item) => createLearningTestMaterialDraft(item))
    .filter((item) => item.fileName && (item.dataUrl || item.storageUrl));
}

function updateLearningTestMaterialDraft(documentId, patch = {}) {
  learningTestMaterialDrafts = learningTestMaterialDrafts.map((item) => (
    item.id === documentId
      ? {
        ...item,
        ...patch,
      }
      : item
  ));
}

function getLearningTestMaterialPreviewUrl(entry = {}) {
  return String(entry.storageUrl || entry.dataUrl || "").trim();
}

function getLearningTestMaterialPreviewKind(entry = {}) {
  const fileType = String(entry.fileType || "").trim().toLowerCase();
  const fileName = String(entry.fileName || "").trim().toLowerCase();
  if (fileType.startsWith("image/") || /\.(png|jpe?g|gif|webp|bmp|svg|tiff?|heic)$/i.test(fileName)) {
    return "image";
  }
  if (fileType.startsWith("video/") || /\.(mp4|webm|mov|m4v)$/i.test(fileName)) {
    return "video";
  }
  if (fileType.includes("pdf") || /\.pdf$/i.test(fileName)) {
    return "pdf";
  }
  return "download";
}

async function queueLearningTestMaterials(files) {
  const uploadFiles = Array.from(files ?? []).filter((file) => file instanceof File);
  if (uploadFiles.length === 0) {
    return;
  }

  for (const file of uploadFiles) {
    if (!isLearningTestMaterialFileAllowed(file)) {
      throw new Error(`Format ${file.name} nije podržan. Dozvoljeno: ${LEARNING_TEST_MATERIAL_ACCEPT_LABEL}`);
    }
    if (file.size > LEARNING_TEST_MATERIAL_MAX_SIZE_BYTES) {
      throw new Error(`Datoteka ${file.name} mora biti manja od 30 MB.`);
    }
  }

  const uploads = await Promise.all(uploadFiles.map(async (file) => createLearningTestMaterialDraft({
    fileName: file.name,
    fileType: file.type,
    fileSize: file.size,
    dataUrl: await readFileAsDataUrl(file, `Ne mogu učitati datoteku ${file.name}.`),
    updatedAt: new Date().toISOString(),
  })));

  learningTestMaterialDrafts = [
    ...learningTestMaterialDrafts,
    ...uploads,
  ];
  renderLearningTestMaterialList();
}

function renderLearningTestMaterialList() {
  if (!learningTestMaterialList) {
    return;
  }

  if (learningTestMaterialDrafts.length === 0) {
    const empty = document.createElement("div");
    empty.className = "learning-test-material-empty";
    const strong = document.createElement("strong");
    strong.textContent = "Dodaj materijale za polaznika";
    const copy = document.createElement("p");
    copy.textContent = "PDF, slike, prezentacije i video prikazat će se u live previewu kao slajdovi prije pitanja.";
    empty.append(strong, copy);
    learningTestMaterialList.replaceChildren(empty);
    return;
  }

  learningTestMaterialList.replaceChildren(...learningTestMaterialDrafts.map((entry) => {
    const row = document.createElement("article");
    row.className = "module-attachment-row learning-test-material-row";

    const copy = document.createElement("div");
    copy.className = "module-attachment-copy";

    const title = document.createElement("strong");
    title.textContent = entry.fileName;

    const meta = document.createElement("span");
    meta.textContent = [
      formatFileSize(entry.fileSize),
      entry.updatedAt ? formatCompactDateTime(entry.updatedAt) : "",
    ].filter(Boolean).join(" | ");

    copy.append(title, meta);

    const categorySlot = document.createElement("div");
    categorySlot.className = "module-attachment-middle";
    const categorySelect = document.createElement("select");
    categorySelect.className = "module-attachment-category-select";
    categorySelect.setAttribute("aria-label", "Vrsta materijala");
    replaceSelectOptions(
      categorySelect,
      LEARNING_TEST_MATERIAL_CATEGORY_OPTIONS,
      entry.documentCategory || inferLearningTestMaterialCategory(entry.fileName, entry.fileType),
    );
    categorySelect.addEventListener("change", () => {
      updateLearningTestMaterialDraft(entry.id, {
        documentCategory: categorySelect.value || inferLearningTestMaterialCategory(entry.fileName, entry.fileType),
      });
    });
    categorySlot.append(categorySelect);

    const actions = document.createElement("div");
    actions.className = "module-attachment-actions";
    const previewButton = createIconActionButton("Live preview", "preview", "", () => {
      const slides = buildLearningTestPreviewSlides();
      const slideIndex = slides.findIndex((slide) => (
        slide.type === "material" && String(slide.document?.id || "") === String(entry.id)
      ));
      openLearningTestPreview(slideIndex >= 0 ? slideIndex : 0);
    });
    const removeButton = createIconActionButton("Makni materijal", "trash", "card-danger", () => {
      learningTestMaterialDrafts = learningTestMaterialDrafts.filter((item) => item.id !== entry.id);
      renderLearningTestMaterialList();
    });
    actions.append(previewButton, removeButton);

    row.append(copy, categorySlot, actions);
    return row;
  }));

  if (learningTestPreviewOpen) {
    renderLearningTestPreview();
  }
}

function buildLearningTestPreviewSlides() {
  const slides = [];
  const title = String(learningTestTitleInput?.value || "").trim() || "Nova grupa edukacije";
  const description = String(learningTestDescriptionInput?.value || "").trim();

  slides.push({
    id: "intro",
    type: "intro",
    title,
    description,
  });

  learningTestMaterialDrafts.forEach((entry, index) => {
    slides.push({
      id: String(entry.id || `material-${index + 1}`),
      type: "material",
      title: entry.fileName || `Materijal ${index + 1}`,
      category: entry.documentCategory || inferLearningTestMaterialCategory(entry.fileName, entry.fileType),
      description: entry.description || "",
      previewKind: getLearningTestMaterialPreviewKind(entry),
      previewUrl: getLearningTestMaterialPreviewUrl(entry),
      fileType: entry.fileType || "",
      fileSize: entry.fileSize || 0,
      document: entry,
    });
  });

  learningTestQuestionGroupDrafts.forEach((group, groupIndex) => {
    (group.questions ?? []).forEach((question, questionIndex) => {
      const questionType = normalizeLearningQuestionTypeClient(question.questionType);
      const normalizedOptions = LEARNING_QUESTION_OPTION_KEYS.map((letter) => ({
        key: letter,
        text: String(question[`option${letter}`] || "").trim(),
        orderIndex: String(question[`order${letter}`] || "").trim(),
      })).filter((option) => option.text);
      const prompt = String(question.prompt || "").trim();
      if (!prompt && normalizedOptions.length === 0) {
        return;
      }
      slides.push({
        id: String(question.id || `question-${groupIndex + 1}-${questionIndex + 1}`),
        type: "question",
        title: `Pitanje ${questionIndex + 1}`,
        groupTitle: String(group.title || `Grupa ${groupIndex + 1}`).trim() || `Grupa ${groupIndex + 1}`,
        questionType,
        questionTypeLabel: getLearningQuestionTypeLabel(questionType),
        prompt,
        imageDocument: question.imageDocument?.fileName ? question.imageDocument : null,
        options: normalizedOptions,
      });
    });
  });

  return slides;
}

function syncLearningTestPreviewModal() {
  const isOpen = Boolean(learningTestPreviewOpen);
  if (learningTestPreviewPanel) {
    learningTestPreviewPanel.hidden = !isOpen;
    learningTestPreviewPanel.setAttribute("aria-hidden", String(!isOpen));
  }
  if (learningTestPreviewBackdrop) {
    learningTestPreviewBackdrop.hidden = !isOpen;
  }
  document.body.classList.toggle("is-learning-test-preview-open", isOpen);
}

function renderLearningTestPreview() {
  if (!learningTestPreviewStage) {
    return;
  }

  const slides = buildLearningTestPreviewSlides();
  const safeIndex = Math.max(0, Math.min(learningTestPreviewSlideIndex, Math.max(0, slides.length - 1)));
  learningTestPreviewSlideIndex = safeIndex;
  const slide = slides[safeIndex] || slides[0] || {
    type: "intro",
    title: "Nova grupa edukacije",
    description: "",
  };

  if (learningTestPreviewTitle) {
    learningTestPreviewTitle.textContent = `${safeIndex + 1}/${slides.length || 1} · ${String(learningTestTitleInput?.value || "").trim() || "Preview edukacije"}`;
  }

  const frame = document.createElement("div");
  frame.className = "learning-test-preview-frame";

  const header = document.createElement("div");
  header.className = "learning-test-preview-slide-head";

  const headerCopy = document.createElement("div");
  headerCopy.className = "learning-test-preview-slide-copy";
  const kicker = document.createElement("span");
  kicker.className = "learning-test-preview-slide-kicker";
  kicker.textContent = slide.type === "question"
    ? `${slide.groupTitle || "Pitanja"} · ${slide.questionTypeLabel || "Pitanje"}`
    : (slide.type === "material" ? (slide.category || "Materijal") : "Pregled edukacije");
  const title = document.createElement("h4");
  title.textContent = slide.title || "Pregled";
  headerCopy.append(kicker, title);
  if (slide.description) {
    const description = document.createElement("p");
    description.textContent = slide.description;
    headerCopy.append(description);
  } else if (slide.prompt && slide.type === "question") {
    const prompt = document.createElement("p");
    prompt.textContent = slide.prompt;
    headerCopy.append(prompt);
  }

  const position = document.createElement("span");
  position.className = "learning-test-preview-position";
  position.textContent = `${safeIndex + 1} / ${slides.length || 1}`;
  header.append(headerCopy, position);

  const stageBody = document.createElement("div");
  stageBody.className = "learning-test-preview-slide-body";

  if (slide.type === "intro") {
    const introCard = document.createElement("article");
    introCard.className = "learning-test-preview-slide-card is-intro";
    const introTitle = document.createElement("h5");
    introTitle.textContent = slide.title || "Grupa edukacije";
    const introCopy = document.createElement("p");
    introCopy.textContent = slide.description || "Materijali i pitanja prikazat će se polazniku kao niz slajdova prije završnog slanja testa.";
    introCard.append(introTitle, introCopy);
    if (learningTestMaterialDrafts.length > 0 || slides.some((item) => item.type === "question")) {
      const stats = document.createElement("div");
      stats.className = "learning-test-preview-stats";
      [
        `${learningTestMaterialDrafts.length} materijala`,
        `${slides.filter((item) => item.type === "question").length} pitanja`,
      ].forEach((label) => {
        const badge = document.createElement("span");
        badge.className = "document-template-status-badge";
        badge.textContent = label;
        stats.append(badge);
      });
      introCard.append(stats);
    }
    stageBody.append(introCard);
  } else if (slide.type === "material") {
    const materialCard = document.createElement("article");
    materialCard.className = "learning-test-preview-slide-card is-material";
    const previewKind = slide.previewKind;
    const previewUrl = String(slide.previewUrl || "").trim();
    if (previewUrl && previewKind === "image") {
      const image = document.createElement("img");
      image.className = "learning-test-preview-image";
      image.src = previewUrl;
      image.alt = slide.title || "Materijal";
      materialCard.append(image);
    } else if (previewUrl && previewKind === "video") {
      const video = document.createElement("video");
      video.className = "learning-test-preview-video";
      video.src = previewUrl;
      video.controls = true;
      video.preload = "metadata";
      materialCard.append(video);
    } else if (previewUrl && previewKind === "pdf") {
      const embed = document.createElement("iframe");
      embed.className = "learning-test-preview-pdf";
      embed.src = previewUrl;
      embed.title = slide.title || "PDF materijal";
      materialCard.append(embed);
    } else {
      const fallback = document.createElement("div");
      fallback.className = "learning-test-preview-download";
      const label = document.createElement("strong");
      label.textContent = slide.title || "Materijal";
      const copy = document.createElement("p");
      copy.textContent = "Ovaj format će se polazniku ponuditi kao datoteka za pregled ili preuzimanje.";
      const link = document.createElement("a");
      link.className = "ghost-button";
      link.href = previewUrl || "#";
      link.target = "_blank";
      link.rel = "noreferrer";
      link.textContent = "Otvori materijal";
      fallback.append(label, copy);
      if (previewUrl) {
        fallback.append(link);
      }
      materialCard.append(fallback);
    }
    stageBody.append(materialCard);
  } else if (slide.type === "question") {
    const questionCard = document.createElement("article");
    questionCard.className = "learning-test-preview-slide-card is-question";
    const prompt = document.createElement("p");
    prompt.className = "learning-test-preview-question-prompt";
    prompt.textContent = slide.prompt || "Pitanje bez teksta";
    questionCard.append(prompt);

    if (slide.imageDocument?.fileName) {
      const imagePreview = document.createElement("div");
      imagePreview.className = "learning-test-preview-question-image";
      const image = document.createElement("img");
      image.src = String(slide.imageDocument.storageUrl || slide.imageDocument.dataUrl || "").trim();
      image.alt = slide.imageDocument.fileName || "Slika pitanja";
      imagePreview.append(image);
      questionCard.append(imagePreview);
    }

    const list = document.createElement("div");
    list.className = "learning-test-preview-answer-list";
    (slide.options ?? []).forEach((option, optionIndex) => {
      const item = document.createElement("div");
      item.className = "learning-test-preview-answer";
      const badge = document.createElement("span");
      badge.className = "learning-test-preview-answer-key";
      badge.textContent = slide.questionType === "ordered_text"
        ? `${option.orderIndex || optionIndex + 1}.`
        : option.key;
      const text = document.createElement("span");
      text.textContent = option.text || `Odgovor ${option.key}`;
      item.append(badge, text);
      list.append(item);
    });
    questionCard.append(list);
    stageBody.append(questionCard);
  }

  const nav = document.createElement("div");
  nav.className = "learning-test-preview-nav";
  const prevButton = document.createElement("button");
  prevButton.type = "button";
  prevButton.className = "ghost-button";
  prevButton.textContent = "Prethodni slajd";
  prevButton.disabled = safeIndex <= 0;
  prevButton.addEventListener("click", () => {
    learningTestPreviewSlideIndex = Math.max(0, learningTestPreviewSlideIndex - 1);
    renderLearningTestPreview();
  });
  const nextButton = document.createElement("button");
  nextButton.type = "button";
  nextButton.className = "primary-button";
  nextButton.textContent = safeIndex >= slides.length - 1 ? "Zatvori preview" : "Sljedeći slajd";
  nextButton.addEventListener("click", () => {
    if (learningTestPreviewSlideIndex >= slides.length - 1) {
      closeLearningTestPreview();
      return;
    }
    learningTestPreviewSlideIndex = Math.min(slides.length - 1, learningTestPreviewSlideIndex + 1);
    renderLearningTestPreview();
  });
  nav.append(prevButton, nextButton);

  frame.append(header, stageBody, nav);
  learningTestPreviewStage.replaceChildren(frame);
}

function closeLearningTestPreview() {
  learningTestPreviewOpen = false;
  syncLearningTestPreviewModal();
}

function openLearningTestPreview(startIndex = 0) {
  learningTestPreviewSlideIndex = Math.max(0, Number(startIndex) || 0);
  learningTestPreviewOpen = true;
  syncLearningTestPreviewModal();
  renderLearningTestPreview();
}

function addLearningTestQuestion({ scrollIntoView = false } = {}) {
  const nextGroups = [...learningTestQuestionGroupDrafts];
  const targetGroup = nextGroups[0] || createEmptyLearningQuestionGroupDraft({}, 0);
  targetGroup.questions = [
    ...(targetGroup.questions ?? []),
    createEmptyLearningQuestionDraft({}, targetGroup.questions?.length ?? 0),
  ];
  nextGroups[0] = targetGroup;
  learningTestQuestionGroupDrafts = nextGroups;
  renderLearningQuestionGroupList();

  if (scrollIntoView) {
    requestAnimationFrame(() => {
      const lastCard = learningTestQuestionList?.querySelector(".learning-test-question-card:last-of-type");
      if (lastCard instanceof HTMLElement) {
        lastCard.scrollIntoView({ behavior: "smooth", block: "nearest" });
      }
    });
  }
}

function buildLearningTestPayload() {
  return {
    organizationId: state.activeOrganizationId || "",
    title: learningTestTitleInput?.value || "",
    status: learningTestStatusInput?.value || "draft",
    description: learningTestDescriptionInput?.value || "",
    handbookDocuments: learningTestMaterialDrafts.map((item) => createModuleAttachmentDraft(item)),
    videoItems: [],
    questionItems: serializeLearningQuestionGroupDrafts(),
    assignmentItems: [],
  };
}

function setLearningTestStepNavigationBusy(isBusy) {
  if (!learningTestNextStepButton) {
    return;
  }
  learningTestNextStepButton.disabled = Boolean(isBusy);
  learningTestNextStepButton.toggleAttribute("aria-busy", Boolean(isBusy));
  learningTestNextStepButton.textContent = isBusy ? "Otvaram pitanja..." : "Dalje na pitanja";
}

async function saveLearningTestDraft({ openQuestionsAfterSave = false } = {}) {
  const title = learningTestTitleInput?.value?.trim() || "";
  if (!title) {
    if (learningTestError) {
      learningTestError.textContent = "Upiši naziv grupe edukacije prije spremanja.";
    }
    learningTestTitleInput?.focus({ preventScroll: true });
    return false;
  }

  const previousStep = learningTestEditorStep;
  if (openQuestionsAfterSave) {
    setLearningTestEditorStep("questions");
    setLearningTestStepNavigationBusy(true);
  }

  const previousIds = new Set((state.learningTests ?? []).map((item) => String(item.id)));
  const previousEditingId = learningTestIdInput?.value || "";
  const isEditing = Boolean(previousEditingId);
  const path = isEditing ? `/learning-tests/${previousEditingId}` : "/learning-tests";
  const method = isEditing ? "PATCH" : "POST";

  const success = await runMutation(() => apiRequest(path, {
    method,
    body: buildLearningTestPayload(),
  }), learningTestError);

  if (openQuestionsAfterSave) {
    setLearningTestStepNavigationBusy(false);
  }

  if (!success) {
    if (openQuestionsAfterSave) {
      setLearningTestEditorStep(previousStep);
    }
    return false;
  }

  let resolvedId = previousEditingId;
  if (!resolvedId) {
    const createdCandidate = (state.learningTests ?? []).find((item) => !previousIds.has(String(item.id)))
      || (state.learningTests ?? []).find((item) => (
        String(item.title || "").trim() === title
        && String(item.description || "").trim() === String(learningTestDescriptionInput?.value || "").trim()
      ));
    resolvedId = createdCandidate?.id || "";
  }

  if (resolvedId) {
    state.activeLearningTestId = resolvedId;
    if (learningTestIdInput) {
      learningTestIdInput.value = resolvedId;
    }
  }

  syncLearningTestEditorChrome();

  return true;
}

function setLearningTestEditorStep(step = "group") {
  learningTestEditorStep = step === "questions" ? "questions" : "group";

  learningTestGroupStep?.toggleAttribute("hidden", learningTestEditorStep !== "group");
  learningTestQuestionsStep?.toggleAttribute("hidden", learningTestEditorStep !== "questions");
  learningTestStepGroupButton?.classList.toggle("is-active", learningTestEditorStep === "group");
  learningTestStepQuestionsButton?.classList.toggle("is-active", learningTestEditorStep === "questions");
}

function syncLearningTestEditorModal() {
  if (state.learningTestEditorOpen && (
    state.activeView !== "module"
    || state.activeModuleItem !== "tests"
    || !state.user
  )) {
    state.learningTestEditorOpen = false;
  }

  const isOpen = state.learningTestEditorOpen;
  learningTestEditorPanel?.classList.toggle("is-modal-open", isOpen);
  document.body.classList.toggle("is-learning-test-editor-open", isOpen);

  if (learningTestEditorPanel) {
    learningTestEditorPanel.hidden = !isOpen;
    learningTestEditorPanel.setAttribute("aria-hidden", String(!isOpen));
  }
  if (learningTestEditorBackdrop) {
    learningTestEditorBackdrop.hidden = !isOpen;
  }
  if (learningTestEditorCloseButton) {
    learningTestEditorCloseButton.hidden = !isOpen;
  }

  if (isOpen) {
    requestAnimationFrame(() => {
      learningTestEditorBody?.scrollTo({ top: 0, behavior: "auto" });
      learningTestEditorBody?.focus({ preventScroll: true });
    });
  } else {
    closeLearningTestPreview();
  }
}

function openLearningTestEditor() {
  state.learningTestEditorOpen = true;
  syncLearningTestEditorModal();
}

function closeLearningTestEditor({ reset = false } = {}) {
  state.learningTestEditorOpen = false;
  syncLearningTestEditorModal();
  if (reset) {
    resetLearningTestForm();
  }
}

function dismissLearningTestEditor() {
  closeLearningTestEditor({ reset: true });
  renderLearningTestsModule();
}

function resetLearningTestForm() {
  learningTestForm?.reset();
  state.activeLearningTestId = "";
  learningTestEditorStep = "group";
  learningTestPreviewSlideIndex = 0;
  learningTestPreviewOpen = false;
  if (learningTestIdInput) {
    learningTestIdInput.value = "";
  }
  if (learningTestStatusInput) {
    learningTestStatusInput.value = "draft";
  }
  if (learningTestError) {
    learningTestError.textContent = "";
  }
  setLearningTestMaterialDrafts([]);
  learningTestQuestionGroupDrafts = [createEmptyLearningQuestionGroupDraft({}, 0)];
  renderLearningTestMaterialList();
  renderLearningQuestionGroupList();
  syncLearningTestPreviewModal();
  syncLearningTestEditorChrome();
  setLearningTestEditorStep("group");
}

function hydrateLearningTestForm(item) {
  state.activeView = "module";
  state.activeModuleItem = "tests";
  renderActiveView();
  renderModuleView();
  state.activeLearningTestId = item.id;
  if (learningTestIdInput) {
    learningTestIdInput.value = item.id || "";
  }
  if (learningTestTitleInput) {
    learningTestTitleInput.value = item.title || "";
  }
  if (learningTestStatusInput) {
    learningTestStatusInput.value = item.status || "draft";
  }
  if (learningTestDescriptionInput) {
    learningTestDescriptionInput.value = item.description || "";
  }
  if (learningTestError) {
    learningTestError.textContent = "";
  }
  setLearningTestMaterialDrafts(item.handbookDocuments ?? []);
  learningTestQuestionGroupDrafts = buildLearningQuestionGroupDraftsFromItems(item.questionItems ?? []);
  if (learningTestQuestionGroupDrafts.length === 0) {
    learningTestQuestionGroupDrafts = [createEmptyLearningQuestionGroupDraft({}, 0)];
  }
  renderLearningTestMaterialList();
  renderLearningQuestionGroupList();
  syncLearningTestPreviewModal();
  syncLearningTestEditorChrome();
  setLearningTestEditorStep("group");
  openLearningTestEditor();
  requestAnimationFrame(() => {
    learningTestTitleInput?.focus({ preventScroll: true });
  });
}

function syncLearningTestEditorChrome() {
  if (learningTestEditorTitle) {
    learningTestEditorTitle.textContent = learningTestIdInput?.value
      ? `Uredi grupu edukacije | ${learningTestTitleInput?.value?.trim() || "Bez naziva"}`
      : "Nova grupa edukacije";
  }
  if (learningTestDeleteButton) {
    learningTestDeleteButton.hidden = !learningTestIdInput?.value;
  }
  if (learningTestNextStepButton) {
    if (!learningTestNextStepButton.disabled) {
      learningTestNextStepButton.textContent = "Dalje na pitanja";
    }
  }
}

function renderLearningQuestionGroupList() {
  if (!learningTestQuestionList) {
    return;
  }

  const baseGroup = createEmptyLearningQuestionGroupDraft(learningTestQuestionGroupDrafts?.[0] || {}, 0);
  if (!Array.isArray(baseGroup.questions) || baseGroup.questions.length === 0) {
    baseGroup.questions = [createEmptyLearningQuestionDraft({}, 0)];
  }
  learningTestQuestionGroupDrafts = [baseGroup];

  const questionList = document.createElement("div");
  questionList.className = "learning-test-question-stack";

  (baseGroup.questions ?? []).forEach((question, questionIndex) => {
    const questionCard = document.createElement("div");
    questionCard.className = "learning-test-question-card";

    const questionType = normalizeLearningQuestionTypeClient(question.questionType);

    const cardHeader = document.createElement("div");
    cardHeader.className = "learning-test-question-card-head";
    const cardHeaderCopy = document.createElement("div");
    cardHeaderCopy.className = "learning-test-question-card-copy";
    const cardTitle = document.createElement("strong");
    cardTitle.textContent = `Pitanje ${questionIndex + 1}`;
    const cardMeta = document.createElement("span");
    cardMeta.textContent = getLearningQuestionTypeLabel(questionType);
    cardHeaderCopy.append(cardTitle, cardMeta);
    const cardBadge = createBadge(question.code || `P${questionIndex + 1}`, "document-template-status-badge");
    cardHeader.append(cardHeaderCopy, cardBadge);

    const setupGrid = document.createElement("div");
    setupGrid.className = "learning-test-question-setup";

    const typeField = document.createElement("label");
    typeField.className = "field";
    const typeLabel = document.createElement("span");
    typeLabel.textContent = "Vrsta pitanja";
    const typeSelect = document.createElement("select");
    replaceSelectOptions(typeSelect, LEARNING_QUESTION_TYPE_OPTIONS, questionType);
    typeSelect.dataset.learningGroupIndex = "0";
    typeSelect.dataset.learningQuestionIndex = String(questionIndex);
    typeSelect.dataset.learningQuestionField = "questionType";
    typeField.append(typeLabel, typeSelect);

    const promptField = document.createElement("label");
    promptField.className = "field field-span-full";
    const promptLabel = document.createElement("span");
    promptLabel.textContent = `Pitanje ${questionIndex + 1}`;
    const promptInput = document.createElement("textarea");
    promptInput.rows = 2;
    promptInput.value = question.prompt || "";
    promptInput.placeholder = "Upiši pitanje";
    promptInput.dataset.learningGroupIndex = "0";
    promptInput.dataset.learningQuestionIndex = String(questionIndex);
    promptInput.dataset.learningQuestionField = "prompt";
    promptField.append(promptLabel, promptInput);
    setupGrid.append(typeField, promptField);

    const mediaRow = document.createElement("div");
    mediaRow.className = "learning-test-question-media";
    const mediaMeta = document.createElement("div");
    mediaMeta.className = "learning-test-question-media-meta";
    const mediaLabel = document.createElement("span");
    mediaLabel.className = "learning-test-question-media-label";
    mediaLabel.textContent = "Slika pitanja";
    const mediaSummary = document.createElement("span");
    mediaSummary.className = "learning-test-question-media-summary";
    mediaSummary.textContent = question.imageDocument?.fileName
      ? question.imageDocument.fileName
      : "Bez dodane slike";
    mediaMeta.append(mediaLabel, mediaSummary);

    const mediaActions = document.createElement("div");
    mediaActions.className = "learning-test-question-media-actions";
    const uploadImageButton = createActionButton(
      question.imageDocument?.fileName ? "Promijeni sliku" : "Dodaj sliku",
      "ghost-button",
      () => {
        const fileInput = document.createElement("input");
        fileInput.type = "file";
        fileInput.accept = "image/*";
        fileInput.addEventListener("change", () => {
          const file = fileInput.files?.[0];
          if (!file) {
            return;
          }
          void readFileAsDataUrl(file, `Ne mogu učitati sliku ${file.name}.`)
            .then((dataUrl) => {
              const nextGroups = [...learningTestQuestionGroupDrafts];
              const targetQuestion = nextGroups[0]?.questions?.[questionIndex];
              if (!targetQuestion) {
                return;
              }
              targetQuestion.imageDocument = createModuleAttachmentDraft({
                fileName: file.name,
                fileType: file.type || "image/*",
                fileSize: file.size || 0,
                documentCategory: "Slika pitanja",
                dataUrl,
                updatedAt: new Date().toISOString(),
              });
              learningTestQuestionGroupDrafts = nextGroups;
              renderLearningQuestionGroupList();
            })
            .catch((error) => {
              if (learningTestError) {
                learningTestError.textContent = error.message;
              }
            });
        });
        fileInput.click();
      },
    );
    mediaActions.append(uploadImageButton);

    if (question.imageDocument?.fileName) {
      const removeImageButton = createActionButton("Makni sliku", "card-button card-danger", () => {
        const nextGroups = [...learningTestQuestionGroupDrafts];
        const targetQuestion = nextGroups[0]?.questions?.[questionIndex];
        if (!targetQuestion) {
          return;
        }
        targetQuestion.imageDocument = null;
        learningTestQuestionGroupDrafts = nextGroups;
        renderLearningQuestionGroupList();
      });
      mediaActions.append(removeImageButton);
    }

    mediaRow.append(mediaMeta, mediaActions);

    if (question.imageDocument?.fileName) {
      const mediaPreview = document.createElement("div");
      mediaPreview.className = "learning-test-question-image-preview";
      const image = document.createElement("img");
      image.src = String(question.imageDocument.storageUrl || question.imageDocument.dataUrl || "").trim();
      image.alt = `Slika pitanja ${questionIndex + 1}`;
      mediaPreview.append(image);
      mediaRow.append(mediaPreview);
    }

    const answersGrid = document.createElement("div");
    answersGrid.className = "learning-test-answer-grid";

    LEARNING_QUESTION_OPTION_KEYS.forEach((letter) => {
      const optionField = document.createElement("label");
      optionField.className = "field";
      const optionLabel = document.createElement("span");
      optionLabel.textContent = `Odgovor ${letter}`;

      if (questionType === "ordered_text") {
        const row = document.createElement("div");
        row.className = "learning-test-ordered-answer-row";

        const orderInput = document.createElement("input");
        orderInput.type = "number";
        orderInput.min = "1";
        orderInput.step = "1";
        orderInput.value = question[`order${letter}`] || "";
        orderInput.placeholder = "#";
        orderInput.dataset.learningGroupIndex = "0";
        orderInput.dataset.learningQuestionIndex = String(questionIndex);
        orderInput.dataset.learningQuestionField = `order${letter}`;
        orderInput.className = "learning-test-order-input";

        const optionInput = document.createElement("input");
        optionInput.type = "text";
        optionInput.value = question[`option${letter}`] || "";
        optionInput.placeholder = `Tekst odgovora ${letter}`;
        optionInput.dataset.learningGroupIndex = "0";
        optionInput.dataset.learningQuestionIndex = String(questionIndex);
        optionInput.dataset.learningQuestionField = `option${letter}`;
        row.append(orderInput, optionInput);
        optionField.append(optionLabel, row);
      } else {
        const optionInput = document.createElement("input");
        optionInput.type = "text";
        optionInput.value = question[`option${letter}`] || "";
        optionInput.placeholder = `Tekst odgovora ${letter}`;
        optionInput.dataset.learningGroupIndex = "0";
        optionInput.dataset.learningQuestionIndex = String(questionIndex);
        optionInput.dataset.learningQuestionField = `option${letter}`;
        optionField.append(optionLabel, optionInput);
      }
      answersGrid.append(optionField);
    });

    const footer = document.createElement("div");
    footer.className = "learning-test-question-footer";

    let correctField = null;
    if (questionType === "single_choice") {
      correctField = document.createElement("label");
      correctField.className = "field";
      const correctLabel = document.createElement("span");
      correctLabel.textContent = "Točan odgovor";
      const correctSelect = document.createElement("select");
      replaceSelectOptions(correctSelect, LEARNING_QUESTION_OPTION_KEYS.map((letter) => ({
        value: letter,
        label: letter,
      })), question.correctOptionKey || "A");
      correctSelect.dataset.learningGroupIndex = "0";
      correctSelect.dataset.learningQuestionIndex = String(questionIndex);
      correctSelect.dataset.learningQuestionField = "correctOptionKey";
      correctField.append(correctLabel, correctSelect);
    } else if (questionType === "multiple_choice") {
      correctField = document.createElement("div");
      correctField.className = "field learning-test-multi-correct-field";
      const correctLabel = document.createElement("span");
      correctLabel.textContent = "Točni odgovori";
      const list = document.createElement("div");
      list.className = "learning-test-correct-multi";
      const selectedKeys = normalizeLearningQuestionCorrectKeysClient(
        question.correctOptionKeys,
        question.correctOptionKey || "A",
      );
      LEARNING_QUESTION_OPTION_KEYS.forEach((letter) => {
        const label = document.createElement("label");
        label.className = "learning-test-correct-option";
        const checkbox = document.createElement("input");
        checkbox.type = "checkbox";
        checkbox.value = letter;
        checkbox.checked = selectedKeys.includes(letter);
        checkbox.dataset.learningGroupIndex = "0";
        checkbox.dataset.learningQuestionIndex = String(questionIndex);
        checkbox.dataset.learningQuestionField = "correctOptionKeys";
        const text = document.createElement("span");
        text.textContent = letter;
        label.append(checkbox, text);
        list.append(label);
      });
      correctField.append(correctLabel, list);
    } else {
      correctField = document.createElement("div");
      correctField.className = "field learning-test-ordering-help";
      const helpLabel = document.createElement("span");
      helpLabel.textContent = "Redoslijed odgovora";
      const helpCopy = document.createElement("small");
      helpCopy.textContent = "Za ovu vrstu pitanja upiši broj ispred svakog odgovora.";
      correctField.append(helpLabel, helpCopy);
    }

    const removeQuestionButton = createActionButton("Ukloni pitanje", "card-button card-danger", () => {
      const nextGroups = [...learningTestQuestionGroupDrafts];
      nextGroups[0].questions = (nextGroups[0].questions ?? []).filter((_, index) => index !== questionIndex);
      if (nextGroups[0].questions.length === 0) {
        nextGroups[0].questions = [createEmptyLearningQuestionDraft({}, 0)];
      }
      learningTestQuestionGroupDrafts = nextGroups;
      renderLearningQuestionGroupList();
    });

    footer.append(correctField, removeQuestionButton);
    questionCard.append(cardHeader, setupGrid, mediaRow, answersGrid, footer);
    questionList.append(questionCard);
  });

  learningTestQuestionList.replaceChildren(questionList);

  if (learningTestPreviewOpen) {
    renderLearningTestPreview();
  }
}

function renderLearningTestsModule() {
  if (!learningTestsModule || !learningTestsList || !learningTestsEmpty) {
    return;
  }

  const canManageMasterData = getCanManageMasterData();
  const filters = {
    query: learningTestsSearchInput?.value?.trim() || state.learningTestsFilters.query || "",
    status: learningTestsFilterStatusInput?.value || state.learningTestsFilters.status || "all",
  };
  state.learningTestsFilters = filters;

  const allItems = sortLearningTests(state.learningTests ?? []);
  const visibleItems = sortLearningTests(filterLearningTests(state.learningTests ?? [], filters));

  if (learningTestOpenFormButton) {
    learningTestOpenFormButton.hidden = !canManageMasterData;
  }
  if (learningTestsTotalCount) {
    learningTestsTotalCount.textContent = String(allItems.length);
  }
  if (learningTestsActiveCount) {
    learningTestsActiveCount.textContent = String(allItems.filter((item) => item.status === "active").length);
  }
  if (learningTestsAssignmentCount) {
    learningTestsAssignmentCount.textContent = String(allItems.filter((item) => item.status === "draft").length);
  }
  if (learningTestsCompletedCount) {
    learningTestsCompletedCount.textContent = String(allItems.reduce((total, item) => total + (item.questionItems?.length ?? 0), 0));
  }
  if (learningTestsHelper) {
    learningTestsHelper.textContent = visibleItems.length === allItems.length
      ? `Prikazano ${visibleItems.length} grupa edukacije.`
      : `Prikazano ${visibleItems.length} od ${allItems.length} grupa edukacije.`;
  }

  learningTestsList.replaceChildren(...visibleItems.map((item) => {
    const card = document.createElement("article");
    card.className = "learning-test-card";
    if (String(item.id) === String(learningTestIdInput?.value || "")) {
      card.classList.add("is-active");
    }
    if (canManageMasterData) {
      card.tabIndex = 0;
      card.setAttribute("role", "button");
    }

    const head = document.createElement("div");
    head.className = "learning-test-card-head";
    const copy = document.createElement("div");
    copy.className = "learning-test-card-copy";
    const title = document.createElement("h4");
    title.textContent = item.title || "Bez naziva";
    const meta = document.createElement("p");
    meta.className = "learning-test-card-meta";
    meta.textContent = [
      "1 grupa edukacije",
      `${item.questionItems?.length ?? 0} pitanja`,
    ].join(" · ");
    copy.append(title, meta);

    const badges = document.createElement("div");
    badges.className = "learning-test-card-badges";
    badges.append(createBadge(
      LEARNING_TEST_STATUS_OPTIONS.find((option) => option.value === item.status)?.label || item.status || "Skica",
      item.status === "active" ? "document-template-status-badge is-active" : "document-template-status-badge is-draft",
    ));
    head.append(copy, badges);

    const description = document.createElement("p");
    description.className = "learning-test-card-description";
    description.textContent = item.description || "Bez dodatnog opisa.";

    const openItem = () => {
      if (!canManageMasterData) {
        return;
      }
      hydrateLearningTestForm(item);
    };

    if (canManageMasterData) {
      card.addEventListener("click", openItem);
      card.addEventListener("keydown", (event) => {
        if (event.key !== "Enter" && event.key !== " ") {
          return;
        }
        event.preventDefault();
        openItem();
      });
    }

    card.append(head, description);
    return card;
  }));

  learningTestsEmpty.hidden = visibleItems.length !== 0;
  if (visibleItems.length === 0) {
    const empty = document.createElement("div");
    empty.className = "offers-empty-card";
    empty.textContent = canManageMasterData
      ? "Nema grupa edukacije za odabrane filtere. Dodaj prvu grupu i u drugom koraku složi pitanja."
      : "Nema grupa edukacije za prikaz u odabranoj organizaciji.";
    learningTestsList.replaceChildren(empty);
  }
}

function renderLearningPeopleModule() {
  if (!learningPeopleModule || !learningPeopleList || !learningPeopleEmpty) {
    return;
  }

  const rows = (state.learningTests ?? []).flatMap((test) => (
    (test.assignmentItems ?? []).map((assignment) => ({
      testTitle: test.title || "Bez naziva testa",
      userLabel: assignment.userLabel || assignment.email || "Nepoznat korisnik",
      status: assignment.status || "pending",
      scorePercent: assignment.scorePercent ?? 0,
    }))
  ));

  learningPeopleList.replaceChildren(...rows.map((entry) => {
    const card = document.createElement("article");
    card.className = "learning-person-card";
    const title = document.createElement("strong");
    title.textContent = entry.userLabel;
    const meta = document.createElement("span");
    meta.textContent = `${entry.testTitle} · ${entry.status} · ${entry.scorePercent}%`;
    card.append(title, meta);
    return card;
  }));

  learningPeopleEmpty.hidden = rows.length !== 0;
  if (rows.length === 0) {
    learningPeopleList.replaceChildren();
  }
}

function toggleDocumentTemplateRuntimeBlockCollapsed(block = {}, blockIndex = 0) {
  setDocumentTemplateRuntimeBlockCollapsed(
    block,
    blockIndex,
    !isDocumentTemplateRuntimeBlockCollapsed(block, blockIndex),
  );
}

function renderDocumentTemplateRuntimeFieldRows() {
  if (!documentTemplateCustomFields) {
    return;
  }

  documentTemplateMeasurementInlineHosts = new Map();
  const activeWorkOrder = getDocumentTemplateRuntimeActiveWorkOrder();
  const template = buildDocumentTemplateDraft();
  const context = buildDocumentTemplatePreviewContext(template);
  const sequenceState = getDocumentTemplateRuntimeSequenceState();
  const shell = document.createElement("div");
  shell.className = "document-template-runtime-shell";

  if (sequenceState?.isSummary) {
    const groupedEntries = groupDocumentTemplateRuntimeDockEntries(sequenceState.entries);
    const signatureMode = normalizeDocumentTemplateSignatureMethod(state.documentTemplateRuntime.common?.signatureMode);

    const summaryBlock = document.createElement("section");
    summaryBlock.className = "document-template-runtime-block document-template-runtime-summary-block";

    const summaryHead = document.createElement("div");
    summaryHead.className = "document-template-runtime-block-head";
    const summaryHeadCopy = document.createElement("div");
    const summaryTitle = document.createElement("h4");
    summaryTitle.textContent = "Summary";
    const summaryMeta = document.createElement("p");
    summaryMeta.className = "document-template-runtime-block-meta";
    summaryMeta.textContent = "Završni korak za pregled batcha, odabir potpisa i preuzimanje gotovih dokumenata.";
    summaryHeadCopy.append(summaryTitle, summaryMeta);
    summaryHead.append(summaryHeadCopy);

    const summaryBody = document.createElement("div");
    summaryBody.className = "document-template-runtime-block-body document-template-runtime-summary-body";

    const batchCard = document.createElement("article");
    batchCard.className = "document-template-runtime-summary-card";
    const batchCardTitle = document.createElement("strong");
    batchCardTitle.textContent = "Pregled batcha";
    const batchCardMeta = document.createElement("p");
    batchCardMeta.className = "helper-copy module-copy";
    batchCardMeta.textContent = `${groupedEntries.length} ${groupedEntries.length === 1 ? "RN" : "RN-a"} · ${sequenceState.itemTotal} ${sequenceState.itemTotal === 1 ? "zapisnik" : "zapisnika"} spremno za završetak.`;
    batchCard.append(batchCardTitle, batchCardMeta);

    const signatureCard = document.createElement("article");
    signatureCard.className = "document-template-runtime-summary-card";
    const signatureCardTitle = document.createElement("strong");
    signatureCardTitle.textContent = "Način potpisa";
    const signatureCardMeta = document.createElement("p");
    signatureCardMeta.className = "helper-copy module-copy";
    signatureCardMeta.textContent = signatureMode === "digital"
      ? "Odabran je digitalni potpis za završni export batcha."
      : "Odabran je scan potpisa za završni export batcha.";
    const signatureActions = document.createElement("div");
    signatureActions.className = "document-template-runtime-summary-actions";
    const scanButton = document.createElement("button");
    scanButton.type = "button";
    scanButton.className = "ghost-button";
    scanButton.textContent = "Scan potpisa";
    scanButton.classList.toggle("is-active", signatureMode === "scan");
    scanButton.addEventListener("click", () => {
      updateDocumentTemplateRuntimeCommon({ signatureMode: "scan" }, { render: true });
      renderDocumentTemplateRuntimeContext();
      renderDocumentTemplatePreviewContent();
    });
    const digitalButton = document.createElement("button");
    digitalButton.type = "button";
    digitalButton.className = "ghost-button";
    digitalButton.textContent = "Digitalni potpis";
    digitalButton.classList.toggle("is-active", signatureMode === "digital");
    digitalButton.addEventListener("click", () => {
      updateDocumentTemplateRuntimeCommon({ signatureMode: "digital" }, { render: true });
      renderDocumentTemplateRuntimeContext();
      renderDocumentTemplatePreviewContent();
    });
    signatureActions.append(scanButton, digitalButton);
    signatureCard.append(signatureCardTitle, signatureCardMeta, signatureActions);

    const exportCard = document.createElement("article");
    exportCard.className = "document-template-runtime-summary-card";
    const exportCardTitle = document.createElement("strong");
    exportCardTitle.textContent = "Preuzimanje";
    const exportCardMeta = document.createElement("p");
    exportCardMeta.className = "helper-copy module-copy";
    exportCardMeta.textContent = "Word i PDF koriste isti Word predložak. Završni export radi tek nakon što pregledaš sve zapisnike.";
    const exportActions = document.createElement("div");
    exportActions.className = "document-template-runtime-summary-actions";
    const wordButton = document.createElement("button");
    wordButton.type = "button";
    wordButton.className = "ghost-button";
    wordButton.textContent = "Preuzmi Word";
    wordButton.addEventListener("click", () => {
      void exportDocumentTemplateWord({ placeholderMode: false });
    });
    const pdfButton = document.createElement("button");
    pdfButton.type = "button";
    pdfButton.className = "ghost-button";
    pdfButton.textContent = "Preuzmi PDF";
    pdfButton.addEventListener("click", () => {
      void exportDocumentTemplatePdf();
    });
    const printAllButton = document.createElement("button");
    printAllButton.type = "button";
    printAllButton.className = "ghost-button";
    printAllButton.textContent = "Ispiši sve";
    printAllButton.hidden = sequenceState.itemTotal <= 1;
    printAllButton.addEventListener("click", () => {
      void exportDocumentTemplateBatchPdf({ print: true });
    });
    const sendSignatureButton = document.createElement("button");
    sendSignatureButton.type = "button";
    sendSignatureButton.className = "ghost-button";
    sendSignatureButton.textContent = "Pošalji na digitalni potpis";
    sendSignatureButton.hidden = signatureMode !== "digital";
    sendSignatureButton.addEventListener("click", () => {
      void queueDocumentTemplateForDigitalSignature();
    });
    exportActions.append(wordButton, pdfButton, printAllButton, sendSignatureButton);
    exportCard.append(exportCardTitle, exportCardMeta, exportActions);

    const groupedList = document.createElement("div");
    groupedList.className = "document-template-runtime-summary-list";
    groupedEntries.forEach((group) => {
      const entryCard = document.createElement("article");
      entryCard.className = "document-template-runtime-summary-entry";
      const entryTitle = document.createElement("strong");
      entryTitle.textContent = `RN ${group.workOrderNumber}`;
      const firstItem = group.items[0] || {};
      const entryMeta = document.createElement("span");
      entryMeta.textContent = [
        firstItem.companyName || "",
        firstItem.locationName || "",
        `${group.items.length} ${group.items.length === 1 ? "zapisnik" : "zapisnika"}`,
      ].filter(Boolean).join(" · ") || "Povezani zapisnici";
      const entryChips = document.createElement("div");
      entryChips.className = "document-template-runtime-summary-entry-chips";
      group.items.forEach((entry) => {
        entryChips.append(createBadge(entry.timelineLabel, "document-template-meta-badge"));
      });
      entryCard.append(entryTitle, entryMeta, entryChips);
      groupedList.append(entryCard);
    });

    summaryBody.append(batchCard, signatureCard, exportCard, groupedList);
    summaryBlock.append(summaryHead, summaryBody);
    shell.append(summaryBlock);
    documentTemplateCustomFields.replaceChildren(shell);

    const shouldCloseRuntimeSheet = state.measurementSheet.ownerKind === "document_template_runtime_field";
    if (shouldCloseRuntimeSheet) {
      setMeasurementSheetOpen(false);
      state.measurementSheet.ownerKind = "work_order";
      state.measurementSheet.ownerFieldId = "";
      state.measurementSheet.ownerRuntimeWorkOrderId = "";
      syncMeasurementToolbar();
    }

    syncMeasurementSheetPanelMount();
    syncDocumentTemplateInlineExcelPreviewVisibility();
    renderDocumentTemplatePreviewContent();
    return;
  }

  if (!activeWorkOrder) {
    const empty = document.createElement("p");
    empty.className = "helper-copy module-copy";
    empty.textContent = "Odaberi RN kako bi otvorio predložak za unos zapisnika.";
    shell.append(empty);
    documentTemplateCustomFields.replaceChildren(shell);
    return;
  }

  const visibleBlocks = buildDocumentTemplateRuntimeBlockGroups(documentTemplateFieldDrafts);
  if (visibleBlocks.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy module-copy";
    empty.textContent = "Ovaj template nema dodatnih polja za ručni unos. Podaci se povlače iz RN-a i povezanih izvora.";
    shell.append(empty);
    documentTemplateCustomFields.replaceChildren(shell);
    return;
  }

  const createFieldTitle = (field, fallbackIndex) => field.label || field.wordLabel || `Polje ${fallbackIndex + 1}`;

  const createPersistedFieldSourcePicker = (field, workOrder, { kind = "value" } = {}) => {
    if (!workOrder || !isDocumentTemplateRuntimePersistedField(field)) {
      return null;
    }

    void ensureDocumentTemplatePreviousRecordOptions(template, workOrder);

    const suggestionState = getDocumentTemplatePreviousRecordFieldCandidates(field, workOrder, template, { kind });
    if (suggestionState.candidates.length === 0 && suggestionState.status !== "loading" && !suggestionState.error) {
      return null;
    }

    const picker = document.createElement("div");
    picker.className = "document-template-runtime-source-picker";

    const pickerLabel = document.createElement("small");
    pickerLabel.className = "document-template-runtime-source-label";
    pickerLabel.textContent = kind === "sheet"
      ? "Izvor tablice"
      : "Izvor vrijednosti";

    const optionList = document.createElement("div");
    optionList.className = "document-template-runtime-source-options";

    const selectedSourceId = getDocumentTemplateRuntimeFieldSource(workOrder.id, field.id)
      || suggestionState.candidates[0]?.id
      || "";

    if (suggestionState.status === "loading" && suggestionState.candidates.length <= 1) {
      const loading = document.createElement("span");
      loading.className = "document-template-runtime-source-empty";
      loading.textContent = "Učitavam stare zapisnike...";
      optionList.append(loading);
    } else if (suggestionState.candidates.length === 0) {
      const empty = document.createElement("span");
      empty.className = "document-template-runtime-source-empty";
      empty.textContent = suggestionState.error || "Nema ranijih zapisnika za ovu tvrtku i lokaciju.";
      optionList.append(empty);
    } else {
      suggestionState.candidates.forEach((candidate, candidateIndex) => {
        const optionButton = document.createElement("button");
        optionButton.type = "button";
        optionButton.className = "document-template-runtime-source-option";
        if (candidate.id === selectedSourceId) {
          optionButton.classList.add("is-active");
        } else if (!selectedSourceId && candidateIndex === 0 && String(candidate.id || "").startsWith("record:")) {
          optionButton.classList.add("is-primary");
        }
        optionButton.title = kind === "sheet"
          ? String(candidate.meta || candidate.label || "").trim()
          : formatDocumentTemplateLookupResolvedValue(candidate.value);

        const label = document.createElement("strong");
        label.textContent = candidate.label;
        const meta = document.createElement("span");
        meta.textContent = candidate.meta || (kind === "sheet"
          ? "Excel tablica"
          : formatDocumentTemplateLookupResolvedValue(candidate.value));

        optionButton.append(label, meta);
        optionButton.addEventListener("click", () => {
          applyDocumentTemplateRuntimePersistedFieldCandidate(workOrder.id, field, candidate.id, template, {
            kind,
            render: true,
          });
        });
        optionList.append(optionButton);
      });
    }

    const helper = document.createElement("small");
    helper.className = "document-template-runtime-field-help";
    helper.textContent = kind === "sheet"
      ? "Najprije nudi zadnju spremljenu tablicu, zatim starije verzije, pa početnu tablicu iz templatea."
      : "Najprije nudi najnoviji stari zapisnik, zatim starije varijante, pa template fallback.";

    picker.append(pickerLabel, optionList, helper);
    return picker;
  };

  const createStandardFieldControl = (field, workOrderId, workOrder = null) => {
    const wrapper = document.createElement("label");
    wrapper.className = field.type === "longtext" ? "field field-span-full" : "field";
    const title = document.createElement("span");
    title.textContent = createFieldTitle(field, 0);
    wrapper.append(title);

    const sourcePicker = createPersistedFieldSourcePicker(field, workOrder, { kind: "value" });
    if (sourcePicker) {
      wrapper.append(sourcePicker);
    }

    let control;
    if (field.type === "longtext") {
      const fieldHeight = normalizeDocumentTemplateFieldHeight(field.fieldHeight, field.type || "longtext");
      control = document.createElement("textarea");
      control.rows = fieldHeight;
      control.style.minHeight = `${Math.max(120, fieldHeight * 28)}px`;
      control.value = String(getDocumentTemplateRuntimeInitialValue(field, workOrderId) ?? "");
      control.addEventListener("input", (event) => {
        setDocumentTemplateRuntimeFieldValue(workOrderId, field.id, String(event.currentTarget.value ?? ""), { render: false });
        renderDocumentTemplatePreviewContent();
      });
    } else if (field.type === "date") {
      control = document.createElement("input");
      control.type = "date";
      control.value = String(getDocumentTemplateRuntimeInitialValue(field, workOrderId) ?? "");
      control.addEventListener("input", (event) => {
        setDocumentTemplateRuntimeFieldValue(workOrderId, field.id, String(event.currentTarget.value ?? ""), { render: false });
        renderDocumentTemplatePreviewContent();
      });
    } else if (field.type === "checkbox" || field.type === "toggle") {
      const toggleWrap = document.createElement("label");
      toggleWrap.className = "document-template-runtime-checkbox";
      const checkbox = document.createElement("input");
      checkbox.type = "checkbox";
      checkbox.checked = Boolean(getDocumentTemplateRuntimeInitialValue(field, workOrderId));
      checkbox.addEventListener("change", (event) => {
        setDocumentTemplateRuntimeFieldValue(workOrderId, field.id, Boolean(event.currentTarget.checked), { render: false });
        renderDocumentTemplatePreviewContent();
      });
      const copy = document.createElement("span");
      copy.textContent = getDocumentTemplateBooleanDisplayValue(field, checkbox.checked);
      checkbox.addEventListener("change", () => {
        copy.textContent = getDocumentTemplateBooleanDisplayValue(field, checkbox.checked);
      });
      toggleWrap.append(checkbox, copy);
      control = toggleWrap;
    } else {
      control = document.createElement("input");
      control.type = "text";
      if (field.type === "number") {
        control.inputMode = "decimal";
      }
      control.value = String(getDocumentTemplateRuntimeInitialValue(field, workOrderId) ?? "");
      control.addEventListener("input", (event) => {
        setDocumentTemplateRuntimeFieldValue(workOrderId, field.id, String(event.currentTarget.value ?? ""), { render: false });
        renderDocumentTemplatePreviewContent();
      });
    }

    const customFieldHeight = getDocumentTemplateBuilderFieldHeightPx(field, { preserveAuto: true });
    if (customFieldHeight > 0) {
      wrapper.style.minHeight = `${customFieldHeight}px`;
      if (control instanceof HTMLTextAreaElement) {
        control.style.minHeight = `${Math.max(120, customFieldHeight - 44)}px`;
      } else if (control instanceof HTMLInputElement) {
        control.style.minHeight = `${Math.max(52, customFieldHeight - 52)}px`;
      } else if (control instanceof HTMLElement) {
        control.style.minHeight = `${Math.max(52, customFieldHeight - 40)}px`;
      }
    }

    wrapper.append(control);
    if (field.helpText) {
      const helper = document.createElement("small");
      helper.className = "document-template-runtime-field-help";
      helper.textContent = field.helpText;
      wrapper.append(helper);
    }
    return wrapper;
  };

  const createInspectorsFieldControl = (field, workOrder) => {
    const wrapper = document.createElement("label");
    wrapper.className = "field field-span-full";
    const title = document.createElement("span");
    title.textContent = createFieldTitle(field, 0);
    const area = field.signatureArea || "elektro";
    const picker = createWorkOrderDocumentSignaturePersonPicker({
      capability: "inspect",
      signatureArea: area,
      multiple: true,
      value: getDocumentTemplateRuntimeArrayValue(
        workOrder.id,
        getWorkOrderDocumentSignaturePersonListFieldName("inspect", area) || "inspectorUserIds",
      ),
      emptyLabel: "Odaberi ispitivače",
      onChange: (nextValues) => {
        const normalizedValues = normalizeQualifiedUserIdList(nextValues);
        const listFieldName = getWorkOrderDocumentSignaturePersonListFieldName("inspect", area) || "inspectorUserIds";
        const fieldName = getWorkOrderDocumentSignaturePersonFieldName("inspect", area) || "inspectorUserId";
        updateDocumentTemplateRuntimeOverride(workOrder.id, {
          [listFieldName]: normalizedValues,
          [fieldName]: normalizedValues[0] || "",
          inspectorUserIds: normalizedValues,
          inspectorUserId: normalizedValues[0] || "",
        }, { render: false });
        syncDocumentTemplateEditorChrome();
        renderDocumentTemplatePreviewContent();
      },
    });
    wrapper.append(title, picker);
    if (field.helpText) {
      const helper = document.createElement("small");
      helper.className = "document-template-runtime-field-help";
      helper.textContent = field.helpText;
      wrapper.append(helper);
    }
    return wrapper;
  };

  const createLegalListFieldControl = (field, workOrder, templateDraft) => {
    const shellNode = document.createElement("div");
    shellNode.className = "document-template-runtime-legal-field";

    const title = document.createElement("strong");
    title.textContent = createFieldTitle(field, 0);
    shellNode.append(title);

    const frameworks = getDocumentTemplateLegalFrameworksForField(templateDraft, field, { selectedOnly: false });
    const selectedIds = new Set(getDocumentTemplateRuntimeSelectedLegalFrameworkIds(workOrder.id, field));

    if (frameworks.length === 0) {
      const empty = document.createElement("p");
      empty.className = "helper-copy module-copy";
      empty.textContent = "Nema dostupnih propisa za ovaj blok.";
      shellNode.append(empty);
      return shellNode;
    }

    const list = document.createElement("div");
    list.className = "document-template-runtime-checklist";
    frameworks.forEach((framework) => {
      const option = document.createElement("label");
      option.className = "document-template-runtime-checklist-item";
      const checkbox = document.createElement("input");
      checkbox.type = "checkbox";
      checkbox.value = String(framework.id);
      checkbox.checked = selectedIds.has(String(framework.id));
      checkbox.addEventListener("change", () => {
        const nextValues = Array.from(list.querySelectorAll('input[type="checkbox"]'))
          .filter((input) => input instanceof HTMLInputElement && input.checked)
          .map((input) => String(input.value || "").trim())
          .filter(Boolean);
        setDocumentTemplateRuntimeFieldValue(workOrder.id, field.id, nextValues, { render: false });
        renderDocumentTemplatePreviewContent();
      });
      const copy = document.createElement("span");
      copy.textContent = framework.title || "Propis";
      option.append(checkbox, copy);
      list.append(option);
    });

    shellNode.append(list);
    if (field.helpText) {
      const helper = document.createElement("small");
      helper.className = "document-template-runtime-field-help";
      helper.textContent = field.helpText;
      shellNode.append(helper);
    }
    return shellNode;
  };

  const createEquipmentFieldControl = (field, workOrder, templateDraft) => {
    const shellNode = document.createElement("div");
    shellNode.className = "document-template-runtime-legal-field document-template-runtime-equipment-field";
    const title = document.createElement("strong");
    title.textContent = createFieldTitle(field, 0);
    shellNode.append(title);

    const equipmentItems = getDocumentTemplateLinkedEquipmentItems(templateDraft);
    const selectedIds = new Set(
      getDocumentTemplateRuntimeSelectedEquipmentIds(workOrder.id, field, templateDraft),
    );

    if (equipmentItems.length === 0) {
      const empty = document.createElement("p");
      empty.className = "helper-copy module-copy";
      empty.textContent = "Nema ponuđene opreme povezane s ovim templateom.";
      shellNode.append(empty);
      return shellNode;
    }

    const list = document.createElement("div");
    list.className = "document-template-runtime-checklist";

    const syncSelection = () => {
      const nextValues = Array.from(list.querySelectorAll('input[type="checkbox"]'))
        .filter((input) => input instanceof HTMLInputElement && input.checked)
        .map((input) => String(input.value || "").trim())
        .filter(Boolean);
      setDocumentTemplateRuntimeFieldValue(workOrder.id, field.id, nextValues, { render: false });
      renderDocumentTemplatePreviewContent();
    };

    equipmentItems.forEach((item) => {
      const option = document.createElement("label");
      option.className = "document-template-runtime-checklist-item";

      const checkbox = document.createElement("input");
      checkbox.type = "checkbox";
      checkbox.value = String(item.id || "");
      checkbox.checked = selectedIds.has(String(item.id || ""));
      checkbox.addEventListener("change", syncSelection);

      const copy = document.createElement("div");
      copy.className = "document-template-runtime-checklist-item-copy";

      const primary = document.createElement("strong");
      primary.textContent = item.name || item.inventoryNumber || item.code || "Uređaj";

      const metaParts = [
        item.deviceType || item.code || "",
        item.inventoryNumber ? `Inv. ${item.inventoryNumber}` : "",
        item.manufacturer || "",
      ].filter(Boolean);

      copy.append(primary);
      if (metaParts.length > 0) {
        const meta = document.createElement("span");
        meta.className = "document-template-runtime-checklist-meta";
        meta.textContent = metaParts.join(" · ");
        copy.append(meta);
      }

      option.append(checkbox, copy);
      list.append(option);
    });

    shellNode.append(list);
    const helper = document.createElement("small");
    helper.className = "document-template-runtime-field-help";
    helper.textContent = field.helpText || "Odaberi uređaje koji ulaze u ovaj zapisnik.";
    shellNode.append(helper);
    return shellNode;
  };

  const createSystemDescriptionFieldControl = (field, workOrder) => {
    const shellNode = document.createElement("div");
    shellNode.className = "document-template-runtime-system-description-field";

    const model = normalizeDocumentTemplateSystemDescriptionRuntimeValue(
      field,
      getDocumentTemplateRuntimeInitialValue(field, workOrder.id),
    );

    const titleBar = document.createElement("div");
    titleBar.className = "document-template-runtime-system-title";
    titleBar.textContent = createFieldTitle(field, 0);
    shellNode.append(titleBar);

    const sourcePicker = createPersistedFieldSourcePicker(field, workOrder, { kind: "value" });
    if (sourcePicker) {
      shellNode.append(sourcePicker);
    }

    const blocksHead = document.createElement("div");
    blocksHead.className = "document-template-runtime-system-blocks-head";

    const blocksCopy = document.createElement("div");
    blocksCopy.className = "document-template-runtime-system-blocks-copy";
    const blocksTitle = document.createElement("strong");
    blocksTitle.textContent = "Blokovi sustava";
    const blocksMeta = document.createElement("span");
    blocksMeta.textContent = "Dodaj više blokova i u svakom uređuj naslov, uvod i retke.";
    blocksCopy.append(blocksTitle, blocksMeta);

    const createBlankRow = (initial = {}, index = 0) => createEmptyDocumentTemplateSystemDescriptionRowDraft({
      subtitle: "",
      description: "",
      lineCount: 1,
      placeholder: "Upiši sadržaj retka...",
      ...initial,
      description: "",
    }, index);

    const createBlankBlock = (index = 0) => {
      const templateRows = normalizeDocumentTemplateSystemDescriptionRows(
        field.systemRows,
        {
          ensureOne: true,
          fallbackRows: createDefaultDocumentTemplateSystemDescriptionRows(),
        },
      );
      return createDocumentTemplateSystemDescriptionBlockDraft({
        title: field.label || field.wordLabel || `Opis sustava ${index + 1}`,
        sectionSubtitle: "",
        rows: templateRows.map((templateRow, rowIndex) => createBlankRow(templateRow, rowIndex)),
      }, field, index);
    };

    const syncValue = () => {
      setDocumentTemplateRuntimeFieldValue(
        workOrder.id,
        field.id,
        {
          blocks: model.blocks.map((block, blockIndex) => ({
            id: block.id || `system-description-block-${blockIndex + 1}`,
            title: block.title || "",
            sectionSubtitle: block.sectionSubtitle || "",
            rows: (Array.isArray(block.rows) ? block.rows : []).map((row, rowIndex) => ({
              id: row.id || `system-description-row-${blockIndex + 1}-${rowIndex + 1}`,
              subtitle: row.subtitle || "",
              description: row.description || "",
              lineCount: normalizeDocumentTemplateSystemDescriptionLineCount(row.lineCount),
              placeholder: row.placeholder || "",
            })),
          })),
        },
        { render: false },
      );
      renderDocumentTemplatePreviewContent();
    };

    const addBlockButton = createActionButton("Dodaj blok", "ghost-button", () => {
      model.blocks.push(createBlankBlock(model.blocks.length));
      syncValue();
      renderDocumentTemplateFieldRows();
      renderDocumentTemplatePreviewContent();
    });
    blocksHead.append(blocksCopy, addBlockButton);
    shellNode.append(blocksHead);

    const blocksWrap = document.createElement("div");
    blocksWrap.className = "document-template-runtime-system-blocks";

    model.blocks.forEach((block, blockIndex) => {
      const blockCard = document.createElement("article");
      blockCard.className = "document-template-runtime-system-block";

      const blockHeader = document.createElement("div");
      blockHeader.className = "document-template-runtime-system-block-head";

      const blockBadge = document.createElement("span");
      blockBadge.className = "document-template-runtime-system-block-badge";
      blockBadge.textContent = `Blok ${blockIndex + 1}`;

      const blockActions = document.createElement("div");
      blockActions.className = "document-template-runtime-system-block-actions";
      const addRowButton = createActionButton("Dodaj red", "ghost-button", () => {
        block.rows = [
          ...(Array.isArray(block.rows) ? block.rows : []),
          createBlankRow({}, block.rows?.length || 0),
        ];
        syncValue();
        renderDocumentTemplateFieldRows();
        renderDocumentTemplatePreviewContent();
      });
      const removeBlockButton = createActionButton("Makni blok", "ghost-button", () => {
        model.blocks = model.blocks.filter((_, currentIndex) => currentIndex !== blockIndex);
        if (model.blocks.length === 0) {
          model.blocks = [createBlankBlock(0)];
        }
        syncValue();
        renderDocumentTemplateFieldRows();
        renderDocumentTemplatePreviewContent();
      });
      removeBlockButton.disabled = model.blocks.length <= 1;
      blockActions.append(addRowButton, removeBlockButton);
      blockHeader.append(blockBadge, blockActions);
      blockCard.append(blockHeader);

      const blockMetaGrid = document.createElement("div");
      blockMetaGrid.className = "document-template-runtime-system-block-meta";

      const blockTitleField = document.createElement("label");
      blockTitleField.className = "field";
      const blockTitleSpan = document.createElement("span");
      blockTitleSpan.textContent = "Naslov bloka";
      const blockTitleInput = document.createElement("input");
      blockTitleInput.type = "text";
      blockTitleInput.value = block.title || "";
      blockTitleInput.placeholder = "npr. DETEKTOR POŽARA - RUČNI";
      blockTitleInput.addEventListener("input", (event) => {
        model.blocks[blockIndex].title = String(event.currentTarget.value ?? "");
        syncValue();
      });
      blockTitleField.append(blockTitleSpan, blockTitleInput);

      const blockSubtitleField = document.createElement("label");
      blockSubtitleField.className = "field";
      const blockSubtitleSpan = document.createElement("span");
      blockSubtitleSpan.textContent = "Uvod / opis bloka";
      const blockSubtitleInput = document.createElement("input");
      blockSubtitleInput.type = "text";
      blockSubtitleInput.value = block.sectionSubtitle || "";
      blockSubtitleInput.placeholder = "Kratki uvod ili dodatni opis za ovaj blok";
      blockSubtitleInput.addEventListener("input", (event) => {
        model.blocks[blockIndex].sectionSubtitle = String(event.currentTarget.value ?? "");
        syncValue();
      });
      blockSubtitleField.append(blockSubtitleSpan, blockSubtitleInput);
      blockMetaGrid.append(blockTitleField, blockSubtitleField);
      blockCard.append(blockMetaGrid);

      const rowsWrap = document.createElement("div");
      rowsWrap.className = "document-template-runtime-system-rows";

      (Array.isArray(block.rows) ? block.rows : []).forEach((row, rowIndex) => {
        const rowCard = document.createElement("article");
        rowCard.className = "document-template-runtime-system-row";

        const rowMeta = document.createElement("div");
        rowMeta.className = "document-template-runtime-system-row-meta";

        const rowSubtitleField = document.createElement("label");
        rowSubtitleField.className = "field";
        const rowSubtitleSpan = document.createElement("span");
        rowSubtitleSpan.textContent = "Podnaslov";
        const rowSubtitleInput = document.createElement("input");
        rowSubtitleInput.type = "text";
        rowSubtitleInput.value = row.subtitle || "";
        rowSubtitleInput.placeholder = "npr. Proizvođač";
        rowSubtitleInput.addEventListener("input", (event) => {
          model.blocks[blockIndex].rows[rowIndex].subtitle = String(event.currentTarget.value ?? "");
          syncValue();
        });
        rowSubtitleField.append(rowSubtitleSpan, rowSubtitleInput);

        const rowLineField = document.createElement("label");
        rowLineField.className = "field";
        const rowLineSpan = document.createElement("span");
        rowLineSpan.textContent = "Visina retka";
        const rowLineSelect = document.createElement("select");
        rowLineSelect.className = "document-template-source-select";
        replaceSelectOptions(
          rowLineSelect,
          DOCUMENT_TEMPLATE_SYSTEM_DESCRIPTION_LINE_OPTIONS,
          String(normalizeDocumentTemplateSystemDescriptionLineCount(row.lineCount)),
        );
        rowLineSelect.addEventListener("change", () => {
          model.blocks[blockIndex].rows[rowIndex].lineCount = normalizeDocumentTemplateSystemDescriptionLineCount(rowLineSelect.value);
          syncValue();
          renderDocumentTemplateFieldRows();
          renderDocumentTemplatePreviewContent();
        });
        rowLineField.append(rowLineSpan, rowLineSelect);

        const removeRowButton = createActionButton("Makni red", "ghost-button", () => {
          model.blocks[blockIndex].rows = model.blocks[blockIndex].rows.filter((_, currentIndex) => currentIndex !== rowIndex);
          if (model.blocks[blockIndex].rows.length === 0) {
            model.blocks[blockIndex].rows = [createBlankRow({}, 0)];
          }
          syncValue();
          renderDocumentTemplateFieldRows();
          renderDocumentTemplatePreviewContent();
        });
        removeRowButton.classList.add("document-template-runtime-system-row-remove");
        removeRowButton.disabled = (Array.isArray(block.rows) ? block.rows.length : 0) <= 1;
        rowMeta.append(rowSubtitleField, rowLineField, removeRowButton);

        const controlWrap = document.createElement("div");
        controlWrap.className = "document-template-runtime-system-row-control";
        const control = document.createElement("textarea");
        const lineCount = normalizeDocumentTemplateSystemDescriptionLineCount(row.lineCount);
        control.rows = lineCount;
        control.style.minHeight = `${Math.max(64, lineCount * 32)}px`;
        control.value = row.description || "";
        control.placeholder = row.placeholder || (row.subtitle
          ? `Upiši ${String(row.subtitle || "").trim().toLowerCase()}`
          : "Dodaj opis sustava...");
        control.addEventListener("input", (event) => {
          model.blocks[blockIndex].rows[rowIndex].description = String(event.currentTarget.value ?? "");
          syncValue();
        });

        controlWrap.append(control);
        rowCard.append(rowMeta, controlWrap);
        rowsWrap.append(rowCard);
      });

      blockCard.append(rowsWrap);
      blocksWrap.append(blockCard);
    });

    shellNode.append(blocksWrap);

    if (field.helpText) {
      const helper = document.createElement("small");
      helper.className = "document-template-runtime-field-help";
      helper.textContent = field.helpText;
      shellNode.append(helper);
    }

    return shellNode;
  };

  const createMediaFieldControl = (field, workOrder) => {
    const shellNode = document.createElement("div");
    shellNode.className = "document-template-runtime-media-field";

    const title = document.createElement("strong");
    title.textContent = createFieldTitle(field, 0);

    const sourcePicker = createPersistedFieldSourcePicker(field, workOrder, { kind: "value" });
    const currentValue = normalizeDocumentTemplateMediaFieldValue(
      getDocumentTemplateRuntimeInitialValue(field, workOrder.id),
    );

    const fileInput = document.createElement("input");
    fileInput.type = "file";
    fileInput.accept = getDocumentTemplateMediaFieldAccept(field.type);
    fileInput.hidden = true;

    const dropzone = document.createElement("button");
    dropzone.type = "button";
    dropzone.className = "work-order-document-dropzone is-compact document-template-runtime-media-dropzone";

    const mark = document.createElement("span");
    mark.className = "work-order-document-dropzone-mark";
    mark.textContent = String(field.type || "").trim().toLowerCase() === "sketch_upload" ? "SK" : "IMG";

    const dropzoneCopy = document.createElement("span");
    dropzoneCopy.className = "work-order-document-dropzone-copy";
    const dropzoneTitle = document.createElement("strong");
    dropzoneTitle.textContent = currentValue
      ? "Zamijeni datoteku"
      : `Dodaj ${getDocumentTemplateMediaFieldKindLabel(field.type).toLowerCase()}`;
    const dropzoneSubtitle = document.createElement("span");
    dropzoneSubtitle.textContent = "Klikni za odabir datoteke ili je povuci ovdje.";
    dropzoneCopy.append(dropzoneTitle, dropzoneSubtitle);
    dropzone.append(mark, dropzoneCopy);

    const previewCard = document.createElement("div");
    previewCard.className = "document-template-runtime-media-preview";

    const renderPreview = (value = null) => {
      const mediaValue = normalizeDocumentTemplateMediaFieldValue(value);
      previewCard.replaceChildren();

      if (!mediaValue) {
        const empty = document.createElement("p");
        empty.className = "helper-copy module-copy";
        empty.textContent = `Još nema dodane datoteke za ${getDocumentTemplateMediaFieldKindLabel(field.type).toLowerCase()}.`;
        previewCard.append(empty);
        return;
      }

      const row = document.createElement("article");
      row.className = "module-attachment-row document-template-runtime-media-row";

      const copy = document.createElement("div");
      copy.className = "module-attachment-copy";

      const titleNode = document.createElement("strong");
      titleNode.textContent = mediaValue.fileName || getDocumentTemplateMediaFieldKindLabel(field.type);

      const meta = document.createElement("span");
      meta.className = "module-attachment-meta";
      meta.textContent = getDocumentTemplateMediaFieldSummary(mediaValue, field);

      copy.append(titleNode, meta);

      const previewUrl = getDocumentTemplateMediaFieldPreviewUrl(mediaValue);
      const isImagePreview = Boolean(previewUrl)
        && !/\.pdf($|\?)/i.test(previewUrl)
        && !/application\/pdf/i.test(String(mediaValue.fileType || ""));

      if (isImagePreview) {
        const previewImage = document.createElement("img");
        previewImage.className = "document-template-runtime-media-image";
        previewImage.src = previewUrl;
        previewImage.alt = mediaValue.fileName || getDocumentTemplateMediaFieldKindLabel(field.type);
        previewImage.loading = "lazy";
        copy.append(previewImage);
      }

      const actions = document.createElement("div");
      actions.className = "module-attachment-actions";

      const openButton = createActionButton("Otvori", "card-button", () => {
        const href = String(mediaValue.storageUrl || mediaValue.dataUrl || "").trim();
        if (!href) {
          return;
        }

        const link = document.createElement("a");
        link.href = href;
        link.target = "_blank";
        link.rel = "noopener";
        document.body.append(link);
        link.click();
        link.remove();
      });

      const removeButton = createActionButton("Makni", "card-button card-danger", () => {
        setDocumentTemplateRuntimeFieldValue(workOrder.id, field.id, null, { render: false });
        renderDocumentTemplateFieldRows();
        renderDocumentTemplatePreviewContent();
      });

      actions.append(openButton, removeButton);
      row.append(copy, actions);
      previewCard.append(row);
    };

    const applyFiles = async (files) => {
      const selectedFiles = Array.from(files ?? []).filter((entry) => entry instanceof File);
      if (!selectedFiles.length) {
        return;
      }

      const nextFile = selectedFiles.find((entry) => isDocumentTemplateMediaFileAllowed(field.type, entry));
      if (!nextFile) {
        setDocumentTemplateMessage(`${getDocumentTemplateMediaFieldKindLabel(field.type)} prihvaća samo podržane slike${String(field.type || "").trim().toLowerCase() === "sketch_upload" ? " ili PDF skicu" : ""}.`);
        return;
      }

      try {
        const mediaDraft = await createDocumentTemplateMediaDraftFromFile(nextFile, field);
        setDocumentTemplateRuntimeFieldValue(workOrder.id, field.id, mediaDraft, { render: false });
        renderDocumentTemplateFieldRows();
        renderDocumentTemplatePreviewContent();
      } catch (error) {
        setDocumentTemplateMessage(error.message || "Ne mogu učitati datoteku.");
      } finally {
        fileInput.value = "";
      }
    };

    let dragDepth = 0;
    dropzone.addEventListener("click", () => {
      fileInput.click();
    });
    fileInput.addEventListener("change", () => {
      void applyFiles(fileInput.files);
    });
    dropzone.addEventListener("dragenter", (event) => {
      if (!isFileDragEvent(event)) {
        return;
      }
      event.preventDefault();
      dragDepth += 1;
      dropzone.classList.add("is-drag-over");
    });
    dropzone.addEventListener("dragover", (event) => {
      if (!isFileDragEvent(event)) {
        return;
      }
      event.preventDefault();
      if (event.dataTransfer) {
        event.dataTransfer.dropEffect = "copy";
      }
      dropzone.classList.add("is-drag-over");
    });
    dropzone.addEventListener("dragleave", (event) => {
      if (!isFileDragEvent(event)) {
        return;
      }
      event.preventDefault();
      dragDepth = Math.max(0, dragDepth - 1);
      if (dragDepth === 0) {
        dropzone.classList.remove("is-drag-over");
      }
    });
    dropzone.addEventListener("drop", (event) => {
      if (!isFileDragEvent(event)) {
        return;
      }
      event.preventDefault();
      dragDepth = 0;
      dropzone.classList.remove("is-drag-over");
      void applyFiles(event.dataTransfer?.files);
    });

    renderPreview(currentValue);

    shellNode.append(title);
    if (sourcePicker) {
      shellNode.append(sourcePicker);
    }
    shellNode.append(dropzone, fileInput, previewCard);
    if (field.helpText) {
      const helper = document.createElement("small");
      helper.className = "document-template-runtime-field-help";
      helper.textContent = field.helpText;
      shellNode.append(helper);
    }
    return shellNode;
  };

  const createSignatureFieldControl = (field, previewContext) => {
    const shellNode = document.createElement("div");
    shellNode.className = "document-template-runtime-readonly-card";
    const title = document.createElement("strong");
    title.textContent = createFieldTitle(field, 0);
    const signaturePreview = getDocumentTemplateSignaturePreviewData(field, previewContext);
    const signatureMethod = getDocumentTemplateContextSignatureMethod(previewContext);
    const meta = document.createElement("p");
    meta.className = "helper-copy module-copy";
    meta.textContent = signaturePreview.summary
      || `${signaturePreview.displayName} se povlači automatski iz People modula kao ${getDocumentTemplateSignatureMethodLabel(signatureMethod).toLowerCase()}.`;
    shellNode.append(title, meta);
    if (signatureMethod === "scan" && signaturePreview.signatureImageUrl) {
      const previewImage = document.createElement("img");
      previewImage.className = "document-template-runtime-signature-image";
      previewImage.src = signaturePreview.signatureImageUrl;
      previewImage.alt = signaturePreview.displayName || "Potpis";
      previewImage.loading = "lazy";
      shellNode.append(previewImage);
    } else if (signatureMethod === "digital") {
      const placeholder = document.createElement("div");
      placeholder.className = "document-template-preview-signature-placeholder is-digital";
      placeholder.textContent = "Rezervirano za digitalni potpis";
      shellNode.append(placeholder);
    }
    return shellNode;
  };

  const createDigitalSignatureFieldControl = (field, previewContext) => {
    const shellNode = document.createElement("div");
    shellNode.className = "document-template-runtime-readonly-card document-template-runtime-digital-signature-card";
    const signatureMethod = getDocumentTemplateContextSignatureMethod(previewContext);

    const title = document.createElement("strong");
    title.textContent = createFieldTitle(field, 0);

    const badgeRow = document.createElement("div");
    badgeRow.className = "document-template-runtime-digital-signature-badges";

    const areaBadge = document.createElement("span");
    areaBadge.className = "document-template-inline-token";
    areaBadge.textContent = getSignatureAreaLabel(field.signatureArea || "elektro");

    const roleBadge = document.createElement("span");
    roleBadge.className = "document-template-inline-token";
    roleBadge.textContent = getDocumentTemplateDigitalSignatureRoleLabel(field.signatureRole || "inspect");

    const modeBadge = document.createElement("span");
    modeBadge.className = "document-template-inline-token";
    modeBadge.textContent = getDocumentTemplateSignatureMethodLabel(signatureMethod);

    const countBadge = document.createElement("span");
    countBadge.className = "document-template-inline-token";
    countBadge.textContent = field.signatureMultiple === false ? "Jedan potpisnik" : "Vise potpisnika";

    badgeRow.append(areaBadge, roleBadge, modeBadge, countBadge);

    const note = document.createElement("p");
    note.className = "helper-copy module-copy";
    note.textContent = signatureMethod === "digital"
      ? "Ovaj blok rezervira mjesto za digitalni potpis odabranih osoba. Buduca Java/Fina/eOI integracija može koristiti isti slot."
      : "Ovaj blok prikazuje scan potpisa odabranih osoba kada on postoji u People modulu.";

    const personGrid = document.createElement("div");
    personGrid.className = "document-template-runtime-digital-signature-grid";
    const entries = getDocumentTemplateDigitalSignatureEntries(field, previewContext);

    if (entries.length === 0) {
      const empty = document.createElement("div");
      empty.className = "document-template-runtime-digital-signature-slot is-empty";
      empty.textContent = "Nema odabranih osoba za ovaj potpisni slot.";
      personGrid.append(empty);
    } else {
      entries.forEach((entry) => {
        const card = document.createElement("article");
        card.className = "document-template-runtime-digital-signature-slot";

        const role = document.createElement("span");
        role.className = "document-template-runtime-digital-signature-role";
        role.textContent = entry.role;

        const name = document.createElement("strong");
        name.textContent = entry.user?.fullName || entry.user?.email || "Potpisnik";

        const meta = document.createElement("div");
        meta.className = "document-template-runtime-digital-signature-meta";
        (entry.metaLines ?? []).forEach((line) => {
          const row = document.createElement("span");
          row.textContent = line;
          meta.append(row);
        });

        const footer = document.createElement("div");
        footer.className = "document-template-runtime-digital-signature-footer";
        const marker = document.createElement("span");
        marker.className = "document-template-inline-token";
        marker.textContent = getDocumentTemplateSignatureMethodLabel(signatureMethod);
        footer.append(marker);

        card.append(role, name);
        if (meta.childElementCount > 0) {
          card.append(meta);
        }
        if (signatureMethod === "scan" && entry.signatureImageUrl) {
          const previewImage = document.createElement("img");
          previewImage.className = "document-template-runtime-signature-image";
          previewImage.src = entry.signatureImageUrl;
          previewImage.alt = entry.user?.fullName || "Potpis";
          previewImage.loading = "lazy";
          card.append(previewImage);
        }
        card.append(footer);
        personGrid.append(card);
      });
    }

    shellNode.append(title, badgeRow, note, personGrid);
    return shellNode;
  };

  const createMeasurementFieldControl = (field, workOrder) => {
    const shellNode = document.createElement("div");
    shellNode.className = "document-template-runtime-measurement-field";
    const title = document.createElement("strong");
    title.textContent = createFieldTitle(field, 0);
    const sourcePicker = createPersistedFieldSourcePicker(field, workOrder, { kind: "sheet" });
    const summaryButton = document.createElement("button");
    summaryButton.type = "button";
    summaryButton.className = "ghost-button document-template-runtime-excel-trigger";
    summaryButton.textContent = getMeasurementSheetTemplateSummary(
      getDocumentTemplateRuntimeMeasurementSheet(workOrder.id, field) ?? field.sheet,
    );
    summaryButton.addEventListener("click", () => {
      ensureDocumentTemplateRuntimeMeasurementSheetForField(field.id, workOrder.id);
      requestAnimationFrame(() => {
        shellNode.scrollIntoView({ behavior: "smooth", block: "nearest" });
      });
    });

    const helper = document.createElement("p");
    helper.className = "helper-copy module-copy";
    helper.textContent = "Klik otvara napredni Excel unutar ovog bloka. Ono što upišeš ide u pregled i Word export.";

    const inlineExcelHost = document.createElement("div");
    inlineExcelHost.className = "document-template-inline-excel-host";
    inlineExcelHost.dataset.templateFieldId = String(field.id || "");
    const preview = document.createElement("div");
    preview.className = "document-template-inline-excel-preview document-template-runtime-excel-preview";
    preview.textContent = "Napredni Excel editor prikazuje se ovdje kada otvoriš ovu tablicu.";
    inlineExcelHost.append(preview);
    documentTemplateMeasurementInlineHosts.set(String(field.id || ""), inlineExcelHost);

    shellNode.append(title);
    if (sourcePicker) {
      shellNode.append(sourcePicker);
    }
    shellNode.append(summaryButton, helper, inlineExcelHost);
    return shellNode;
  };

  const createRuntimeFieldNode = ({ field, index }) => {
    const card = document.createElement("article");
    card.className = "document-template-item-card document-template-runtime-field-card";
    card.dataset.templateFieldId = String(field.id || "");
    card.dataset.fieldWidth = getDocumentTemplateRuntimeFieldLayoutWidth(field);
    card.style.setProperty("--document-template-runtime-span", String(getDocumentTemplateRuntimeFieldLayoutSpan(field)));
    const customCardHeight = getDocumentTemplateBuilderFieldHeightPx(field, { preserveAuto: true });
    if (customCardHeight > 0) {
      card.style.setProperty("--document-template-runtime-card-min-height", `${customCardHeight}px`);
      card.dataset.hasCustomHeight = "true";
    } else {
      card.style.removeProperty("--document-template-runtime-card-min-height");
      card.dataset.hasCustomHeight = "false";
    }
    const grid = document.createElement("div");
    grid.className = "form-grid document-template-inline-grid document-template-runtime-field-grid";

    if (field.type === "measurement_table") {
      const fieldShell = document.createElement("div");
      fieldShell.className = "field field-span-full";
      fieldShell.append(createMeasurementFieldControl(field, activeWorkOrder));
      grid.append(fieldShell);
    } else if (field.type === "system_description") {
      const fieldShell = document.createElement("div");
      fieldShell.className = "field field-span-full";
      fieldShell.append(createSystemDescriptionFieldControl(field, activeWorkOrder));
      grid.append(fieldShell);
    } else if (isDocumentTemplateMediaFieldType(field.type)) {
      const fieldShell = document.createElement("div");
      fieldShell.className = "field field-span-full";
      fieldShell.append(createMediaFieldControl(field, activeWorkOrder));
      grid.append(fieldShell);
    } else if (field.type === "qualified_inspectors") {
      grid.append(createInspectorsFieldControl(field, activeWorkOrder));
    } else if (field.type === "legal_list") {
      const fieldShell = document.createElement("div");
      fieldShell.className = "field field-span-full";
      fieldShell.append(createLegalListFieldControl(field, activeWorkOrder, template));
      grid.append(fieldShell);
    } else if (field.type === "equipment_list") {
      const fieldShell = document.createElement("div");
      fieldShell.className = "field field-span-full";
      fieldShell.append(createEquipmentFieldControl(field, activeWorkOrder, template));
      grid.append(fieldShell);
    } else if (field.type === "inspector_signature" || field.type === "authorization_holder_signature") {
      const fieldShell = document.createElement("div");
      fieldShell.className = "field field-span-full";
      fieldShell.append(createSignatureFieldControl(field, context));
      grid.append(fieldShell);
    } else if (field.type === "digital_signature") {
      const fieldShell = document.createElement("div");
      fieldShell.className = "field field-span-full";
      fieldShell.append(createDigitalSignatureFieldControl(field, context));
      grid.append(fieldShell);
    } else {
      grid.append(createStandardFieldControl(field, activeWorkOrder.id, activeWorkOrder));
    }

    card.append(grid);
    return card;
  };

  visibleBlocks.forEach((block, blockIndex) => {
    const blockNode = document.createElement("section");
    blockNode.className = "document-template-runtime-block";
    const collapsed = isDocumentTemplateRuntimeBlockCollapsed(block, blockIndex);
    blockNode.classList.toggle("is-collapsed", collapsed);

    const head = document.createElement("div");
    head.className = "document-template-runtime-block-head";
    const toggleButton = document.createElement("button");
    toggleButton.type = "button";
    toggleButton.className = "document-template-runtime-block-toggle";
    toggleButton.textContent = collapsed ? "+" : "−";
    toggleButton.setAttribute("aria-label", collapsed ? "Prikaži blok" : "Sakrij blok");
    toggleButton.addEventListener("click", () => {
      toggleDocumentTemplateRuntimeBlockCollapsed(block, blockIndex);
    });
    const copy = document.createElement("div");
    const title = document.createElement("h4");
    title.textContent = block.chapter?.label || `Blok ${blockIndex + 1}`;
    const meta = document.createElement("p");
    meta.className = "document-template-runtime-block-meta";
    meta.textContent = block.chapter?.helpText
      || (block.items.length > 0
        ? `${block.items.length} polja za unos u ovom bloku.`
        : "Ovaj blok se puni automatski iz RN-a i povezanih podataka.");
    copy.append(title, meta);
    const headMeta = document.createElement("div");
    headMeta.className = "document-template-runtime-block-actions";
    headMeta.append(
      createBadge(`${block.items.length} polja`, "document-template-meta-badge"),
      toggleButton,
    );
    head.append(copy, headMeta);
    blockNode.append(head);

    const body = document.createElement("div");
    body.className = "document-template-runtime-block-body";
    body.hidden = collapsed;
    if (block.items.length === 0) {
      const empty = document.createElement("p");
      empty.className = "helper-copy module-copy";
      empty.textContent = "U ovom bloku nema ručnih polja. Sadržaj će se popuniti automatski iz RN-a i povezanih izvora.";
      body.append(empty);
    } else {
      block.items.forEach((entry) => {
        body.append(createRuntimeFieldNode(entry));
      });
    }
    blockNode.append(body);
    shell.append(blockNode);
  });

  documentTemplateCustomFields.replaceChildren(shell);

  const shouldCloseRuntimeSheet = state.measurementSheet.ownerKind === "document_template_runtime_field"
    && (
      !state.measurementSheet.isOpen
      || String(state.measurementSheet.ownerRuntimeWorkOrderId || "") !== String(activeWorkOrder.id || "")
      || !documentTemplateFieldDrafts.some((field) => String(field.id) === String(state.measurementSheet.ownerFieldId || ""))
    );
  if (shouldCloseRuntimeSheet) {
    setMeasurementSheetOpen(false);
    state.measurementSheet.ownerKind = "work_order";
    state.measurementSheet.ownerFieldId = "";
    state.measurementSheet.ownerRuntimeWorkOrderId = "";
    syncMeasurementToolbar();
  }

  syncMeasurementSheetPanelMount();
  syncDocumentTemplateInlineExcelPreviewVisibility();
  renderDocumentTemplatePreviewContent();
}

function renderDocumentTemplateFieldRows({ renderSupport = true, supportImmediate = false } = {}) {
  if (!documentTemplateCustomFields) {
    return;
  }

  invalidateDocumentTemplateDraftCache();
  documentTemplateMeasurementInlineHosts = new Map();

  if (isDocumentTemplateRuntimeFillMode()) {
    renderDocumentTemplateRuntimeFieldRows();
    return;
  }

  const visibleFields = documentTemplateFieldDrafts.filter((field) => field?.type !== "page_break");
  const chapterIds = new Set(
    visibleFields
      .filter((field) => field?.type === "chapter")
      .map((field) => String(field.id || ""))
      .filter(Boolean),
  );
  collapsedDocumentTemplateChapterIds = new Set(
    [...collapsedDocumentTemplateChapterIds].filter((id) => chapterIds.has(String(id))),
  );
  const chapterChildCounts = new Map();
  const chapterOwnerByFieldId = new Map();
  let activeChapterId = "";
  visibleFields.forEach((field) => {
    const fieldId = String(field?.id || "");
    if (field?.type === "chapter") {
      activeChapterId = fieldId;
      chapterChildCounts.set(fieldId, 0);
      return;
    }
    chapterOwnerByFieldId.set(fieldId, activeChapterId);
    if (activeChapterId) {
      chapterChildCounts.set(activeChapterId, (chapterChildCounts.get(activeChapterId) || 0) + 1);
    }
  });
  const shell = document.createElement("div");
  shell.className = "document-template-sheet-shell";
  const previewContext = buildDocumentTemplatePreviewContext(buildDocumentTemplateDraft());
  activeDocumentTemplateInspectorFieldId = getDocumentTemplateBuilderInspectorFieldId(visibleFields);

  const pageBody = document.createElement("div");
  pageBody.className = "document-template-sheet-panel";
  const chapterShells = new Map();
  const refreshEditorSupport = ({ immediate = false } = {}) => {
    scheduleDocumentTemplateEditorSupportRefresh({ immediate });
  };
  const inspectorShell = document.createElement("div");
  inspectorShell.className = "document-template-field-inspector-shell";
  const inspectorEmpty = document.createElement("p");
  inspectorEmpty.className = "helper-copy module-copy document-template-field-inspector-empty";
  inspectorEmpty.textContent = visibleFields.length > 0
    ? "Klikni blok na canvasu za detaljne postavke."
    : "Dodaj polje iz alatne trake pa će se ovdje pojaviti postavke.";
  inspectorShell.append(inspectorEmpty);

  if (visibleFields.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy document-template-sheet-empty";
    empty.textContent = "Template je prazan. Dodaj blok, pravilnike, opremu ili Excel tablicu pa nastavi slagati raspored.";
    pageBody.append(empty);
  }

  documentTemplateFieldDrafts.forEach((field, draftIndex) => {
    if (field?.type === "page_break") {
      return;
    }

    const fieldId = String(field.id || "");
    const isInspectorActive = fieldId === activeDocumentTemplateInspectorFieldId;
    ensureDocumentTemplateDatabaseLookupDraft(field);
    const chapterOwnerId = field.type === "chapter" ? "" : (chapterOwnerByFieldId.get(fieldId) || "");
    const previousField = visibleFields[draftIndex - 1] ?? null;
    const nextField = visibleFields[draftIndex + 1] ?? null;
    const previousOwnerId = previousField && previousField.type !== "chapter"
      ? (chapterOwnerByFieldId.get(String(previousField.id || "")) || "")
      : "";
    const nextOwnerId = nextField && nextField.type !== "chapter"
      ? (chapterOwnerByFieldId.get(String(nextField.id || "")) || "")
      : "";
    const isChapterChild = Boolean(chapterOwnerId);
    const isHiddenByCollapsedChapter = isChapterChild && collapsedDocumentTemplateChapterIds.has(chapterOwnerId);
    const row = document.createElement("div");
    row.className = [
      "document-template-item-card",
      "is-canvas-field",
      field.type === "chapter" ? "is-chapter" : "",
      isChapterChild ? "is-chapter-child" : "",
      isChapterChild && previousOwnerId !== chapterOwnerId ? "is-chapter-child-start" : "",
      isChapterChild && nextOwnerId !== chapterOwnerId ? "is-chapter-child-end" : "",
      isHiddenByCollapsedChapter ? "is-hidden-by-chapter" : "",
      isInspectorActive ? "is-active" : "",
    ].filter(Boolean).join(" ");
    row.dataset.templateFieldId = String(field.id || "");
    row.dataset.fieldWidth = getDocumentTemplateRuntimeFieldLayoutWidth(field);
    row.style.setProperty("--document-template-builder-width", getDocumentTemplateBuilderWidthPercent(field));
    if (chapterOwnerId) {
      row.dataset.chapterOwnerId = chapterOwnerId;
    }
    if (field.type === "measurement_table") {
      row.classList.add("is-excel-block");
    }

    const head = document.createElement("div");
    head.className = "document-template-item-head";
    const dragHandle = document.createElement("button");
    dragHandle.type = "button";
    dragHandle.className = "document-template-drag-handle";
    dragHandle.draggable = true;
    dragHandle.setAttribute("aria-label", `Promijeni redoslijed bloka ${field.label || getDocumentTemplateFieldTypeLabel(field.type) || `Blok ${draftIndex + 1}`}`);
    dragHandle.title = "Povuci za promjenu redoslijeda";
    dragHandle.innerHTML = '<span aria-hidden="true">⋮⋮</span>';
    dragHandle.addEventListener("dragstart", (event) => {
      draggedDocumentTemplateFieldId = String(field.id || "");
      row.classList.add("is-dragging");
      event.dataTransfer?.setData("text/plain", draggedDocumentTemplateFieldId);
      if (event.dataTransfer) {
        event.dataTransfer.effectAllowed = "move";
      }
    });
    dragHandle.addEventListener("dragend", () => {
      clearDocumentTemplateFieldDragState();
    });
    const headCopy = document.createElement("div");
    headCopy.className = "document-template-item-head-copy";
    const title = document.createElement("strong");
    title.textContent = field.label || getDocumentTemplateFieldTypeLabel(field.type) || `Blok ${draftIndex + 1}`;
    const tokenPreview = document.createElement("span");
    tokenPreview.className = "document-template-inline-token";
    tokenPreview.textContent = getDocumentTemplateFieldToken(field, draftIndex);
    headCopy.append(title, tokenPreview);
    if (field.type === "chapter") {
      const chapterCount = document.createElement("span");
      chapterCount.className = "document-template-chapter-count";
      const count = chapterChildCounts.get(fieldId) || 0;
      chapterCount.textContent = `${count} ${count === 1 ? "stavka" : "stavki"}`;
      headCopy.append(chapterCount);
    }
    const headActions = document.createElement("div");
    headActions.className = "document-template-item-head-actions";

    const selectInspectorField = ({ focus = false } = {}) => {
      activeDocumentTemplateInspectorFieldId = fieldId;
      renderDocumentTemplateFieldRows({ renderSupport: false });
      if (focus) {
        requestAnimationFrame(() => {
          const inspectorInput = documentTemplateFieldInspector?.querySelector("input, textarea, select");
          if (inspectorInput instanceof HTMLElement) {
            inspectorInput.focus({ preventScroll: true });
          }
        });
      }
    };

    const settingsButton = createActionButton("Postavke", "ghost-button document-template-canvas-settings", () => {
      selectInspectorField({ focus: true });
    });
    settingsButton.addEventListener("click", (event) => {
      event.stopPropagation();
    });
    headActions.append(settingsButton);

    if (field.type === "longtext") {
      const currentHeight = normalizeDocumentTemplateFieldHeight(field.fieldHeight, field.type || "longtext");
      const reduceHeightButton = createActionButton("Nize", "ghost-button document-template-canvas-resize", () => {
        documentTemplateFieldDrafts[draftIndex].fieldHeight = normalizeDocumentTemplateFieldHeight(String(Math.max(3, currentHeight - 1)), field.type || "longtext");
        renderDocumentTemplateFieldRows({ supportImmediate: true });
      });
      const increaseHeightButton = createActionButton("Vise", "ghost-button document-template-canvas-resize", () => {
        documentTemplateFieldDrafts[draftIndex].fieldHeight = normalizeDocumentTemplateFieldHeight(String(Math.min(12, currentHeight + 1)), field.type || "longtext");
        renderDocumentTemplateFieldRows({ supportImmediate: true });
      });
      headActions.append(reduceHeightButton, increaseHeightButton);
    }

    head.append(dragHandle, headCopy, headActions);

    const tokenValue = field.type === "chapter"
      ? null
      : document.createElement("code");
    let tokenRow = null;
    if (tokenValue) {
      tokenRow = document.createElement("div");
      tokenRow.className = "document-template-item-token-row";

      const tokenLabel = document.createElement("span");
      tokenLabel.className = "document-template-item-token-label";
      tokenLabel.textContent = "Placeholder";

      tokenValue.className = "document-template-item-token-value";
      tokenValue.textContent = getDocumentTemplateFieldToken(field, draftIndex);

      const tokenCopyButton = createActionButton("Kopiraj", "ghost-button document-template-token-copy", () => {
        void copyDocumentTemplateToken(tokenValue.textContent);
      });

      tokenRow.append(tokenLabel, tokenValue, tokenCopyButton);
    }

    row.addEventListener("click", (event) => {
      const target = event.target instanceof HTMLElement ? event.target : null;
      if (target?.closest("button, input, select, textarea, a")) {
        return;
      }
      activeDocumentTemplateInspectorFieldId = fieldId;
      renderDocumentTemplateFieldRows({ renderSupport: false });
    });

    row.addEventListener("dragover", (event) => {
      if (!draggedDocumentTemplateFieldId || draggedDocumentTemplateFieldId === String(field.id || "")) {
        return;
      }

      event.preventDefault();
      const bounds = row.getBoundingClientRect();
      const placement = event.clientY >= (bounds.top + bounds.height / 2) ? "after" : "before";
      row.dataset.dropPlacement = placement;
      row.classList.toggle("is-drop-before", placement === "before");
      row.classList.toggle("is-drop-after", placement === "after");
    });
    row.addEventListener("dragleave", (event) => {
      if (event.currentTarget !== event.target) {
        return;
      }
      row.classList.remove("is-drop-before", "is-drop-after");
      delete row.dataset.dropPlacement;
    });
    row.addEventListener("drop", (event) => {
      event.preventDefault();
      const moved = moveDocumentTemplateFieldDraft(
        draggedDocumentTemplateFieldId,
        field.id,
        {
          pageIndex: 0,
          placement: row.dataset.dropPlacement || "before",
        },
      );
      clearDocumentTemplateFieldDragState();
      if (moved) {
        renderDocumentTemplateFieldRows({ supportImmediate: true });
      }
    });
    const grid = document.createElement("div");
    grid.className = "form-grid document-template-inline-grid";
    if (field.type === "measurement_table") {
      grid.classList.add("is-excel-layout");
    }
    const isSpecialType = isDocumentTemplateSpecialFieldType(field.type);

    const labelField = document.createElement("label");
    labelField.className = "field";
    const labelSpan = document.createElement("span");
    labelSpan.textContent = field.type === "chapter"
      ? "Ime bloka"
      : field.type === "system_description"
        ? "Naslov bloka"
        : "Naziv u aplikaciji";
    const labelInput = document.createElement("input");
    labelInput.type = "text";
    labelInput.value = field.label || "";
    labelInput.dataset.templateFieldAppLabel = "true";
    labelInput.addEventListener("input", (event) => {
      const previousLabel = String(documentTemplateFieldDrafts[draftIndex].label || "");
      const previousWordLabel = String(documentTemplateFieldDrafts[draftIndex].wordLabel || "");
      const nextLabel = event.currentTarget.value;
      const shouldSyncWordLabel = field.type === "chapter"
        || !previousWordLabel
        || previousWordLabel === previousLabel;
      documentTemplateFieldDrafts[draftIndex].label = nextLabel;
      if (shouldSyncWordLabel) {
        documentTemplateFieldDrafts[draftIndex].wordLabel = nextLabel;
      }
      documentTemplateFieldDrafts[draftIndex].key = normalizeDocumentTemplateFieldKeyDraft(
        documentTemplateFieldDrafts[draftIndex].wordLabel || nextLabel,
        `FIELD_${draftIndex + 1}`,
      );
      refreshEditorSupport();
      title.textContent = nextLabel || getDocumentTemplateFieldTypeLabel(documentTemplateFieldDrafts[draftIndex].type) || `Blok ${draftIndex + 1}`;
      tokenPreview.textContent = getDocumentTemplateFieldToken(documentTemplateFieldDrafts[draftIndex], draftIndex);
      if (tokenValue) {
        tokenValue.textContent = getDocumentTemplateFieldToken(documentTemplateFieldDrafts[draftIndex], draftIndex);
      }
      if (shouldSyncWordLabel && field.type !== "chapter") {
        const wordLabelTarget = documentTemplateFieldInspector?.querySelector("[data-template-field-word-label]");
        if (wordLabelTarget instanceof HTMLInputElement) {
          wordLabelTarget.value = nextLabel;
        }
      }
    });
    labelInput.addEventListener("focus", () => rememberDocumentTemplateTextTarget(labelInput, `field-label:${field.id}`));
    labelField.append(labelSpan, labelInput);

    const wordLabelField = document.createElement("label");
    wordLabelField.className = "field";
    const wordLabelSpan = document.createElement("span");
    wordLabelSpan.textContent = field.type === "chapter"
      ? "Naslov u Wordu"
      : field.type === "system_description"
        ? "Placeholder bloka u Wordu"
        : "Placeholder u Wordu";
    const wordLabelInput = document.createElement("input");
    wordLabelInput.type = "text";
    wordLabelInput.placeholder = "Kako se placeholder zove u Wordu";
    wordLabelInput.value = field.wordLabel || field.label || "";
    wordLabelInput.dataset.templateFieldWordLabel = "true";
    wordLabelInput.addEventListener("input", (event) => {
      documentTemplateFieldDrafts[draftIndex].wordLabel = event.currentTarget.value;
      documentTemplateFieldDrafts[draftIndex].key = normalizeDocumentTemplateFieldKeyDraft(
        event.currentTarget.value || documentTemplateFieldDrafts[draftIndex].label,
        `FIELD_${draftIndex + 1}`,
      );
      refreshEditorSupport();
      tokenPreview.textContent = getDocumentTemplateFieldToken(documentTemplateFieldDrafts[draftIndex], draftIndex);
      if (tokenValue) {
        tokenValue.textContent = getDocumentTemplateFieldToken(documentTemplateFieldDrafts[draftIndex], draftIndex);
      }
    });
    wordLabelInput.addEventListener("focus", () => rememberDocumentTemplateTextTarget(wordLabelInput, `field-word-label:${field.id}`));
    wordLabelField.append(wordLabelSpan, wordLabelInput);

    const widthField = document.createElement("label");
    widthField.className = "field";
    widthField.hidden = !isDocumentTemplateFieldWidthEditable(field.type);
    const widthSpan = document.createElement("span");
    widthSpan.textContent = "Širina polja";
    const widthSelect = document.createElement("select");
    widthSelect.className = "document-template-source-select";
    widthSelect.dataset.templateFieldWidthSelect = "true";
    replaceSelectOptions(
      widthSelect,
      DOCUMENT_TEMPLATE_FIELD_WIDTH_OPTIONS,
      normalizeDocumentTemplateFieldLayoutWidth(field.layoutWidth, field.type || "text"),
    );
    widthSelect.addEventListener("change", () => {
      documentTemplateFieldDrafts[draftIndex].layoutWidth = normalizeDocumentTemplateFieldLayoutWidth(
        widthSelect.value || "",
        documentTemplateFieldDrafts[draftIndex].type || "text",
      );
      renderDocumentTemplateFieldRows({ supportImmediate: true });
    });
    widthField.append(widthSpan, widthSelect);

    const heightField = document.createElement("label");
    heightField.className = "field";
    heightField.hidden = field.type !== "longtext";
    const heightSpan = document.createElement("span");
    heightSpan.textContent = "Visina polja";
    const heightSelect = document.createElement("select");
    heightSelect.className = "document-template-source-select";
    heightSelect.dataset.templateFieldHeightSelect = "true";
    replaceSelectOptions(
      heightSelect,
      DOCUMENT_TEMPLATE_LONGTEXT_HEIGHT_OPTIONS,
      String(normalizeDocumentTemplateFieldHeight(field.fieldHeight, field.type || "longtext")),
    );
    heightSelect.addEventListener("change", () => {
      documentTemplateFieldDrafts[draftIndex].fieldHeight = normalizeDocumentTemplateFieldHeight(
        heightSelect.value || "",
        documentTemplateFieldDrafts[draftIndex].type || "longtext",
      );
      renderDocumentTemplateFieldRows({ supportImmediate: true });
    });
    heightField.append(heightSpan, heightSelect);

    const sourceField = document.createElement("label");
    sourceField.className = "field";
    sourceField.hidden = isSpecialType;
    const sourceSpan = document.createElement("span");
    sourceSpan.textContent = "Veza iz baze";
    const sourceSelect = document.createElement("select");
    sourceSelect.className = "document-template-source-select";
    replaceSelectOptions(sourceSelect, DOCUMENT_TEMPLATE_SOURCE_OPTIONS, field.source || getDocumentTemplateDefaultFieldSource(field.type));
    sourceSelect.addEventListener("change", () => {
      documentTemplateFieldDrafts[draftIndex].source = sourceSelect.value || "CUSTOM_VALUE";
      ensureDocumentTemplateDatabaseLookupDraft(documentTemplateFieldDrafts[draftIndex]);
      renderDocumentTemplateFieldRows({ supportImmediate: true });
    });
    sourceField.append(sourceSpan, sourceSelect);

    const sourceConfigField = document.createElement("div");
    sourceConfigField.className = "field field-span-full document-template-source-config";
    sourceConfigField.hidden = isSpecialType;
    const sourceConfigTitle = document.createElement("span");
    sourceConfigTitle.textContent = "Lookup i fallback";
    sourceConfigField.append(sourceConfigTitle);

    const sourceConfigGrid = document.createElement("div");
    sourceConfigGrid.className = "form-grid document-template-inline-grid document-template-source-config-grid";
    const isDatabaseLookup = String(field.source || "").trim().toUpperCase() === "DATABASE_LOOKUP";
    const lookupMode = getDocumentTemplateLookupMode(field);

    if (isDatabaseLookup) {
      const lookupModeField = document.createElement("label");
      lookupModeField.className = "field field-span-full";
      const lookupModeSpan = document.createElement("span");
      lookupModeSpan.textContent = "Trazenje";
      const lookupModeSelect = document.createElement("select");
      lookupModeSelect.className = "document-template-source-select";
      replaceSelectOptions(
        lookupModeSelect,
        DOCUMENT_TEMPLATE_LOOKUP_MODE_OPTIONS,
        lookupMode,
      );
      lookupModeSelect.addEventListener("change", () => {
        const draft = documentTemplateFieldDrafts[draftIndex];
        setDocumentTemplateLookupMode(draft, lookupModeSelect.value || "WORK_ORDER_NUMBER");
        ensureDocumentTemplateDatabaseLookupDraft(draft);
        renderDocumentTemplateFieldRows({ supportImmediate: true });
      });
      lookupModeField.append(lookupModeSpan, lookupModeSelect);
      sourceConfigGrid.append(lookupModeField);

      if (lookupMode !== "PREVIOUS_DOCUMENT_LOCATION") {
      const tableField = document.createElement("label");
      tableField.className = "field";
      const tableSpan = document.createElement("span");
      tableSpan.textContent = "Tablica";
      const tableSelect = document.createElement("select");
      tableSelect.className = "document-template-source-select";
      replaceSelectOptions(
        tableSelect,
        getDocumentTemplateDatabaseTableOptions(),
        field.sourceTable || getDocumentTemplateDefaultDatabaseLookupConfig().sourceTable,
      );
      tableSelect.addEventListener("change", () => {
        const draft = documentTemplateFieldDrafts[draftIndex];
        const defaults = getDocumentTemplateDefaultDatabaseLookupConfig(tableSelect.value || "radni_nalozi");
        draft.sourceTable = defaults.sourceTable;
        draft.lookupColumn = defaults.lookupColumn;
        draft.valueColumn = defaults.valueColumn;
        ensureDocumentTemplateDatabaseLookupDraft(draft);
        renderDocumentTemplateFieldRows({ supportImmediate: true });
      });
      tableField.append(tableSpan, tableSelect);

      const lookupColumnField = document.createElement("label");
      lookupColumnField.className = "field";
      const lookupColumnSpan = document.createElement("span");
      lookupColumnSpan.textContent = "Trazi po koloni";
      const lookupColumnSelect = document.createElement("select");
      lookupColumnSelect.className = "document-template-source-select";
      replaceSelectOptions(
        lookupColumnSelect,
        getDocumentTemplateDatabaseColumnOptions(field.sourceTable || "radni_nalozi"),
        field.lookupColumn || "",
      );
      lookupColumnSelect.addEventListener("change", () => {
        documentTemplateFieldDrafts[draftIndex].lookupColumn = lookupColumnSelect.value || "";
        refreshEditorSupport();
      });
      lookupColumnField.append(lookupColumnSpan, lookupColumnSelect);

      const valueColumnField = document.createElement("label");
      valueColumnField.className = "field";
      const valueColumnSpan = document.createElement("span");
      valueColumnSpan.textContent = "Vrati kolonu";
      const valueColumnSelect = document.createElement("select");
      valueColumnSelect.className = "document-template-source-select";
      replaceSelectOptions(
        valueColumnSelect,
        getDocumentTemplateDatabaseColumnOptions(field.sourceTable || "radni_nalozi"),
        field.valueColumn || "",
      );
      valueColumnSelect.addEventListener("change", () => {
        documentTemplateFieldDrafts[draftIndex].valueColumn = valueColumnSelect.value || "";
        refreshEditorSupport();
      });
      valueColumnField.append(valueColumnSpan, valueColumnSelect);

      sourceConfigGrid.append(tableField, lookupColumnField, valueColumnField);

      if (lookupMode === "CUSTOM_VALUE") {
        const lookupCustomValueField = document.createElement("label");
        lookupCustomValueField.className = "field field-span-full";
        const lookupCustomValueSpan = document.createElement("span");
        lookupCustomValueSpan.textContent = "Rucna vrijednost za trazenje";
        const lookupCustomValueInput = document.createElement("input");
        lookupCustomValueInput.type = "text";
        lookupCustomValueInput.placeholder = "Upisi lookup vrijednost";
        lookupCustomValueInput.value = field.lookupValue || "";
        lookupCustomValueInput.addEventListener("input", (event) => {
          documentTemplateFieldDrafts[draftIndex].lookupValue = String(event.currentTarget.value || "");
          refreshEditorSupport();
        });
        lookupCustomValueField.append(lookupCustomValueSpan, lookupCustomValueInput);
        sourceConfigGrid.append(lookupCustomValueField);
      }
      }
    }

    const sourceConfigHint = document.createElement("small");
    sourceConfigHint.className = "document-template-source-config-hint";
    if (isDatabaseLookup && lookupMode === "PREVIOUS_DOCUMENT_LOCATION") {
      sourceConfigHint.textContent = "Uzet ce zadnji zapisnik za istu tvrtku i istu lokaciju. Ako ga nema, ostaje vrijednost iz templatea.";
    } else if (isDatabaseLookup) {
      const tableLabel = field.sourceTable || "radni_nalozi";
      const lookupLabel = field.lookupColumn || "broj_rn";
      const valueLabel = field.valueColumn || "ime_tvrtke";
      sourceConfigHint.textContent = lookupMode === "CUSTOM_VALUE"
        ? `Trazi podatak u tablici ${tableLabel} preko kolone ${lookupLabel} i rucno upisane lookup vrijednosti, pa vraca ${valueLabel}.`
        : `Trazi podatak u tablici ${tableLabel} preko kolone ${lookupLabel} za aktivni broj radnog naloga i vraca ${valueLabel}.`;
    } else {
      sourceConfigHint.textContent = "Ostavi na rucni unos ili ukljuci lookup iz baze ako zelis povuci podatak automatski.";
    }

    sourceConfigField.append(sourceConfigGrid, sourceConfigHint);

    const specialInfoField = document.createElement("label");
    specialInfoField.className = "field document-template-inline-special-field";
    specialInfoField.hidden = !isSpecialType;
    const specialInfoSpan = document.createElement("span");
    specialInfoSpan.textContent = "Veza";
    specialInfoField.append(specialInfoSpan);

    const columnsField = document.createElement("div");
    columnsField.className = "field document-template-inline-excel-field";
    columnsField.hidden = field.type !== "measurement_table";
    const columnsSpan = document.createElement("span");
    columnsSpan.className = "document-template-inline-excel-label";
    columnsSpan.textContent = "Excel tablica";
    columnsSpan.tabIndex = 0;
    columnsSpan.setAttribute("role", "button");
    columnsSpan.setAttribute("aria-label", "Otvori napredni Excel");
    const excelMeta = document.createElement("div");
    excelMeta.className = "document-template-excel-meta";
    excelMeta.tabIndex = 0;
    excelMeta.setAttribute("role", "button");
    excelMeta.setAttribute("aria-label", "Otvori napredni Excel");
    const excelSummary = document.createElement("strong");
    excelSummary.textContent = getMeasurementSheetTemplateSummary(field.sheet);
    const excelHint = document.createElement("span");
    excelHint.textContent = "Klik otvara napredni Excel sa svim funkcijama.";
    excelMeta.append(excelSummary, excelHint);
    columnsField.append(columnsSpan, excelMeta);

    const removeButton = createActionButton("Ukloni", "card-button card-danger", () => {
      clearDocumentTemplateFieldDragState();
      if (field.type === "chapter") {
        collapsedDocumentTemplateChapterIds.delete(String(field.id || ""));
      }
      documentTemplateFieldDrafts = documentTemplateFieldDrafts.filter((entry) => entry.id !== field.id);
      renderDocumentTemplateFieldRows({ supportImmediate: true });
    });
    removeButton.classList.add("document-template-item-remove");

    grid.append(labelField);
    if (field.type !== "chapter") {
      grid.append(wordLabelField);
      if (!widthField.hidden) {
        grid.append(widthField);
      }
      if (!heightField.hidden) {
        grid.append(heightField);
      }
    }

    if (field.type === "chapter") {
      specialInfoSpan.textContent = "Blok";
      const specialInfoValue = document.createElement("div");
      specialInfoValue.className = "document-template-inline-special-value";
      const chapterCount = chapterChildCounts.get(fieldId) || 0;
      specialInfoValue.textContent = chapterCount > 0
        ? `Interni blok buildera. U njemu je ${chapterCount} ${chapterCount === 1 ? "stavka" : "stavki"} i sve sljedeće stavke ulaze unutra do novog bloka.`
        : "Interni blok buildera. Dodaj polja, tekst ili Excel ispod njega i sve će automatski ući u ovu cjelinu.";
      specialInfoField.append(specialInfoValue);
    } else if (field.type === "system_description") {
      specialInfoField.hidden = true;

      const subtitleField = document.createElement("label");
      subtitleField.className = "field field-span-full";
      const subtitleSpan = document.createElement("span");
      subtitleSpan.textContent = "Podnaslov / uvodni opis";
      const subtitleInput = document.createElement("input");
      subtitleInput.type = "text";
      subtitleInput.placeholder = "Kratka uvodna rečenica ili podnaslov bloka";
      subtitleInput.value = field.sectionSubtitle || "";
      subtitleInput.addEventListener("input", (event) => {
        documentTemplateFieldDrafts[draftIndex].sectionSubtitle = String(event.currentTarget.value || "");
        refreshEditorSupport();
      });
      subtitleField.append(subtitleSpan, subtitleInput);

      const rowsField = document.createElement("div");
      rowsField.className = "field field-span-full document-template-system-config";

      const rowsHead = document.createElement("div");
      rowsHead.className = "document-template-system-config-head";

      const rowsCopy = document.createElement("div");
      rowsCopy.className = "document-template-system-config-copy";
      const rowsTitle = document.createElement("strong");
      rowsTitle.textContent = "Redovi bloka";
      const rowsMeta = document.createElement("span");
      rowsMeta.textContent = "Ostavi podnaslov praznim ako želiš puni tekst preko cijele širine.";
      rowsCopy.append(rowsTitle, rowsMeta);

      const addRowButton = createActionButton("Dodaj red", "ghost-button", () => {
        documentTemplateFieldDrafts[draftIndex].systemRows = [
          ...normalizeDocumentTemplateSystemDescriptionRows(documentTemplateFieldDrafts[draftIndex].systemRows, {
            ensureOne: false,
          }),
          createEmptyDocumentTemplateSystemDescriptionRowDraft({}, documentTemplateFieldDrafts[draftIndex].systemRows?.length || 0),
        ];
        renderDocumentTemplateFieldRows({ supportImmediate: true });
      });

      rowsHead.append(rowsCopy, addRowButton);
      rowsField.append(rowsHead);

      const rowsList = document.createElement("div");
      rowsList.className = "document-template-system-config-list";
      const systemRows = normalizeDocumentTemplateSystemDescriptionRows(field.systemRows, {
        ensureOne: true,
        fallbackRows: createDefaultDocumentTemplateSystemDescriptionRows(),
      });
      documentTemplateFieldDrafts[draftIndex].systemRows = systemRows;

      systemRows.forEach((systemRow, systemRowIndex) => {
        const rowCard = document.createElement("article");
        rowCard.className = "document-template-system-config-row";

        const rowHeader = document.createElement("div");
        rowHeader.className = "document-template-system-config-row-head";

        const rowCounter = document.createElement("strong");
        rowCounter.textContent = `Red ${systemRowIndex + 1}`;

        const removeRowButton = createActionButton("Makni red", "ghost-button", () => {
          const currentRows = normalizeDocumentTemplateSystemDescriptionRows(documentTemplateFieldDrafts[draftIndex].systemRows, {
            ensureOne: true,
            fallbackRows: createDefaultDocumentTemplateSystemDescriptionRows(),
          });
          documentTemplateFieldDrafts[draftIndex].systemRows = currentRows.filter((_, currentIndex) => currentIndex !== systemRowIndex);
          if (documentTemplateFieldDrafts[draftIndex].systemRows.length === 0) {
            documentTemplateFieldDrafts[draftIndex].systemRows = [createEmptyDocumentTemplateSystemDescriptionRowDraft({}, 0)];
          }
          renderDocumentTemplateFieldRows({ supportImmediate: true });
        });
        removeRowButton.disabled = systemRows.length <= 1;
        rowHeader.append(rowCounter, removeRowButton);

        const rowGrid = document.createElement("div");
        rowGrid.className = "document-template-system-config-row-grid";

        const rowSubtitleField = document.createElement("label");
        rowSubtitleField.className = "field";
        const rowSubtitleSpan = document.createElement("span");
        rowSubtitleSpan.textContent = "Podnaslov";
        const rowSubtitleInput = document.createElement("input");
        rowSubtitleInput.type = "text";
        rowSubtitleInput.placeholder = "npr. Proizvođač";
        rowSubtitleInput.value = systemRow.subtitle || "";
        rowSubtitleInput.addEventListener("input", (event) => {
          documentTemplateFieldDrafts[draftIndex].systemRows[systemRowIndex].subtitle = String(event.currentTarget.value || "");
          refreshEditorSupport();
        });
        rowSubtitleField.append(rowSubtitleSpan, rowSubtitleInput);

        const rowLineField = document.createElement("label");
        rowLineField.className = "field document-template-system-config-line-field";
        const rowLineSpan = document.createElement("span");
        rowLineSpan.textContent = "Visina";
        const rowLineSelect = document.createElement("select");
        rowLineSelect.className = "document-template-source-select";
        replaceSelectOptions(
          rowLineSelect,
          DOCUMENT_TEMPLATE_SYSTEM_DESCRIPTION_LINE_OPTIONS,
          String(normalizeDocumentTemplateSystemDescriptionLineCount(systemRow.lineCount)),
        );
        rowLineSelect.addEventListener("change", () => {
          documentTemplateFieldDrafts[draftIndex].systemRows[systemRowIndex].lineCount = normalizeDocumentTemplateSystemDescriptionLineCount(rowLineSelect.value);
          renderDocumentTemplateFieldRows({ supportImmediate: true });
        });
        rowLineField.append(rowLineSpan, rowLineSelect);

        const rowDescriptionField = document.createElement("label");
        rowDescriptionField.className = "field field-span-full";
        const rowDescriptionSpan = document.createElement("span");
        rowDescriptionSpan.textContent = "Opis / vrijednost";
        const rowDescriptionInput = document.createElement("textarea");
        rowDescriptionInput.rows = normalizeDocumentTemplateSystemDescriptionLineCount(systemRow.lineCount);
        rowDescriptionInput.placeholder = systemRow.subtitle
          ? `Vrijednost za red "${systemRow.subtitle}"`
          : "Opis koji ide preko cijele širine bloka";
        rowDescriptionInput.value = systemRow.description || "";
        rowDescriptionInput.addEventListener("input", (event) => {
          documentTemplateFieldDrafts[draftIndex].systemRows[systemRowIndex].description = String(event.currentTarget.value || "");
          refreshEditorSupport();
        });
        rowDescriptionField.append(rowDescriptionSpan, rowDescriptionInput);

        rowGrid.append(rowSubtitleField, rowLineField, rowDescriptionField);
        rowCard.append(rowHeader, rowGrid);
        rowsList.append(rowCard);
      });

      rowsField.append(rowsList);
      grid.append(subtitleField, rowsField);
    } else if (field.type === "measurement_table") {
      specialInfoField.hidden = true;
    } else if (isDocumentTemplateMediaFieldType(field.type)) {
      specialInfoSpan.textContent = "Upload u zapisniku";
      const specialInfoValue = document.createElement("div");
      specialInfoValue.className = "document-template-inline-special-value";
      specialInfoValue.textContent = String(field.type || "").trim().toLowerCase() === "sketch_upload"
        ? "Korisnik ovdje kasnije dodaje tlocrt ili skicu. Podržani su klik na polje i drag and drop."
        : "Korisnik ovdje kasnije dodaje sliku. Podržani su klik na polje i drag and drop.";
      specialInfoField.append(specialInfoValue);
    } else if (field.type === "qualified_inspectors") {
      specialInfoSpan.textContent = "Usluga / dio potpisa";
      const signatureAreaSelect = document.createElement("select");
      signatureAreaSelect.className = "document-template-source-select";
      replaceSelectOptions(
        signatureAreaSelect,
        DOCUMENT_TEMPLATE_SIGNATURE_AREA_OPTIONS,
        field.signatureArea || "elektro",
      );
      signatureAreaSelect.addEventListener("change", () => {
        documentTemplateFieldDrafts[draftIndex].signatureArea = signatureAreaSelect.value || "elektro";
        refreshEditorSupport();
      });
      specialInfoField.append(signatureAreaSelect);
    } else if (field.type === "legal_list") {
      specialInfoField.hidden = true;

      const legalFrameworkOptions = getDocumentTemplateLegalFrameworkOptions();
      const allLegalFrameworkIds = legalFrameworkOptions.map((option) => String(option.value));
      const visibleLegalIds = new Set(
        (Array.isArray(field.legalFrameworkIds) && field.legalFrameworkIds.length > 0
          ? field.legalFrameworkIds
          : allLegalFrameworkIds).map(String),
      );
      const defaultLegalIds = new Set(
        (Array.isArray(field.defaultLegalFrameworkIds) ? field.defaultLegalFrameworkIds : []).map(String),
      );

      const createLegalSelectField = (labelText, selectedValues, onChange) => {
        const fieldShell = document.createElement("label");
        fieldShell.className = "field";
        const fieldTitle = document.createElement("span");
        fieldTitle.textContent = labelText;
        const select = document.createElement("select");
        select.className = "document-template-source-select";
        select.multiple = true;
        select.size = Math.max(4, Math.min(8, legalFrameworkOptions.length || 4));
        if (legalFrameworkOptions.length === 0) {
          select.disabled = true;
        }
        legalFrameworkOptions.forEach((option) => {
          const node = document.createElement("option");
          node.value = option.value;
          node.textContent = option.label;
          node.selected = selectedValues.has(String(option.value));
          select.append(node);
        });
        select.addEventListener("change", () => {
          onChange(Array.from(select.selectedOptions).map((option) => String(option.value)));
        });
        fieldShell.append(fieldTitle, select);
        return fieldShell;
      };

      const visibleField = createLegalSelectField("Prikaži pravilnike", visibleLegalIds, (selectedValues) => {
        const normalizedValues = selectedValues.length > 0 ? selectedValues : [];
        documentTemplateFieldDrafts[draftIndex].legalFrameworkIds = normalizedValues;
        documentTemplateFieldDrafts[draftIndex].defaultLegalFrameworkIds = (documentTemplateFieldDrafts[draftIndex].defaultLegalFrameworkIds ?? [])
          .filter((value) => normalizedValues.length === 0 || normalizedValues.includes(String(value)));
        renderDocumentTemplateFieldRows({ supportImmediate: true });
      });

      const selectedField = createLegalSelectField("Preselektiraj", defaultLegalIds, (selectedValues) => {
        const allowedIds = documentTemplateFieldDrafts[draftIndex].legalFrameworkIds?.length
          ? new Set(documentTemplateFieldDrafts[draftIndex].legalFrameworkIds.map(String))
          : new Set(allLegalFrameworkIds);
        documentTemplateFieldDrafts[draftIndex].defaultLegalFrameworkIds = selectedValues.filter((value) => allowedIds.has(String(value)));
        refreshEditorSupport();
      });

      const legalHint = document.createElement("div");
      legalHint.className = "document-template-inline-special-value document-template-legal-hint";
      legalHint.textContent = legalFrameworkOptions.length > 0
        ? "Prvi popis određuje što korisnik vidi, a drugi što je već označeno kad otvori zapisnik."
        : "Nema dostupnih pravilnika u Legal Framework modulu.";

      grid.append(visibleField, selectedField, legalHint);
    } else if (field.type === "equipment_list") {
      const specialInfoValue = document.createElement("div");
      specialInfoValue.className = "document-template-inline-special-value";
      specialInfoValue.textContent = "Povlači povezanu mjernu i ispitnu opremu.";
      specialInfoField.append(specialInfoValue);
    } else if (field.type === "inspector_signature" || field.type === "authorization_holder_signature") {
      specialInfoSpan.textContent = "Dio";
      const signatureAreaSelect = document.createElement("select");
      signatureAreaSelect.className = "document-template-source-select";
      replaceSelectOptions(
        signatureAreaSelect,
        DOCUMENT_TEMPLATE_SIGNATURE_AREA_OPTIONS,
        field.signatureArea || "elektro",
      );
      signatureAreaSelect.addEventListener("change", () => {
        documentTemplateFieldDrafts[draftIndex].signatureArea = signatureAreaSelect.value || "elektro";
        refreshEditorSupport();
      });
      specialInfoField.append(signatureAreaSelect);
    } else if (field.type === "digital_signature") {
      specialInfoField.hidden = true;

      const createDigitalSelectField = (labelText, options, value, onChange) => {
        const shellNode = document.createElement("label");
        shellNode.className = "field";
        const shellLabel = document.createElement("span");
        shellLabel.textContent = labelText;
        const select = document.createElement("select");
        select.className = "document-template-source-select";
        replaceSelectOptions(select, options, value);
        select.addEventListener("change", () => {
          onChange(select.value || "");
          refreshEditorSupport();
        });
        shellNode.append(shellLabel, select);
        return shellNode;
      };

      const areaField = createDigitalSelectField(
        "Usluga / dio potpisa",
        DOCUMENT_TEMPLATE_SIGNATURE_AREA_OPTIONS,
        field.signatureArea || "elektro",
        (nextValue) => {
          documentTemplateFieldDrafts[draftIndex].signatureArea = nextValue || "elektro";
        },
      );

      const roleField = createDigitalSelectField(
        "Potpisnici",
        DOCUMENT_TEMPLATE_DIGITAL_SIGNATURE_ROLE_OPTIONS,
        field.signatureRole || "inspect",
        (nextValue) => {
          documentTemplateFieldDrafts[draftIndex].signatureRole = nextValue || "inspect";
        },
      );

      documentTemplateFieldDrafts[draftIndex].signatureMultiple = true;

      const hintField = document.createElement("div");
      hintField.className = "field field-span-full";
      const hint = document.createElement("small");
      hint.className = "document-template-source-config-hint";
      hint.textContent = "Legacy potpisni blok. Za novi raspored koristi Ispitivače, gdje se potpisi automatski slažu po odabranoj usluzi. U izradi zapisnika biraš koristiš li scan potpisa ili digitalni potpis.";
      hintField.append(hint);

      grid.append(areaField, roleField, hintField);
    } else {
      specialInfoField.hidden = true;
    }

    if (field.type === "measurement_table") {
      grid.append(columnsField);
    } else if (field.type === "system_description") {
      // system description fields already appended above
    } else if (field.type === "legal_list") {
      // legal fields already appended above
    } else if (isSpecialType) {
      grid.append(specialInfoField);
    } else {
      grid.append(sourceField, sourceConfigField);
    }

    if (field.type === "chapter") {
      const collapseButton = document.createElement("button");
      collapseButton.type = "button";
      collapseButton.className = "ghost-button document-template-chapter-toggle";
      const isCollapsed = collapsedDocumentTemplateChapterIds.has(fieldId);
      collapseButton.textContent = isCollapsed ? "Otvori sadržaj" : "Sakrij sadržaj";
      collapseButton.addEventListener("click", () => {
        if (collapsedDocumentTemplateChapterIds.has(fieldId)) {
          collapsedDocumentTemplateChapterIds.delete(fieldId);
        } else {
          collapsedDocumentTemplateChapterIds.add(fieldId);
        }
        renderDocumentTemplateFieldRows({ renderSupport: false });
      });
      headActions.append(collapseButton);
    }

    headActions.append(removeButton);

    const previewShell = document.createElement("div");
    previewShell.className = "document-template-canvas-preview";
    previewShell.innerHTML = buildDocumentTemplateFieldPreviewMarkup(field, previewContext, draftIndex, {
      placeholderMode: false,
    });
    const previewFieldValue = previewShell.querySelector(".document-template-preview-field-value");
    const applyCanvasPreviewHeight = (resolvedField = field) => {
      const nextHeight = getDocumentTemplateBuilderFieldHeightPx(resolvedField, { preserveAuto: true });
      const nextValueHeight = getDocumentTemplateBuilderPreviewValueHeightPx(resolvedField, { preserveAuto: true });
      if (nextHeight > 0) {
        previewShell.style.setProperty("--document-template-canvas-preview-min-height", `${nextHeight}px`);
        row.dataset.fieldHeight = String(
          getDocumentTemplateBuilderFieldHeightValue(resolvedField, { preserveAuto: true }) || "auto",
        );
      } else {
        previewShell.style.removeProperty("--document-template-canvas-preview-min-height");
        row.dataset.fieldHeight = "auto";
      }
      if (previewFieldValue instanceof HTMLElement) {
        if (nextValueHeight > 0) {
          previewFieldValue.style.minHeight = `${nextValueHeight}px`;
        } else {
          previewFieldValue.style.removeProperty("min-height");
        }
      }
    };

    const canvasMeta = document.createElement("div");
    canvasMeta.className = "document-template-canvas-meta";
    const widthLabel = document.createElement("span");
    widthLabel.className = "document-template-canvas-meta-pill";
    widthLabel.textContent = getDocumentTemplateBuilderWidthMetaLabel(
      getDocumentTemplateRuntimeFieldLayoutWidth(field),
      field.type || "text",
    );
    canvasMeta.append(widthLabel);
    let heightLabel = null;
    if (isDocumentTemplateFieldHeightEditable(field.type)) {
      heightLabel = document.createElement("span");
      heightLabel.className = "document-template-canvas-meta-pill";
      heightLabel.textContent = getDocumentTemplateBuilderHeightMetaLabel(field);
      canvasMeta.append(heightLabel);
    }

    row.append(head, previewShell, canvasMeta);

    let inspectorWidthSelect = null;
    let inspectorHeightSelect = null;
    const syncInspectorWidthSelect = (value) => {
      if (!isInspectorActive) {
        return;
      }
      if (!(inspectorWidthSelect instanceof HTMLSelectElement)) {
        inspectorWidthSelect = documentTemplateFieldInspector?.querySelector("[data-template-field-width-select='true']") || null;
      }
      if (inspectorWidthSelect instanceof HTMLSelectElement && inspectorWidthSelect.value !== value) {
        inspectorWidthSelect.value = value;
      }
    };
    const syncInspectorHeightSelect = (value) => {
      if (!isInspectorActive || field.type !== "longtext") {
        return;
      }
      if (!(inspectorHeightSelect instanceof HTMLSelectElement)) {
        inspectorHeightSelect = documentTemplateFieldInspector?.querySelector("[data-template-field-height-select='true']") || null;
      }
      if (inspectorHeightSelect instanceof HTMLSelectElement) {
        const nextSelectValue = String(normalizeDocumentTemplateFieldHeight(value, field.type || "longtext"));
        if (inspectorHeightSelect.value !== nextSelectValue) {
          inspectorHeightSelect.value = nextSelectValue;
        }
      }
    };
    const createCanvasResizeSession = ({
      startEvent,
      handle,
      activeClass,
      bodyClass,
      onFrame,
      onEnd = null,
    }) => {
      row.classList.add("is-active", activeClass);
      document.body.classList.add(bodyClass);
      handle.setPointerCapture?.(startEvent.pointerId);

      let latestPoint = {
        clientX: startEvent.clientX,
        clientY: startEvent.clientY,
      };
      let frameId = 0;
      let hasPendingPoint = false;

      const flushFrame = () => {
        frameId = 0;
        if (!latestPoint || !hasPendingPoint) {
          return;
        }
        onFrame(latestPoint);
        hasPendingPoint = false;
      };
      const queueFrame = (moveEvent) => {
        latestPoint = {
          clientX: moveEvent.clientX,
          clientY: moveEvent.clientY,
        };
        hasPendingPoint = true;
        if (frameId) {
          return;
        }
        frameId = window.requestAnimationFrame(flushFrame);
      };
      const stopSession = () => {
        if (frameId) {
          window.cancelAnimationFrame(frameId);
          frameId = 0;
        }
        if (latestPoint && hasPendingPoint) {
          onFrame(latestPoint);
          hasPendingPoint = false;
        }
        row.classList.remove(activeClass);
        document.body.classList.remove(bodyClass);
        handle.releasePointerCapture?.(startEvent.pointerId);
        window.removeEventListener("pointermove", queueFrame);
        window.removeEventListener("pointerup", stopSession);
        window.removeEventListener("pointercancel", stopSession);
        if (typeof onEnd === "function") {
          onEnd();
        }
      };

      window.addEventListener("pointermove", queueFrame, { passive: true });
      window.addEventListener("pointerup", stopSession);
      window.addEventListener("pointercancel", stopSession);
      queueFrame(startEvent);
    };

    const applyCanvasWidth = (nextWidth, { syncInspector = true } = {}) => {
      if (!isDocumentTemplateFieldWidthEditable(field.type)) {
        return;
      }
      const normalizedWidth = normalizeDocumentTemplateFieldLayoutWidth(nextWidth, field.type || "text");
      const draft = documentTemplateFieldDrafts[draftIndex];
      if (!draft) {
        return;
      }
      if (String(draft.layoutWidth || "") !== normalizedWidth) {
        draft.layoutWidth = normalizedWidth;
      }
      if (row.dataset.fieldWidth !== normalizedWidth) {
        row.dataset.fieldWidth = normalizedWidth;
        row.style.setProperty("--document-template-builder-width", getDocumentTemplateBuilderWidthPercent({
          ...draft,
          layoutWidth: normalizedWidth,
        }));
      }
      const nextWidthLabel = getDocumentTemplateBuilderWidthMetaLabel(normalizedWidth, field.type || "text");
      if (widthLabel.textContent !== nextWidthLabel) {
        widthLabel.textContent = nextWidthLabel;
      }
      if (syncInspector) {
        syncInspectorWidthSelect(normalizedWidth);
      }
    };

    const applyCanvasHeight = (nextHeight, { syncInspector = true } = {}) => {
      if (!isDocumentTemplateFieldHeightEditable(field.type)) {
        return;
      }
      const normalizedHeight = normalizeDocumentTemplateFieldHeight(nextHeight, field.type || "text");
      const draft = documentTemplateFieldDrafts[draftIndex];
      if (!draft) {
        return;
      }
      if (String(draft.fieldHeight ?? "") !== String(normalizedHeight ?? "")) {
        draft.fieldHeight = normalizedHeight;
      }
      applyCanvasPreviewHeight({
        ...draft,
        fieldHeight: normalizedHeight,
      });
      if (heightLabel) {
        const nextHeightLabel = getDocumentTemplateBuilderHeightMetaLabel({
          ...draft,
          fieldHeight: normalizedHeight,
        });
        if (heightLabel.textContent !== nextHeightLabel) {
          heightLabel.textContent = nextHeightLabel;
        }
      }
      if (syncInspector) {
        syncInspectorHeightSelect(normalizedHeight);
      }
    };

    if (isDocumentTemplateFieldWidthEditable(field.type)) {
      const resizeHandle = document.createElement("button");
      resizeHandle.type = "button";
      resizeHandle.className = "document-template-canvas-resize-handle";
      resizeHandle.setAttribute("aria-label", "Povuci rub za širinu polja");
      resizeHandle.title = "Povuci rub za širinu polja";

      const resizeHandleIcon = document.createElement("span");
      resizeHandleIcon.className = "document-template-canvas-resize-handle-icon";
      resizeHandleIcon.setAttribute("aria-hidden", "true");
      resizeHandleIcon.textContent = "↔";
      resizeHandle.append(resizeHandleIcon);

      resizeHandle.addEventListener("pointerdown", (event) => {
        if (event.button !== 0) {
          return;
        }

        event.preventDefault();
        event.stopPropagation();
        activeDocumentTemplateInspectorFieldId = fieldId;
        const canvasBounds = pageBody.getBoundingClientRect();
        createCanvasResizeSession({
          startEvent: event,
          handle: resizeHandle,
          activeClass: "is-resizing",
          bodyClass: "is-document-template-resizing",
          onFrame: (point) => {
            const ratio = (point.clientX - canvasBounds.left) / Math.max(canvasBounds.width, 1);
            applyCanvasWidth(
              getDocumentTemplateBuilderWidthValueFromRatio(ratio, field.type || "text"),
              { syncInspector: false },
            );
          },
          onEnd: () => {
            applyCanvasWidth(documentTemplateFieldDrafts[draftIndex]?.layoutWidth || field.layoutWidth || "12");
            renderDocumentTemplateFieldRows({ supportImmediate: true });
          },
        });
      });

      row.append(resizeHandle);
      applyCanvasWidth(normalizeDocumentTemplateFieldLayoutWidth(field.layoutWidth, field.type || "text"));
    }

    if (isDocumentTemplateFieldHeightEditable(field.type)) {
      const heightResizeHandle = document.createElement("button");
      heightResizeHandle.type = "button";
      heightResizeHandle.className = "document-template-canvas-height-handle";
      heightResizeHandle.setAttribute("aria-label", "Povuci rub za visinu polja");
      heightResizeHandle.title = "Povuci rub za visinu polja";

      const heightResizeIcon = document.createElement("span");
      heightResizeIcon.className = "document-template-canvas-height-handle-icon";
      heightResizeIcon.setAttribute("aria-hidden", "true");
      heightResizeIcon.textContent = "↕";
      heightResizeHandle.append(heightResizeIcon);

      heightResizeHandle.addEventListener("pointerdown", (event) => {
        if (event.button !== 0) {
          return;
        }

        event.preventDefault();
        event.stopPropagation();
        activeDocumentTemplateInspectorFieldId = fieldId;
        const heightConfig = getDocumentTemplateBuilderHeightConfig(field.type || "text");
        const startY = event.clientY;
        const startHeight = getDocumentTemplateBuilderFieldHeightValue(
          documentTemplateFieldDrafts[draftIndex],
          { preserveAuto: false },
        );
        createCanvasResizeSession({
          startEvent: event,
          handle: heightResizeHandle,
          activeClass: "is-resizing-height",
          bodyClass: "is-document-template-resizing-vertical",
          onFrame: (point) => {
            const delta = Math.round((point.clientY - startY) / Math.max(heightConfig.pixelStep, 1));
            const nextValue = Math.max(
              heightConfig.min,
              Math.min(heightConfig.max, startHeight + delta),
            );
            applyCanvasHeight(String(nextValue), { syncInspector: false });
          },
          onEnd: () => {
            applyCanvasHeight(documentTemplateFieldDrafts[draftIndex]?.fieldHeight ?? field.fieldHeight ?? "");
            renderDocumentTemplateFieldRows({ supportImmediate: true });
          },
        });
      });

      row.append(heightResizeHandle);
      applyCanvasPreviewHeight(field);
    }

    if (
      previewFieldValue instanceof HTMLElement
      && isDocumentTemplatePreviewValueResizeEnabled(field.type)
      && (isDocumentTemplateFieldWidthEditable(field.type) || isDocumentTemplateFieldHeightEditable(field.type))
    ) {
      previewFieldValue.classList.add("is-resizable-input");
      const previewResizeHandle = document.createElement("button");
      previewResizeHandle.type = "button";
      previewResizeHandle.className = "document-template-canvas-input-resize-handle";
      previewResizeHandle.setAttribute("aria-label", "Povuci za veličinu textboxa");
      previewResizeHandle.title = "Povuci za veličinu textboxa";

      const previewResizeIcon = document.createElement("span");
      previewResizeIcon.className = "document-template-canvas-input-resize-handle-icon";
      previewResizeIcon.setAttribute("aria-hidden", "true");
      previewResizeIcon.textContent = "↘";
      previewResizeHandle.append(previewResizeIcon);

      previewResizeHandle.addEventListener("pointerdown", (event) => {
        if (event.button !== 0) {
          return;
        }

        event.preventDefault();
        event.stopPropagation();
        activeDocumentTemplateInspectorFieldId = fieldId;
        const canvasBounds = pageBody.getBoundingClientRect();
        const heightConfig = getDocumentTemplateBuilderHeightConfig(field.type || "text");
        const startY = event.clientY;
        const startHeight = getDocumentTemplateBuilderFieldHeightValue(
          documentTemplateFieldDrafts[draftIndex],
          { preserveAuto: false },
        );
        createCanvasResizeSession({
          startEvent: event,
          handle: previewResizeHandle,
          activeClass: "is-resizing-inner",
          bodyClass: "is-document-template-resizing-diagonal",
          onFrame: (point) => {
            if (isDocumentTemplateFieldWidthEditable(field.type)) {
              const ratio = (point.clientX - canvasBounds.left) / Math.max(canvasBounds.width, 1);
              applyCanvasWidth(
                getDocumentTemplateBuilderWidthValueFromRatio(ratio, field.type || "text"),
                { syncInspector: false },
              );
            }
            if (isDocumentTemplateFieldHeightEditable(field.type)) {
              const delta = Math.round((point.clientY - startY) / Math.max(heightConfig.pixelStep, 1));
              const nextValue = Math.max(
                heightConfig.min,
                Math.min(heightConfig.max, startHeight + delta),
              );
              applyCanvasHeight(String(nextValue), { syncInspector: false });
            }
          },
          onEnd: () => {
            if (isDocumentTemplateFieldWidthEditable(field.type)) {
              applyCanvasWidth(documentTemplateFieldDrafts[draftIndex]?.layoutWidth || field.layoutWidth || "12");
            }
            if (isDocumentTemplateFieldHeightEditable(field.type)) {
              applyCanvasHeight(documentTemplateFieldDrafts[draftIndex]?.fieldHeight ?? field.fieldHeight ?? "");
            }
            renderDocumentTemplateFieldRows({ supportImmediate: true });
          },
        });
      });

      previewFieldValue.append(previewResizeHandle);
    }

    if (isInspectorActive) {
      inspectorShell.replaceChildren();

      const inspectorHeader = document.createElement("div");
      inspectorHeader.className = "document-template-field-inspector-head";

      const inspectorCopy = document.createElement("div");
      inspectorCopy.className = "document-template-field-inspector-copy";
      const inspectorTitle = document.createElement("strong");
      inspectorTitle.textContent = field.label || getDocumentTemplateFieldTypeLabel(field.type) || `Blok ${draftIndex + 1}`;
      const inspectorMeta = document.createElement("span");
      inspectorMeta.textContent = "Mijenjaj placeholdere, izvore podataka i veličinu odabranog polja.";
      inspectorCopy.append(inspectorTitle, inspectorMeta);
      inspectorHeader.append(inspectorCopy);

      inspectorShell.append(inspectorHeader);
      if (tokenRow) {
        inspectorShell.append(tokenRow);
      }
      inspectorShell.append(grid);
    }
    if (field.type === "measurement_table") {
      const inlineExcelHost = document.createElement("div");
      inlineExcelHost.className = "document-template-inline-excel-host";
      inlineExcelHost.dataset.templateFieldId = fieldId;
      inlineExcelHost.hidden = false;
      const openExcelBlock = () => {
        ensureTemplateMeasurementSheetForField(fieldId);
        requestAnimationFrame(() => {
          inlineExcelHost.scrollIntoView({
            behavior: "smooth",
            block: "nearest",
          });
        });
      };
      const handleOpenExcelActivatorKey = (event) => {
        if (event.key !== "Enter" && event.key !== " ") {
          return;
        }

        event.preventDefault();
        openExcelBlock();
      };
      columnsSpan.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        openExcelBlock();
      });
      columnsSpan.addEventListener("keydown", handleOpenExcelActivatorKey);
      columnsField.addEventListener("click", (event) => {
        if (event.target instanceof HTMLElement && event.target.closest("input, select, textarea, button")) {
          return;
        }

        event.preventDefault();
        event.stopPropagation();
        openExcelBlock();
      });
      excelMeta.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        openExcelBlock();
      });
      excelMeta.addEventListener("keydown", handleOpenExcelActivatorKey);
      documentTemplateMeasurementInlineHosts.set(fieldId, inlineExcelHost);
      columnsField.append(inlineExcelHost);
    }
    if (field.type === "chapter") {
      const chapterShell = document.createElement("section");
      chapterShell.className = "document-template-chapter-group";
      chapterShell.dataset.chapterId = fieldId;
      if (collapsedDocumentTemplateChapterIds.has(fieldId)) {
        chapterShell.classList.add("is-collapsed");
      }
      const chapterBody = document.createElement("div");
      chapterBody.className = "document-template-chapter-group-body";
      chapterBody.hidden = collapsedDocumentTemplateChapterIds.has(fieldId);
      chapterShell.append(row, chapterBody);
      chapterShells.set(fieldId, chapterBody);
      pageBody.append(chapterShell);
    } else if (chapterOwnerId && chapterShells.has(chapterOwnerId)) {
      chapterShells.get(chapterOwnerId)?.append(row);
    } else {
      pageBody.append(row);
    }
  });

  if (visibleFields.length > 0) {
    const tailDropZone = document.createElement("div");
    tailDropZone.className = "document-template-drop-tail";
    tailDropZone.textContent = "Povuci blok ovdje za kraj templatea";
    tailDropZone.addEventListener("dragover", (event) => {
      if (!draggedDocumentTemplateFieldId) {
        return;
      }

      event.preventDefault();
      tailDropZone.classList.add("is-active");
    });
    tailDropZone.addEventListener("dragleave", () => {
      tailDropZone.classList.remove("is-active");
    });
    tailDropZone.addEventListener("drop", (event) => {
      event.preventDefault();
      const lastField = visibleFields[visibleFields.length - 1];
      const moved = lastField
        ? moveDocumentTemplateFieldDraft(
          draggedDocumentTemplateFieldId,
          lastField.id,
          {
            pageIndex: 0,
            placement: "after",
          },
        )
        : false;
      tailDropZone.classList.remove("is-active");
      clearDocumentTemplateFieldDragState();
      if (moved) {
        renderDocumentTemplateFieldRows({ supportImmediate: true });
      }
    });
    pageBody.append(tailDropZone);
  }

  shell.append(pageBody);
  documentTemplateCustomFields.replaceChildren(shell);
  if (documentTemplateFieldInspector) {
    documentTemplateFieldInspector.replaceChildren(inspectorShell);
  }

  const activeTemplateSheetFieldId = String(state.measurementSheet.ownerFieldId || "").trim();
  const hasActiveTemplateSheetField = activeTemplateSheetFieldId
    ? documentTemplateFieldDrafts.some((field) => String(field?.id || "") === activeTemplateSheetFieldId)
    : false;
  const activeTemplateSheetHost = state.measurementSheet.ownerKind === "template_field"
    && state.measurementSheet.isOpen
    ? getTemplateMeasurementSheetInlineHost(activeTemplateSheetFieldId)
    : null;
  const shouldCloseTemplateSheet = state.measurementSheet.ownerKind === "template_field"
    && (
      !hasActiveTemplateSheetField
      || (state.measurementSheet.isOpen && !(activeTemplateSheetHost instanceof HTMLElement))
    );
  if (shouldCloseTemplateSheet) {
    state.measurementSheet.selectionDrag = null;
    state.measurementSheet.fillMenu = null;
    state.measurementSheet.fillDrag = null;
    state.measurementSheet.contextMenu = null;
    state.measurementSheet.editingCell = null;
    state.measurementSheet.editorSource = null;
    state.measurementSheet.formulaReferences = [];
    document.body.classList.remove("is-selecting-measurement-cells");
    document.body.classList.remove("is-filling-measurement-cells");
    setMeasurementSheetOpen(false);
    state.measurementSheet.ownerKind = "work_order";
    state.measurementSheet.ownerFieldId = "";
    syncMeasurementToolbar();
  }

  syncMeasurementSheetPanelMount();
  syncDocumentTemplateInlineExcelPreviewVisibility();
  if (renderSupport) {
    scheduleDocumentTemplateEditorSupportRefresh({ immediate: supportImmediate });
  }
}

function renderDocumentTemplateEquipmentRows({ renderSupport = true, supportImmediate = false } = {}) {
  if (!documentTemplateEquipmentItems) {
    return;
  }

  if (documentTemplateEquipmentDrafts.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy";
    empty.textContent = "Dodaj opremu koja ulazi u zapisnik ili ostavi prazno pa ces to unijeti kasnije po dokumentu.";
    documentTemplateEquipmentItems.replaceChildren(empty);
    if (renderSupport) {
      scheduleDocumentTemplateEditorSupportRefresh({ immediate: supportImmediate });
    }
    return;
  }

  documentTemplateEquipmentItems.replaceChildren(...documentTemplateEquipmentDrafts.map((item, index) => {
    const row = document.createElement("div");
    row.className = "document-template-item-card";

    const head = document.createElement("div");
    head.className = "document-template-item-head";
    const title = document.createElement("strong");
    title.textContent = item.name || `Oprema ${index + 1}`;
    const meta = document.createElement("span");
    meta.className = "document-template-inline-token";
    meta.textContent = `${parseTemplateLooseNumber(item.quantity, 1)} kom`;
    head.append(title, meta);

    const grid = document.createElement("div");
    grid.className = "form-grid document-template-inline-grid";

    [
      { label: "Naziv opreme", key: "name", spanFull: false },
      { label: "Oznaka", key: "code", spanFull: false },
      { label: "Količina", key: "quantity", spanFull: false },
      { label: "Napomena", key: "note", spanFull: true },
    ].forEach((definition) => {
      const label = document.createElement("label");
      label.className = definition.spanFull ? "field field-span-full" : "field";
      const span = document.createElement("span");
      span.textContent = definition.label;
      const input = document.createElement("input");
      input.type = "text";
      input.value = item[definition.key] ?? "";
      input.addEventListener("input", (event) => {
        documentTemplateEquipmentDrafts[index][definition.key] = event.currentTarget.value;
        meta.textContent = `${parseTemplateLooseNumber(documentTemplateEquipmentDrafts[index].quantity, 1)} kom`;
        title.textContent = documentTemplateEquipmentDrafts[index].name || `Oprema ${index + 1}`;
        scheduleDocumentTemplateEditorSupportRefresh();
      });
      input.addEventListener("focus", () => rememberDocumentTemplateTextTarget(input, `equipment:${item.id}:${definition.key}`));
      label.append(span, input);
      grid.append(label);
    });

    const actions = document.createElement("div");
    actions.className = "document-template-item-actions";
    const removeButton = createActionButton("Ukloni", "card-button card-danger", () => {
      documentTemplateEquipmentDrafts = documentTemplateEquipmentDrafts.filter((entry) => entry.id !== item.id);
      renderDocumentTemplateEquipmentRows();
    });
    actions.append(removeButton);

    row.append(head, grid, actions);
    return row;
  }));

  if (renderSupport) {
    scheduleDocumentTemplateEditorSupportRefresh({ immediate: supportImmediate });
  }
}

function renderDocumentTemplateSectionRows({ renderSupport = true, supportImmediate = false } = {}) {
  if (!documentTemplateSections) {
    return;
  }

  documentTemplateSections.replaceChildren(...documentTemplateSectionDrafts.map((section, index) => {
    const row = document.createElement("div");
    row.className = "document-template-item-card";

    const head = document.createElement("div");
    head.className = "document-template-item-head";
    const title = document.createElement("strong");
    title.textContent = section.title || `Sekcija ${index + 1}`;
    const typeBadge = document.createElement("span");
    typeBadge.className = "document-template-inline-token";
    typeBadge.textContent = getDocumentTemplateSectionTypeLabel(section.type);
    head.append(title, typeBadge);

    const grid = document.createElement("div");
    grid.className = "form-grid document-template-inline-grid";

    const typeField = document.createElement("label");
    typeField.className = "field";
    const typeSpan = document.createElement("span");
    typeSpan.textContent = "Tip sekcije";
    const typeSelect = document.createElement("select");
    replaceSelectOptions(typeSelect, DOCUMENT_TEMPLATE_SECTION_TYPE_OPTIONS, section.type || "rich_text");
    typeSelect.addEventListener("change", () => {
      documentTemplateSectionDrafts[index].type = typeSelect.value;
      if (!String(documentTemplateSectionDrafts[index].title || "").trim()) {
        documentTemplateSectionDrafts[index].title = getDocumentTemplateSectionTypeLabel(typeSelect.value);
      }
      if (typeSelect.value === "measurement_table" && !String(documentTemplateSectionDrafts[index].columns || "").trim()) {
        documentTemplateSectionDrafts[index].columns = "Pozicija, Opis, Vrijednost, Granica, Napomena";
        documentTemplateSectionDrafts[index].rowCount = "12";
      }
      renderDocumentTemplateSectionRows({ supportImmediate: true });
    });
    typeField.append(typeSpan, typeSelect);

    const titleField = document.createElement("label");
    titleField.className = "field";
    const titleSpan = document.createElement("span");
    titleSpan.textContent = "Naslov";
    const titleInput = document.createElement("input");
    titleInput.type = "text";
    titleInput.value = section.title || "";
    titleInput.addEventListener("input", (event) => {
      documentTemplateSectionDrafts[index].title = event.currentTarget.value;
      title.textContent = event.currentTarget.value || `Sekcija ${index + 1}`;
      scheduleDocumentTemplateEditorSupportRefresh();
    });
    titleInput.addEventListener("focus", () => rememberDocumentTemplateTextTarget(titleInput, `section-title:${section.id}`));
    titleField.append(titleSpan, titleInput);

    const bodyField = document.createElement("label");
    bodyField.className = "field field-span-full";
    const bodySpan = document.createElement("span");
    bodySpan.textContent = "Sadrzaj";
    const bodyInput = document.createElement("textarea");
    bodyInput.rows = 4;
    bodyInput.value = section.body || "";
    bodyInput.addEventListener("input", (event) => {
      documentTemplateSectionDrafts[index].body = event.currentTarget.value;
      scheduleDocumentTemplateEditorSupportRefresh();
    });
    bodyInput.addEventListener("focus", () => rememberDocumentTemplateTextTarget(bodyInput, `section-body:${section.id}`));
    bodyField.append(bodySpan, bodyInput);

    const columnsField = document.createElement("label");
    columnsField.className = "field field-span-full";
    columnsField.hidden = section.type !== "measurement_table";
    const columnsSpan = document.createElement("span");
    columnsSpan.textContent = "Stupci tablice";
    const columnsInput = document.createElement("input");
    columnsInput.type = "text";
    columnsInput.placeholder = "Pozicija, Opis, Vrijednost, Granica, Napomena";
    columnsInput.value = section.columns || "";
    columnsInput.addEventListener("input", (event) => {
      documentTemplateSectionDrafts[index].columns = event.currentTarget.value;
      scheduleDocumentTemplateEditorSupportRefresh();
    });
    columnsInput.addEventListener("focus", () => rememberDocumentTemplateTextTarget(columnsInput, `section-columns:${section.id}`));
    columnsField.append(columnsSpan, columnsInput);

    const rowCountField = document.createElement("label");
    rowCountField.className = "field";
    rowCountField.hidden = section.type !== "measurement_table";
    const rowCountSpan = document.createElement("span");
    rowCountSpan.textContent = "Broj redaka";
    const rowCountInput = document.createElement("input");
    rowCountInput.type = "number";
    rowCountInput.min = "4";
    rowCountInput.max = "40";
    rowCountInput.value = section.rowCount || "12";
    rowCountInput.addEventListener("input", (event) => {
      documentTemplateSectionDrafts[index].rowCount = event.currentTarget.value;
      scheduleDocumentTemplateEditorSupportRefresh();
    });
    rowCountField.append(rowCountSpan, rowCountInput);

    grid.append(typeField, titleField, bodyField, columnsField, rowCountField);

    const actions = document.createElement("div");
    actions.className = "document-template-item-actions";
    const removeButton = createActionButton("Ukloni", "card-button card-danger", () => {
      documentTemplateSectionDrafts = documentTemplateSectionDrafts.filter((entry) => entry.id !== section.id);
      if (documentTemplateSectionDrafts.length === 0) {
        documentTemplateSectionDrafts = createDefaultDocumentTemplateSectionDrafts();
      }
      renderDocumentTemplateSectionRows({ supportImmediate: true });
    });
    actions.append(removeButton);

    row.append(head, grid, actions);
    return row;
  }));

  if (renderSupport) {
    scheduleDocumentTemplateEditorSupportRefresh({ immediate: supportImmediate });
  }
}

function renderDocumentTemplateLegalFrameworkChecklist() {
  if (!documentTemplateLegalFrameworkList) {
    return;
  }

  const selectedIds = new Set(getSelectedDocumentTemplateLegalFrameworkIds());
  const items = sortLegalFrameworks(state.legalFrameworks ?? []);

  if (items.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy";
    empty.textContent = "Prvo dodaj propise u Legal Framework pa ih ovdje povezi s templateom.";
    documentTemplateLegalFrameworkList.replaceChildren(empty);
    return;
  }

  documentTemplateLegalFrameworkList.replaceChildren(...items.map((item) => {
    const label = document.createElement("label");
    label.className = "document-template-legal-option";

    const checkbox = document.createElement("input");
    checkbox.type = "checkbox";
    checkbox.name = "document-template-legal-framework-id";
    checkbox.value = String(item.id);
    checkbox.checked = selectedIds.has(String(item.id));
    checkbox.addEventListener("change", () => {
      renderDocumentTemplatePreviewContent();
      renderDocumentTemplateModule();
    });

    const copy = document.createElement("span");
    copy.className = "document-template-legal-option-copy";
    const title = document.createElement("strong");
    title.textContent = item.title || "Propis";
    const meta = document.createElement("span");
    meta.textContent = [
      item.referenceCode || "",
      item.authority || "",
      getLegalFrameworkStatusLabel(item.status),
    ].filter(Boolean).join(" | ");

    copy.append(title, meta);
    label.append(checkbox, copy);
    return label;
  }));
}

function resetDocumentTemplateForm() {
  if (!documentTemplateForm) {
    return;
  }

  cancelDocumentTemplateEditorSupportRefresh();

  documentTemplateForm.reset();
  state.activeDocumentTemplateId = "";
  activeDocumentTemplateSheetIndex = 0;
  activeDocumentTemplateTextTarget = null;
  activeDocumentTemplateSectionTarget = "";
  activeDocumentTemplateInspectorFieldId = "";
  documentTemplateReferenceDraft = null;
  state.documentTemplateSidebarPanels = {
    referenceCollapsed: false,
    placeholdersCollapsed: false,
  };
  clearDocumentTemplateFieldDragState();
  collapsedDocumentTemplateChapterIds = new Set();
  clearDocumentTemplateRuntimeContext({ render: false });

  if (documentTemplateIdInput) {
    documentTemplateIdInput.value = "";
  }
  if (documentTemplateTypeInput) {
    documentTemplateTypeInput.value = "Zapisnik";
  }
  if (documentTemplateStatusInput) {
    documentTemplateStatusInput.value = "draft";
  }
  if (documentTemplateOutputFileNameInput) {
    documentTemplateOutputFileNameInput.value = "";
  }
  if (documentTemplateCompanyIdInput) {
    documentTemplateCompanyIdInput.value = "";
  }
  rebuildDocumentTemplateCompanyOptions("");
  rebuildDocumentTemplateLocationOptions("");
  setDocumentTemplateFieldDrafts([], { ensureOne: true });
  setDocumentTemplateEquipmentDrafts([], { ensureOne: false });
  setDocumentTemplateSectionDrafts([], { ensureDefault: false });
  renderDocumentTemplateFieldRows();
  renderDocumentTemplateEquipmentRows();
  renderDocumentTemplateSectionRows();
  renderDocumentTemplateLegalFrameworkChecklist();
  renderDocumentTemplateReferenceMeta();
  setDocumentTemplateMessage("");
  syncDocumentTemplateEditorChrome();
}

function hydrateDocumentTemplateForm(
  template,
  {
    preserveRuntimeContext = false,
    runtimeMode = "builder",
    skipModuleNavigation = false,
  } = {},
) {
  cancelDocumentTemplateEditorSupportRefresh();

  if (!skipModuleNavigation) {
    state.activeView = "module";
    state.activeModuleItem = "template-development";
    renderActiveView();
    renderModuleView();
  }
  state.activeDocumentTemplateId = template.id;
  activeDocumentTemplateSheetIndex = 0;
  activeDocumentTemplateInspectorFieldId = "";
  collapsedDocumentTemplateChapterIds = new Set();
  state.documentTemplateSidebarPanels = {
    referenceCollapsed: false,
    placeholdersCollapsed: false,
  };
  if (!preserveRuntimeContext) {
    clearDocumentTemplateRuntimeContext({ render: false });
  } else {
    state.documentTemplateRuntime.mode = runtimeMode === "fill" ? "fill" : "builder";
  }
  if (documentTemplateIdInput) {
    documentTemplateIdInput.value = template.id || "";
  }
  if (documentTemplateTitleInput) {
    documentTemplateTitleInput.value = template.title || "";
  }
  if (documentTemplateTypeInput) {
    documentTemplateTypeInput.value = template.documentType || "Zapisnik";
  }
  if (documentTemplateStatusInput) {
    documentTemplateStatusInput.value = template.status || "draft";
  }
  if (documentTemplateOutputFileNameInput) {
    documentTemplateOutputFileNameInput.value = template.outputFileName || "";
  }
  rebuildDocumentTemplateCompanyOptions(template.sampleCompanyId || "");
  if (documentTemplateCompanyIdInput) {
    documentTemplateCompanyIdInput.value = template.sampleCompanyId || "";
  }
  rebuildDocumentTemplateLocationOptions(template.sampleLocationId || "");
  if (documentTemplateLocationIdInput) {
    documentTemplateLocationIdInput.value = template.sampleLocationId || "";
  }
  if (documentTemplateDescriptionInput) {
    documentTemplateDescriptionInput.value = template.description || "";
  }
  setDocumentTemplateFieldDrafts(template.customFields ?? [], { ensureOne: true });
  setDocumentTemplateEquipmentDrafts(template.equipmentItems ?? [], { ensureOne: false });
  setDocumentTemplateSectionDrafts(template.sections ?? [], { ensureDefault: false });
  setDocumentTemplateReferenceDocument(template.referenceDocument ?? null);
  renderDocumentTemplateFieldRows();
  renderDocumentTemplateEquipmentRows();
  renderDocumentTemplateSectionRows();
  renderDocumentTemplateLegalFrameworkChecklist();
  Array.from(documentTemplateLegalFrameworkList?.querySelectorAll('input[name="document-template-legal-framework-id"]') ?? []).forEach((input) => {
    input.checked = (template.selectedLegalFrameworkIds ?? []).map(String).includes(String(input.value));
  });
  setDocumentTemplateMessage("");
  syncDocumentTemplateEditorChrome();
  openDocumentTemplateEditor();
  requestAnimationFrame(() => {
    if (isDocumentTemplateRuntimeFillMode()) {
      const firstRuntimeInput = documentTemplateCustomFields?.querySelector("input, textarea, select, button");
      if (firstRuntimeInput instanceof HTMLElement) {
        firstRuntimeInput.focus({ preventScroll: true });
        return;
      }
    }
    documentTemplateTitleInput?.focus({ preventScroll: true });
  });
}

function createDocumentTemplateStatusBadge(status) {
  return createBadge(
    getDocumentTemplateStatusLabel(status),
    `document-template-status-badge is-${slugifyValue(status || "draft")}`,
  );
}

function renderDocumentTemplateModule() {
  if (!templateDevelopmentModule || !documentTemplateList || !documentTemplateEmpty) {
    return;
  }

  syncDocumentTemplateEditorModal();

  const filters = {
    query: documentTemplateSearchInput?.value?.trim() || state.documentTemplateFilters.query || "",
    status: documentTemplateFilterStatusInput?.value || state.documentTemplateFilters.status || "all",
  };
  state.documentTemplateFilters = filters;

  const allItems = sortDocumentTemplates(state.documentTemplates ?? []);
  const visibleItems = sortDocumentTemplates(filterDocumentTemplates(state.documentTemplates ?? [], filters));

  if (documentTemplateTotalCount) {
    documentTemplateTotalCount.textContent = String(allItems.length);
  }
  if (documentTemplateActiveCount) {
    documentTemplateActiveCount.textContent = String(allItems.filter((item) => item.status === "active").length);
  }
  if (documentTemplateDraftCount) {
    documentTemplateDraftCount.textContent = String(allItems.filter((item) => item.status === "draft").length);
  }
  if (documentTemplateReferenceCount) {
    documentTemplateReferenceCount.textContent = String(allItems.filter((item) => item.referenceDocument?.fileName).length);
  }
  documentTemplateList.replaceChildren(...visibleItems.map((template) => {
    const card = document.createElement("article");
    card.className = `document-template-card is-${slugifyValue(template.status || "draft")}`;
    card.tabIndex = 0;
    card.setAttribute("role", "button");
    if (String(template.id) === String(documentTemplateIdInput?.value || "")) {
      card.classList.add("is-active");
    }

    const head = document.createElement("div");
    head.className = "document-template-card-head";

    const badges = document.createElement("div");
    badges.className = "document-template-card-badges";
    badges.append(
      createDocumentTemplateStatusBadge(template.status),
      createBadge(getDocumentTemplateTypeLabel(template.documentType), "document-template-meta-badge"),
    );

    const copy = document.createElement("div");
    copy.className = "document-template-card-copy";
    const title = document.createElement("h4");
    title.textContent = template.title || "Bez naziva";
    const linkedLegalCount = getDocumentTemplateSelectedLegalFrameworks(template).length;
    const linkedEquipmentCount = getDocumentTemplateLinkedEquipmentItems(template).length;
    const meta = document.createElement("p");
    meta.className = "document-template-card-meta";
    meta.textContent = [
      `${template.customFields?.length || 0} blokova`,
      linkedLegalCount > 0 ? `${linkedLegalCount} propisa` : "",
      linkedEquipmentCount > 0 ? `${linkedEquipmentCount} opreme` : "",
      template.referenceDocument?.fileName ? "Word ref" : "",
    ].filter(Boolean).join(" · ") || "Bez dodatnih veza";
    copy.append(title, meta);
    head.append(copy, badges);

    const descriptionText = String(template.description || "").trim();
    const description = descriptionText
      ? document.createElement("p")
      : null;
    if (description) {
      description.className = "document-template-card-description";
      description.textContent = descriptionText;
    }

    const footer = document.createElement("div");
    footer.className = "document-template-card-footer";
    const updated = document.createElement("span");
    updated.textContent = template.updatedAt ? `Ažurirano ${formatDateTime(template.updatedAt)}` : "Nova skica";
    footer.append(updated);

    const openCard = () => {
      hydrateDocumentTemplateForm(template);
    };

    card.append(head);
    if (description) {
      card.append(description);
    }
    card.append(footer);
    card.addEventListener("click", openCard);
    card.addEventListener("keydown", (event) => {
      if (event.key !== "Enter" && event.key !== " ") {
        return;
      }
      event.preventDefault();
      openCard();
    });
    return card;
  }));

  documentTemplateEmpty.hidden = visibleItems.length !== 0;
}

function scrollVehicleEditorToTop() {
  vehicleEditorBody?.scrollTo({ top: 0, left: 0, behavior: "auto" });
}

function scrollVehicleReservationToTop() {
  vehicleReservationBody?.scrollTo({ top: 0, left: 0, behavior: "auto" });
}

function syncVehicleReservationAssigneePicker() {
  if (state.vehicleReservationAssigneePickerOpen && (!state.vehicleReservationEditorOpen || !vehicleReservationAssigneesDropdown)) {
    state.vehicleReservationAssigneePickerOpen = false;
  }

  const isOpen = Boolean(state.vehicleReservationAssigneePickerOpen && vehicleReservationAssigneesDropdown);

  vehicleReservationAssigneesDropdown?.classList.toggle("is-open", isOpen);
  if (vehicleReservationAssigneesTrigger) {
    vehicleReservationAssigneesTrigger.setAttribute("aria-expanded", isOpen ? "true" : "false");
  }
  if (vehicleReservationAssigneesInput) {
    vehicleReservationAssigneesInput.hidden = !isOpen;
  }
}

function setVehicleReservationAssigneePickerOpen(isOpen) {
  state.vehicleReservationAssigneePickerOpen = Boolean(isOpen);
  syncVehicleReservationAssigneePicker();
}

function syncVehicleEditorModal() {
  if (state.vehicleEditorOpen && (
    state.activeView !== "module"
    || state.activeModuleItem !== "vehicles"
    || !state.user
  )) {
    state.vehicleEditorOpen = false;
  }

  const isOpen = state.vehicleEditorOpen;

  vehicleEditorPanel?.classList.toggle("is-modal-open", isOpen);
  document.body.classList.toggle("is-vehicle-editor-open", isOpen);

  if (vehicleEditorPanel) {
    vehicleEditorPanel.hidden = !isOpen;
    vehicleEditorPanel.setAttribute("aria-hidden", String(!isOpen));
  }

  if (vehicleEditorBackdrop) {
    vehicleEditorBackdrop.hidden = !isOpen;
  }

  if (vehicleEditorCloseButton) {
    vehicleEditorCloseButton.hidden = !isOpen;
  }

  if (isOpen) {
    requestAnimationFrame(() => {
      scrollVehicleEditorToTop();
      vehicleEditorBody?.focus({ preventScroll: true });
      window.setTimeout(() => {
        scrollVehicleEditorToTop();
      }, 0);
    });
  }
}

function syncVehicleReservationModal() {
  if (state.vehicleReservationEditorOpen && (
    state.activeView !== "module"
    || state.activeModuleItem !== "vehicles"
    || !state.user
  )) {
    state.vehicleReservationEditorOpen = false;
  }

  const isOpen = state.vehicleReservationEditorOpen;

  if (!isOpen) {
    state.vehicleReservationAssigneePickerOpen = false;
  }

  vehicleReservationPanel?.classList.toggle("is-modal-open", isOpen);
  document.body.classList.toggle("is-vehicle-reservation-open", isOpen);

  if (vehicleReservationPanel) {
    vehicleReservationPanel.hidden = !isOpen;
    vehicleReservationPanel.setAttribute("aria-hidden", String(!isOpen));
  }

  if (vehicleReservationBackdrop) {
    vehicleReservationBackdrop.hidden = !isOpen;
  }

  if (vehicleReservationCloseButton) {
    vehicleReservationCloseButton.hidden = !isOpen;
  }

  syncVehicleReservationAssigneePicker();

  if (isOpen) {
    requestAnimationFrame(() => {
      scrollVehicleReservationToTop();
      vehicleReservationBody?.focus({ preventScroll: true });
      window.setTimeout(() => {
        scrollVehicleReservationToTop();
      }, 0);
    });
  }
}

