function clearDocumentTemplateRuntimeContext({ render = true } = {}) {
  state.documentTemplateRuntime = {
    mode: "builder",
    source: "",
    workOrderIds: [],
    activeWorkOrderId: "",
    returnState: null,
    sequenceEntries: [],
    sequenceIndex: -1,
    previousRecordOptions: {},
    savedRecordFingerprints: {},
    collapsedBlocks: {},
    common: {
      inspectionDate: "",
      issuedDate: "",
      issuedPlace: "",
      note: "",
      outsideTemperature: "",
      relativeHumidity: "",
      airflowSpeed: "",
      weather: "",
      groundCondition: "",
      groundResistance: "",
      randomizeEnvironment: false,
      signatureMode: "scan",
      electricalValidityMonths: "12",
      tipkaloValidityMonths: "12",
      inspectorUserIds: [],
      inspectorUserId: "",
      authorizationHolderUserId: "",
      electricalInspectorUserIds: [],
      electricalInspectorUserId: "",
      electricalAuthorizationHolderUserId: "",
      tipkaloInspectorUserIds: [],
      tipkaloInspectorUserId: "",
      tipkaloAuthorizationHolderUserId: "",
    },
    overrides: {},
  };

  if (render) {
    if (state.measurementSheet.ownerKind === "document_template_runtime_field") {
      setMeasurementSheetOpen(false);
      state.measurementSheet.ownerKind = "work_order";
      state.measurementSheet.ownerFieldId = "";
      state.measurementSheet.ownerRuntimeWorkOrderId = "";
    }
    renderDocumentTemplateRuntimeContext();
    renderDocumentTemplateFieldRows();
    renderDocumentTemplatePlaceholderPalette();
    renderDocumentTemplatePreviewContent();
  }
}

function pruneDocumentTemplateRuntimeContext() {
  if (!hasDocumentTemplateRuntimeContext()) {
    return;
  }

  const validIds = (state.documentTemplateRuntime.workOrderIds ?? [])
    .map((value) => String(value ?? "").trim())
    .filter((value) => state.workOrders.some((item) => String(item.id) === value));

  if (validIds.length === 0) {
    clearDocumentTemplateRuntimeContext({ render: false });
    return;
  }

  state.documentTemplateRuntime.workOrderIds = validIds;
  if (!validIds.includes(String(state.documentTemplateRuntime.activeWorkOrderId || "").trim())) {
    state.documentTemplateRuntime.activeWorkOrderId = validIds[0];
  }

  const nextOverrides = {};
  validIds.forEach((id) => {
    if (state.documentTemplateRuntime.overrides?.[id]) {
      nextOverrides[id] = normalizeDocumentTemplateRuntimeOverrideRecord(state.documentTemplateRuntime.overrides[id]);
    }
  });
  state.documentTemplateRuntime.overrides = nextOverrides;
  state.documentTemplateRuntime.sequenceEntries = normalizeDocumentTemplateRuntimeSequenceEntries(
    state.documentTemplateRuntime.sequenceEntries ?? [],
  );
  if (state.documentTemplateRuntime.sequenceEntries.length === 0) {
    state.documentTemplateRuntime.sequenceIndex = -1;
  } else {
    state.documentTemplateRuntime.sequenceIndex = clampDocumentTemplateRuntimeSequenceIndex(
      state.documentTemplateRuntime.sequenceIndex,
      state.documentTemplateRuntime.sequenceEntries,
    );
  }
}

function getDocumentTemplateRuntimeWorkOrders() {
  if (!hasDocumentTemplateRuntimeContext()) {
    return [];
  }

  const selectedIds = new Set(
    (state.documentTemplateRuntime.workOrderIds ?? [])
      .map((value) => String(value ?? "").trim())
      .filter(Boolean),
  );

  return sortWorkOrders((state.workOrders ?? []).filter((item) => selectedIds.has(String(item.id))));
}

function getDocumentTemplateRuntimeActiveWorkOrder() {
  const workOrders = getDocumentTemplateRuntimeWorkOrders();

  if (workOrders.length === 0) {
    return null;
  }

  const activeId = String(state.documentTemplateRuntime.activeWorkOrderId || "").trim();
  return workOrders.find((item) => String(item.id) === activeId) ?? workOrders[0] ?? null;
}

function getDocumentTemplateRuntimeValue(workOrderId, fieldName) {
  const normalizedId = String(workOrderId || "").trim();
  const current = normalizedId ? getDocumentTemplateRuntimeOverrideRecord(normalizedId) ?? {} : {};
  if (current && Object.prototype.hasOwnProperty.call(current, fieldName)) {
    return String(current?.[fieldName] ?? "").trim();
  }

  const commonValue = String(state.documentTemplateRuntime.common?.[fieldName] ?? "").trim();
  if (
    normalizedId
    && state.documentTemplateRuntime.common?.randomizeEnvironment
    && WORK_ORDER_DOCUMENT_RANDOMIZED_ENVIRONMENT_FIELDS.has(String(fieldName || ""))
  ) {
    return applyDeterministicEnvironmentVariance(commonValue, `runtime:${normalizedId}:${fieldName}`, fieldName);
  }
  return commonValue;
}

function getDocumentTemplateRuntimeArrayValue(workOrderId, fieldName) {
  const normalizedId = String(workOrderId || "").trim();
  const current = normalizedId ? getDocumentTemplateRuntimeOverrideRecord(normalizedId) ?? {} : {};
  if (current && Object.prototype.hasOwnProperty.call(current, fieldName)) {
    return normalizeQualifiedUserIdList(current?.[fieldName] ?? []);
  }

  return normalizeQualifiedUserIdList(state.documentTemplateRuntime.common?.[fieldName] ?? []);
}

