workOrderDocumentWizardNextButton?.addEventListener("click", (event) => {
  event.preventDefault();
  event.stopPropagation();
  if (workOrderDocumentWizardError) {
    workOrderDocumentWizardError.textContent = "";
  }
  if (state.workOrderDocumentWizard.step !== "details") {
    return;
  }
  const mode = state.workOrderDocumentWizard.mode || getSelectedWorkOrderDocumentMode() || "inspection";
  if (mode === "znr") {
    setWorkOrderDocumentWizardStep("templates");
    return;
  }
  if (mode !== "inspection") {
    return;
  }
  const selectedWorkOrders = getAllSelectedWorkOrdersForDocumentWizard();
  const sequence = buildWorkOrderDocumentWizardSequence(selectedWorkOrders);
  if (sequence.length === 0) {
    setWorkOrderDocumentWizardStep("templates");
    if (workOrderDocumentWizardError) {
      workOrderDocumentWizardError.textContent = "Za odabrane RN-ove nema povezanog zapisnika. Poveži template na usluzi pa pokušaj ponovno.";
    }
    return;
  }
  const firstEntry = sequence[0];
  const previousWizardState = {
    open: state.workOrderDocumentWizard.open,
    step: state.workOrderDocumentWizard.step,
  };
  state.workOrderDocumentWizard.open = false;
  syncWorkOrderDocumentWizardModal();
  requestAnimationFrame(() => {
    let opened = false;
    try {
      opened = openDocumentTemplateFromWizard(firstEntry.templateId, selectedWorkOrders, {
        sequenceEntries: sequence,
        sequenceIndex: 0,
        activeWorkOrderId: firstEntry.workOrderId,
        closeWizard: false,
        preserveRuntimeContext: false,
        keepCurrentRuntimeView: false,
      });
    } catch (error) {
      console.error("Otvaranje zapisnika iz wizarda nije uspjelo.", error);
      opened = false;
      if (workOrderDocumentWizardError) {
        workOrderDocumentWizardError.textContent = error?.message
          || "Zapisnik se nije uspio otvoriti. Provjeri povezani template i pokušaj ponovno.";
      }
    }
    if (!opened) {
      state.workOrderDocumentWizard.open = previousWizardState.open;
      state.workOrderDocumentWizard.step = previousWizardState.step;
      renderWorkOrderDocumentWizard();
      syncWorkOrderDocumentWizardModal();
      if (workOrderDocumentWizardError) {
        workOrderDocumentWizardError.textContent = workOrderDocumentWizardError.textContent
          || "Zapisnik se nije uspio otvoriti. Provjeri povezani template i pokušaj ponovno.";
      }
      return;
    }
  });
});
